-- Poems batch 40
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7c5f16e6-5ea1-4164-9d4b-be4db54852dc','秋日北固晚望二首 二','高蟾','唐','唐诗','tang','','[]','澤國路岐當面苦，江城砧杵入心寒。',32,'全唐诗/poet.tang.37000.json','["澤國路岐當面苦，江城砧杵入心寒。", "不知白髮誰醫得，爲問無情歲月看。"]'),
('3a3ef417-d4a1-4e4b-bfb9-d30f22e6ba18','送張道士','高蟾','唐','唐诗','tang','','[]','因將歲月離三島，閑貯風煙在一壺。',32,'全唐诗/poet.tang.37000.json','["因將歲月離三島，閑貯風煙在一壺。", "爲問金烏頭白後，人間流水却回無。"]'),
('697b0901-9b9c-4606-8f26-37f55fa4e4c7','吳門春雨','高蟾','唐','唐诗','tang','','[]','吳甸落花春漫漫，吳宮芳樹晚沈沈。',32,'全唐诗/poet.tang.37000.json','["吳甸落花春漫漫，吳宮芳樹晚沈沈。", "王孫不耐如絲雨，罥斷春風一寸心。"]'),
('67493499-0c20-4c09-becd-a0f193ff0955','旅夕','高蟾','唐','唐诗','tang','','[]','風散古陂驚宿鴈，月臨荒戍起啼鴉。',32,'全唐诗/poet.tang.37000.json','["風散古陂驚宿鴈，月臨荒戍起啼鴉。", "不堪吟斷無人見，時復寒燈落一花。"]'),
('1a8e0c02-9b0d-40c8-86ff-5e0c2b71e631','瓜洲夜泊','高蟾','唐','唐诗','tang','','[]','偶爲芳草無情客，況是青山有事身。',32,'全唐诗/poet.tang.37000.json','["偶爲芳草無情客，況是青山有事身。", "一夕瓜洲渡頭宿，天風吹盡廣陵塵。"]'),
('93e0a959-e0f9-4874-9f24-a9c46f03f772','金陵晚望','高蟾','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u7231\u56fd", "\u79cb\u5929", "\u611f\u4f24"]','曾伴浮雲歸晚翠，猶陪落日汎秋聲。',32,'全唐诗/poet.tang.37000.json','["曾伴浮雲歸晚翠，猶陪落日汎秋聲。", "世間無限丹青手，一片傷心畫不成。"]'),
('2f0d97a2-4c4a-42f4-b408-730d2712dceb','晚思','高蟾','唐','唐诗','tang','','[]','虞泉冬恨由來短，楊葉春期分外長。',32,'全唐诗/poet.tang.37000.json','["虞泉冬恨由來短，楊葉春期分外長。", "惆悵浮生不知處，明朝依舊出滄浪。"]'),
('ba9a8eff-23ed-4efe-9d76-ba036eae056e','長信宮二首 一','高蟾','唐','唐诗','tang','','[]','天上夢魂何杳杳，日宮消息太沈沈。',32,'全唐诗/poet.tang.37000.json','["天上夢魂何杳杳，日宮消息太沈沈。", "君恩不似黃金井，一處團圓萬丈深。"]'),
('d19a705e-a164-4299-bbda-3a14be0d0a87','長信宮二首 二','高蟾','唐','唐诗','tang','','[]','天上鳳皇休寄夢，人間鸚鵡舊堪悲。',32,'全唐诗/poet.tang.37000.json','["天上鳳皇休寄夢，人間鸚鵡舊堪悲。", "平生心緒無人識，一隻金梭萬丈絲。"]'),
('4769ee06-0656-41e3-a88b-96706762678c','長安旅懷','高蟾','唐','唐诗','tang','','[]','馬嘶九陌年年苦，人語千門日日新。',32,'全唐诗/poet.tang.37000.json','["馬嘶九陌年年苦，人語千門日日新。", "唯有終南寂無事，寒光不入帝鄉塵。"]'),
('d3e41f72-a6b4-43d7-aa75-cc911f6e8469','春 一','高蟾','唐','唐诗','tang','','[]','天柱幾條搘白日，天門幾扇鎖明時。',32,'全唐诗/poet.tang.37000.json','["天柱幾條搘白日，天門幾扇鎖明時。", "陽春發處無根蔕，憑仗東風分外吹。"]'),
('bb5967b0-b011-4581-86dc-d026c6816d69','春 二','高蟾','唐','唐诗','tang','','[]','明月斷魂清靄靄，平蕪歸思綠迢迢。',32,'全唐诗/poet.tang.37000.json','["明月斷魂清靄靄，平蕪歸思綠迢迢。", "人生莫遣頭如雪，縱得春風亦不消。"]'),
('d97e166e-8466-4858-9338-26368b63bbe4','秋','高蟾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','陽羨溪聲冷駭人，洞庭山翠晚凝神。',32,'全唐诗/poet.tang.37000.json','["陽羨溪聲冷駭人，洞庭山翠晚凝神。", "天將金玉爲風露，曾爲高秋幾度貧。"]'),
('c8b51f54-f8b4-4e39-9a2b-18f04ea8f3a8','灞陵亭','高蟾','唐','唐诗','tang','','[]','一條歸夢朱弦直，一片離心白羽輕。',32,'全唐诗/poet.tang.37000.json','["一條歸夢朱弦直，一片離心白羽輕。", "明日灞陵新霽後，馬頭煙樹綠相迎。"]'),
('a047fbbc-1826-4d75-96fa-fa428a7c4c18','偶作二首 一','高蟾','唐','唐诗','tang','','[]','丁當玉佩三更雨，平帖金閨一覺雲。',32,'全唐诗/poet.tang.37000.json','["丁當玉佩三更雨，平帖金閨一覺雲。", "明日薄情何處去，風流春水不知君。"]'),
('f8138abe-d50a-4864-ab27-3f12c79f9233','偶作二首 二','高蟾','唐','唐诗','tang','','[]','霞衣重疊紅蟬暖，雲髻葱籠紫鳳寒。',32,'全唐诗/poet.tang.37000.json','["霞衣重疊紅蟬暖，雲髻葱籠紫鳳寒。", "天上少年分散後，一條煙水若爲看。"]'),
('3bc457ab-c395-419e-9534-e022a1e5d11d','永夕','高蟾','唐','唐诗','tang','','[]','雲鴻宿處江村冷，獨狖啼時海國陰。',32,'全唐诗/poet.tang.37000.json','["雲鴻宿處江村冷，獨狖啼時海國陰。", "不會殘燈無一事，覺來猶有向隅心。"]'),
('2f72c929-cccc-4271-b8a7-6ed1cb6d5885','落花','高蟾','唐','唐诗','tang','','[]','一葉落時空下淚，三春歸盡復何情。',32,'全唐诗/poet.tang.37000.json','["一葉落時空下淚，三春歸盡復何情。", "無人共得東風語，半日尊前計不成。"]'),
('833b593c-1915-4bd9-b42b-d08a75fcbcce','下第後上永崇高侍郎','高蟾','唐','唐诗','tang','','[]','天上碧桃和露種，日邊紅杏倚雲栽。',32,'全唐诗/poet.tang.37000.json','["天上碧桃和露種，日邊紅杏倚雲栽。", "芙蓉生在秋江上，不向東風怨未開。"]'),
('9ce1d0ff-7973-4912-99bd-ccdfa23c3c42','句','高蟾','唐','唐诗','tang','','[]','君恩秋後葉，日日向人疎。',12,'全唐诗/poet.tang.37000.json','["君恩秋後葉，日日向人疎。"]'),
('fca65d81-55d7-417a-832c-0a023d3319fa','城南偶題','章謁','唐','唐诗','tang','','[]','誰家朱閣道邊開，竹拂欄干滿壁苔。',64,'全唐诗/poet.tang.37000.json','["誰家朱閣道邊開，竹拂欄干滿壁苔。", "野水不知何處去，遊人却是等閑來。", "南山氣聳分紅樹，北闕風高隔紫苔。", "可惜登臨好光景，五門須聽鼓聲迴。"]'),
('86442d00-c11b-49c0-bb2d-d944c3b06598','贈邊將','章謁','唐','唐诗','tang','','[]','千千鐵騎擁塵紅，去去平吞萬里空。',64,'全唐诗/poet.tang.37000.json','["千千鐵騎擁塵紅，去去平吞萬里空。", "宛轉龍蟠金劍雪，連錢豹躩繡旗風。", "行收部落歸天闕，旋進封疆入帝聰。", "只有河源與遼海，如今全屬指麾中。"]'),
('8322f9e9-2b20-46e9-b197-f7abc6b5b2fa','桃源','章謁','唐','唐诗','tang','','[]','絕壁相欹是洞門，昔人從此入仙源。',64,'全唐诗/poet.tang.37000.json','["絕壁相欹是洞門，昔人從此入仙源。", "數株花下逢珠翠，半曲歌中老子孫。", "別後自疑園吏夢，歸來誰信釣翁言。", "山前空有無情水，猶遶當時碧樹村。"]'),
('f6ca028f-bedd-4e92-97a2-70dda5d54eb0','曲江','章謁','唐','唐诗','tang','','[]','日照香塵逐馬蹄，風吹浪濺幾回隄。',64,'全唐诗/poet.tang.37000.json','["日照香塵逐馬蹄，風吹浪濺幾回隄。", "無窮羅綺填花徑，大半笙歌占麥畦。", "落絮却籠他樹白，嬌鶯更學別禽啼。", "秪緣頻燕蓬洲客，引得遊人去似迷。"]'),
('5e611b2b-07c7-44b4-b332-f22b3d289f7b','送韋岫郎中典泗州','章謁','唐','唐诗','tang','','[]','玉皇恩詔別星班，去壓徐方分野間。',64,'全唐诗/poet.tang.37000.json','["玉皇恩詔別星班，去壓徐方分野間。", "有鳥盡巢垂汴柳，無樓不到隔淮山。", "旌旗漸向行時擁，案牘應從到日閑。", "想憶朝天獨吟坐，旋飛新作過秦關。"]'),
('099eee4c-c77d-434a-a97a-99bb57d036c0','贈婺州蘇員外','章謁','唐','唐诗','tang','','[]','帝念瓊枝欲並芳，星分婺女寄仙郎。',64,'全唐诗/poet.tang.37000.json','["帝念瓊枝欲並芳，星分婺女寄仙郎。", "鸞從闕下雖辭侶，鴈到江都却續行。", "煙月一時搜古句，山川兩地植甘棠。", "即看龍虎西歸去，便佐羲軒活萬方。"]'),
('6592c58a-f40b-4728-8f71-fe4e5d6785e5','寄友人','章謁','唐','唐诗','tang','','[]','謝家山水屬君家，曾共持鉤擲歲華。',64,'全唐诗/poet.tang.37000.json','["謝家山水屬君家，曾共持鉤擲歲華。", "竹裏竹雞眠蘚石，溪頭鸂鶒踏金沙。", "登樓夜坐三層月，接果春看五色花。", "昨日西風動歸思，滿船涼葉在天涯。"]'),
('a9810cfa-5187-4892-95c5-58a456f21267','雨','章謁','唐','唐诗','tang','','[]','低着煙花漠漠輕，正堪吟坐掩柴扃。',64,'全唐诗/poet.tang.37000.json','["低着煙花漠漠輕，正堪吟坐掩柴扃。", "亂沾細網垂窮巷，斜送陰雲入古廳。", "鎖却暮愁終不散，添成春醉轉難醒。", "霽來還有風流事，重染南山一遍青。"]'),
('424f3ad5-df99-4932-b024-ad7fee5d1523','觀錫宴','章謁','唐','唐诗','tang','','[]','傾朝朱紫正駢闐，紅杏青莎映廣筵。',64,'全唐诗/poet.tang.37000.json','["傾朝朱紫正駢闐，紅杏青莎映廣筵。", "不道樓臺無錦繡，只愁塵土撲神仙。", "魚銜嫩草浮池面，蝶趂飛花到酒邊。", "日暮驊騮相擁去，幾人沉醉失金鞭。"]'),
('fc5aaf0c-06cf-4ac2-aeea-717698457384','城東即事','章謁','唐','唐诗','tang','','[]','閑尋香陌鳳城東，時暫開襟向遠風。',64,'全唐诗/poet.tang.37000.json','["閑尋香陌鳳城東，時暫開襟向遠風。", "玉笛一聲芳草外，錦鴛雙起碧流中。", "苑邊花竹濃如繡，渭北山川澹似空。", "回首漢宮煙靄裏，天河金閣未央宮。"]'),
('a823aa8e-b302-4d26-b4e3-b104c8c28bf3','夏日湖上即事寄晉陵蕭明府','章謁','唐','唐诗','tang','','[]','亭午羲和駐火輪，開門嘉樹庇湖濆。',64,'全唐诗/poet.tang.37000.json','["亭午羲和駐火輪，開門嘉樹庇湖濆。", "行來賓客奇茶味，睡起兒童帶簟紋。", "屋小有時投樹影，舟輕不覺入鷗羣。", "陶家豈是無詩酒，公退堪驚日已曛。"]'),
('a3ea6907-29ea-4932-a1d4-1c75089bf317','對月','章謁','唐','唐诗','tang','','[]','殘霞卷盡出東溟，萬古難消一片冰。',64,'全唐诗/poet.tang.37000.json','["殘霞卷盡出東溟，萬古難消一片冰。", "公子踏開香徑蘚，美人吹滅畫堂燈。", "瓊輪正輾丹霄去，銀箭休催皓露凝。", "別有洞天三十六，水晶臺殿冷層層。"]'),
('44214f22-ead3-4208-8c4d-3d748944ef0d','浙西送杜晦侍御入關','章謁','唐','唐诗','tang','','[]','紫詔徵賢發帝聰，繡衣行處撲香風。',64,'全唐诗/poet.tang.37000.json','["紫詔徵賢發帝聰，繡衣行處撲香風。", "鶚歸秦樹幽禽散，星出吳天列舍空。", "捧日思馳仙掌外，朝宗勢動海門中。", "鞭鞘所拂三千里，多少諸侯合避驄。"]'),
('e7c7741d-8e74-4bd8-a04f-1961b251fa0c','寄江東道友','章謁','唐','唐诗','tang','','[]','野亭歌罷指西秦，避俗爭名興各新。',64,'全唐诗/poet.tang.37000.json','["野亭歌罷指西秦，避俗爭名興各新。", "碧帶黃麻呈縹緲，短竿長線弄因循。", "夜潮分卷三江月，曉騎齊驅九陌塵。", "可惜人間好聲勢，片帆羸馬不相親。"]'),
('bcce9bf6-0f7b-4f3b-b3b0-fcbf3ba0764e','下第有懷','章謁','唐','唐诗','tang','','[]','故鄉朝夕有人還，欲作家書下筆難。',64,'全唐诗/poet.tang.37000.json','["故鄉朝夕有人還，欲作家書下筆難。", "滅燭何曾妨夜坐，傾壺不獨爲春寒。", "遷來鶯語雖堪聽，落了楊花也怕看。", "但使他年遇公道，月輪長在桂珊珊。"]'),
('9544c664-85d7-4080-a2b1-c7d7b23aa41c','春日經湖上友人別業','章謁','唐','唐诗','tang','','[]','何處狂歌破積愁，攜觴共下木蘭舟。',64,'全唐诗/poet.tang.37000.json','["何處狂歌破積愁，攜觴共下木蘭舟。", "綠泉濺石銀屏濕，黃鳥逢人玉笛休。", "天借煙霞裝島嶼，春鋪錦繡作汀洲。", "一年一電逡巡事，不合花前不醉遊。"]'),
('e13a0bb7-36cb-46e0-b319-527eaabfe3ae','長安春日','章謁','唐','唐诗','tang','','[]','春日皇家瑞景遲，東風無力雨微微。',64,'全唐诗/poet.tang.37000.json','["春日皇家瑞景遲，東風無力雨微微。", "六宮羅綺同時泊，九陌煙花一樣飛。", "暖著柳絲金蘂重，冷開山翠雪稜稀。", "輸他得路蓬洲客，紅綠山頭爛醉歸。"]'),
('61602e97-e557-48c1-a0ae-57c441a00f66','陪浙西王侍郎夜宴','章謁','唐','唐诗','tang','','[]','深鎖雷門宴上才，旋看歌舞旋傳杯。',64,'全唐诗/poet.tang.37000.json','["深鎖雷門宴上才，旋看歌舞旋傳杯。", "黃金鸂鶒當筵睡，紅錦薔薇影燭開。", "稽嶺好風吹玉佩，鏡湖殘月照樓臺。", "小儒末座頻傾耳，祗怕城頭畫角催。"]'),
('70e656ff-164d-4453-a10a-17b25418f318','春別','章謁','唐','唐诗','tang','','[]','擲下籬觴指亂山，趨程不待鳳笙殘。',64,'全唐诗/poet.tang.37000.json','["擲下籬觴指亂山，趨程不待鳳笙殘。", "花邊馬嚼金銜去，樓上人垂玉筯看。", "柳陌雖然風裊裊，蔥河猶自雪漫漫。", "殷勤莫厭貂裘重，恐犯三邊五月寒。"]'),
('0b861df3-63b5-413a-a6f8-f1d3219fb1f4','送謝進士還閩','章謁','唐','唐诗','tang','','[]','百越風煙接巨鼇，還鄉心壯不知勞。',64,'全唐诗/poet.tang.37000.json','["百越風煙接巨鼇，還鄉心壯不知勞。", "雷霆入地建溪險，星斗逼人梨嶺高。", "却擁木綿吟麗句，便攀龍眼醉香醪。", "名場聲利喧喧在，莫向林泉改鬢毛。"]'),
('8b2f93c6-c644-46c0-b382-55565f0317c3','焚書坑','章謁','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u53d9\u4e8b", "\u548f\u53f2\u6000\u53e4", "\u8bae\u8bba", "\u8bbd\u523a"]','竹帛煙消帝業虛，關河空鎖祖龍居。',32,'全唐诗/poet.tang.37000.json','["竹帛煙消帝業虛，關河空鎖祖龍居。", "坑灰未冷山東亂，劉項元來不讀書。"]'),
('f033f158-82a2-418c-b925-51ae54958838','東都望幸','章謁','唐','唐诗','tang','','[]','懶脩珠翠上高臺，眉月連娟恨不開。',32,'全唐诗/poet.tang.37000.json','["懶脩珠翠上高臺，眉月連娟恨不開。", "縱使東巡也無益，君王自領美人來。"]'),
('4f684fc9-e128-4e17-afb0-3d2ddafcfda3','旅舍早起','章謁','唐','唐诗','tang','','[]','跡暗心多感，神疲夢不遊。',48,'全唐诗/poet.tang.37000.json','["跡暗心多感，神疲夢不遊。", "驚舟同厭夜，獨樹對悲秋。", "晚角和人戰，殘星入漢流。", "門前早行子，敲鐙唱離憂。"]'),
('e23781b6-f3a5-49cb-a78a-e1f8db50bf5e','癸卯歲毘陵登高會中貽同志','章謁','唐','唐诗','tang','','[]','流落常嗟勝會稀，故人相遇菊花時。',64,'全唐诗/poet.tang.37000.json','["流落常嗟勝會稀，故人相遇菊花時。", "鳳笙龍笛數巡酒，紅樹碧山無限詩。", "塵土十分歸舉子，乾坤大半屬偷兒。", "長楊羽獵須留本，開濟重爲闕下期。"]'),
('d79f8aa0-7d00-41c2-9a0b-237383fda160','上元夜建元寺觀燈呈智通上人','章謁','唐','唐诗','tang','','[]','建元看別上元燈，處處迴廊鬬火層。',64,'全唐诗/poet.tang.37000.json','["建元看別上元燈，處處迴廊鬬火層。", "珠玉亂拋高殿佛，綺羅深拜遠山僧。", "臨風走筆思呈惠，到曉行禪合伴能。", "無限喧闐留不得，月華西下露華凝。"]'),
('e10fe79e-2f8f-457b-801e-8008a6078058','變體詩','章謁','唐','唐诗','tang','','[]','東南路盡吳江畔，正是窮愁暮雨天。',64,'全唐诗/poet.tang.37000.json','["東南路盡吳江畔，正是窮愁暮雨天。", "鷗鷺不嫌斜兩岸，波濤欺得逆風船。", "偶逢島寺停帆看，深羨漁翁下釣眠。", "今古若論英達筭，鴟夷高興固無邊。"]'),
('9a7e551b-84ff-4d6e-ab91-36756da44fb9','長安書懷','秦韜玉','唐','唐诗','tang','','[]','涼風吹雨滴寒更，鄉思欺人撥不平。',64,'全唐诗/poet.tang.37000.json','["涼風吹雨滴寒更，鄉思欺人撥不平。", "長有歸心懸馬首，可堪無寐枕蛩聲。", "嵐收楚岫和空碧，秋染湘江到底清。", "早晚身閑著蓑去，橘香深處釣船橫。"]'),
('ed3b9f46-1571-47f0-b8aa-20a735fe94ba','檜樹','秦韜玉','唐','唐诗','tang','','[]','翠雲交幹瘦輪囷，嘯雨吟風幾百春。',64,'全唐诗/poet.tang.37000.json','["翠雲交幹瘦輪囷，嘯雨吟風幾百春。", "深蓋屈盤青麈尾，老皮張展黑龍鱗。", "唯堆寒色資琴興，不放秋聲染俗塵。", "歲月如波事如夢，竟留蒼翠待何人。"]'),
('f463cf98-abc0-491d-aee3-52e745b3e574','讀五侯傳','秦韜玉','唐','唐诗','tang','','[]','漢亡金鏡道將衰，便有姦臣競佐時。',64,'全唐诗/poet.tang.37000.json','["漢亡金鏡道將衰，便有姦臣競佐時。", "專國祗誇兄弟貴，舉家誰念子孫危。", "後宮得寵人爭附，前殿陳誠帝不疑。", "朱紫盈門自稱貴，可嗟區宇盡瘡痍。"]'),
('24d1c6b5-381e-4397-a05f-74d0b837684d','春雪','秦韜玉','唐','唐诗','tang','','[]','雲重寒空思寂寥，玉塵如糝滿春[朝]。',66,'全唐诗/poet.tang.37000.json','["雲重寒空思寂寥，玉塵如糝滿春[朝]。", "片纔著地輕輕陷，力不禁風旋旋銷。", "惹砌任他香粉妒，縈叢自學小梅嬌。", "誰家醉卷珠簾看，弦管堂深暖易調。"]'),
('16ddf43c-ac3a-47bc-95a5-36a49bceb30b','貧女','秦韜玉','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u54f2\u7406", "\u4e03\u8a00\u5f8b\u8bd7", "\u751f\u6d3b", "\u5973\u5b50", "\u6000\u624d\u4e0d\u9047"]','蓬門未識綺羅香，擬託良媒益自傷。',64,'全唐诗/poet.tang.37000.json','["蓬門未識綺羅香，擬託良媒益自傷。", "誰愛風流高格調，共憐時世儉梳妝。", "敢將十指誇偏巧，不把雙眉鬬畫長。", "苦恨年年壓金線，爲他人作嫁衣裳。"]'),
('33aa941b-d87d-458b-abf4-f4b08dc42353','題竹','秦韜玉','唐','唐诗','tang','','[]','削玉森森幽思清，院家高興尚分明。',64,'全唐诗/poet.tang.37000.json','["削玉森森幽思清，院家高興尚分明。", "捲簾陰薄漏山色，欹枕韻寒宜雨聲。", "斜對酒缸偏覺好，靜籠碁局最多情。", "却驚九陌輪蹄外，獨有溪煙數十莖。"]'),
('d585f174-6f74-4fa9-a47a-57298f8bad32','鸚鵡','秦韜玉','唐','唐诗','tang','','[]','每聞別雁競悲鳴，却歎金籠寄此生。',64,'全唐诗/poet.tang.37000.json','["每聞別雁競悲鳴，却歎金籠寄此生。", "早是翠襟爭愛惜，可堪丹觜彊分明。", "雲漫隴樹魂應斷，歌接秦樓夢不成。", "幸自禰衡人未識，賺他作賦被時輕。"]'),
('829f02b4-f589-478d-afbc-540876fe98af','寄李處士','秦韜玉','唐','唐诗','tang','','[]','呂望甘羅道已彰，只憑時數爲門張。',64,'全唐诗/poet.tang.37000.json','["呂望甘羅道已彰，只憑時數爲門張。", "世塗必竟皆應定，人事都來不在忙。", "要路強干情本薄，舊山歸去意偏長。", "因君指似封侯骨，漸擬回頭別醉鄉。"]'),
('b355f489-5b12-469b-a94a-38f46fa8e776','對花','秦韜玉','唐','唐诗','tang','','[]','長與韶光暗有期，可憐蜂蝶却先知。',64,'全唐诗/poet.tang.37000.json','["長與韶光暗有期，可憐蜂蝶却先知。", "誰家促席臨低樹，何處橫釵戴小枝？", "麗日多情疑曲照，和風得路合偏吹。", "向人雖道渾無語，笑勸王孫到醉時。"]'),
('6e6ce13d-0228-4363-b15f-5c0c5ad46e38','寄懷','秦韜玉','唐','唐诗','tang','','[]','總藏心劒事儒風，大道如今已渾同。',64,'全唐诗/poet.tang.37000.json','["總藏心劒事儒風，大道如今已渾同。", "會致名津搜儁彥，是張愁網絆英雄。", "蘇公有國皆懸印，楚將無官可賞功。", "若使重生太平日，也應回首哭塗窮。"]'),
('deba8a09-39c7-47b3-a718-73007cd0bbe5','題刑部李郎中山亭','秦韜玉','唐','唐诗','tang','','[]','儂家雲水本相知，每到高齋強展眉。',64,'全唐诗/poet.tang.37000.json','["儂家雲水本相知，每到高齋強展眉。", "瘦竹嚲煙遮板閣，卷荷擎雨出盆池。", "笑吟山色同欹枕，閑背庭陰對覆碁。", "不是主人多野興，肯開青眼重漁師。"]'),
('ce3f553c-065f-4e14-bbc8-06cfd789925a','八月十五日夜同衛諫議看月','秦韜玉','唐','唐诗','tang','','[]','常時月好賴新晴，不似年年此夜生。',64,'全唐诗/poet.tang.37000.json','["常時月好賴新晴，不似年年此夜生。", "初出海濤疑尚濕，漸來雲路覺偏清。", "寒光入水蛟龍起，靜色當天鬼魅驚。", "豈獨座中堪仰望，孤高應到鳳凰城。"]'),
('953ed3f1-b18e-40d2-8da6-747622ba8a5a','亭臺','秦韜玉','唐','唐诗','tang','','[]','雕楹累棟架崔嵬，院宇生煙次第開。',64,'全唐诗/poet.tang.37000.json','["雕楹累棟架崔嵬，院宇生煙次第開。", "爲向西窗添月色，豈辭南海取花栽。", "意將畫地成幽沼，勢擬驅山近小臺。", "清境漸深官轉重，春時長是別人來。"]'),
('8839b049-2848-4e7f-aeff-d2fb1ec76e5f','邊將','秦韜玉','唐','唐诗','tang','','[]','劒光如電馬如風，百捷長輕是掌中。',64,'全唐诗/poet.tang.37000.json','["劒光如電馬如風，百捷長輕是掌中。", "無定河邊蕃將死，受降城外虜塵空。", "旗縫雁翅如竿褭，箭撚雕翎逐隼雄。", "自指燕山最高石，不知誰爲勒殊功。"]'),
('3ca26ad0-3d2a-4657-8f0a-9f89a92b5119','塞下','秦韜玉','唐','唐诗','tang','','[]','到處人皆著戰袍，麾旗風緊馬蹄勞。',66,'全唐诗/poet.tang.37000.json','["到處人皆著戰袍，麾旗風緊馬蹄勞。", "黑山霜重弓添硬，青冢沙平月更高。", "大野幾重開雪嶺，長河無限舊雲濤。", "[鳳]林關外皆唐土，何日陳兵戍不毛。"]'),
('1742f423-b288-46e6-a821-4e57c517bb9c','織錦婦','秦韜玉','唐','唐诗','tang','','[]','桃花日日覓新奇，有鏡何曾及畫眉。',64,'全唐诗/poet.tang.37000.json','["桃花日日覓新奇，有鏡何曾及畫眉。", "祗恐輕梭難作匹，豈辭纖手遍生胝。", "合蟬巧間雙盤帶，聯鴈斜銜小折枝。", "豪貴大堆酬曲徹，可憐辛苦一絲絲。"]'),
('c59290f6-1143-411d-8135-c2a514a92abc','釣翁','秦韜玉','唐','唐诗','tang','','[]','一竿青竹老江隈，荷葉衣裳可自裁。',64,'全唐诗/poet.tang.37000.json','["一竿青竹老江隈，荷葉衣裳可自裁。", "潭定靜懸絲影直，風高斜颭浪紋開。", "朝攜輕棹穿雲去，暮背寒塘戴月回。", "世上無窮嶮巇事，算應難入釣船來。"]'),
('8dcfa6d0-8eff-41c1-a67a-798ab32b2673','曲江','秦韜玉','唐','唐诗','tang','','[]','曲沼深塘躍錦鱗，槐煙徑裏碧波新。',64,'全唐诗/poet.tang.37000.json','["曲沼深塘躍錦鱗，槐煙徑裏碧波新。", "此中境既無佳境，他處春應不是春。", "金牓真仙開樂席，銀鞍公子醉花塵。", "明年二月重來看，好共東風作主人。"]'),
('a31064e4-4378-4167-b606-ee0c4f7c39e2','隋隄','秦韜玉','唐','唐诗','tang','','[]','種柳開河爲勝遊，隄前常使路人愁。',66,'全唐诗/poet.tang.37000.json','["種柳開河爲勝遊，隄前常使路人愁。", "陰埋野色萬條思，翠束寒聲千里秋。", "西日至今悲兔苑，東[波]終不反龍舟。", "遠山應見繁華事，不語青青對水流。"]'),
('114652a6-cfc5-4ecc-a5a6-2365d353d064','天街','秦韜玉','唐','唐诗','tang','','[]','九衢風景盡爭新，獨占天門近紫宸。',64,'全唐诗/poet.tang.37000.json','["九衢風景盡爭新，獨占天門近紫宸。", "寶馬競隨朝暮客，香車爭碾古今塵。", "煙光正入南山色，氣勢遙連北闕春。", "莫見繁華祗如此，暗中還換往來人。"]'),
('18ef97af-6315-4aa9-952d-0354dcaa8158','紫騮馬','秦韜玉','唐','唐诗','tang','','[]','渥洼奇骨本難求，況是豪家重紫騮。',64,'全唐诗/poet.tang.37000.json','["渥洼奇骨本難求，況是豪家重紫騮。", "臕大宜懸銀壓胯，力渾欺著玉銜頭。", "生獰弄影風隨步，踥蹀衝塵汗滿溝。", "若遇丈夫能控馭，任從騎取覓封侯。"]'),
('76bad1b1-bd27-4aec-9bbf-c5445d71ec9d','問古','秦韜玉','唐','唐诗','tang','','[]','大底榮枯各自行，兼疑陰隲也難明。',64,'全唐诗/poet.tang.37000.json','["大底榮枯各自行，兼疑陰隲也難明。", "無門雪向頭中出，得路雲從脚下生。", "深作四溟何浩渺，高爲五嶽太崢嶸。", "都來總向人間看，直到皇天可是平。"]'),
('e3bbf32d-d296-48c8-9812-8821423bae3e','豪家','秦韜玉','唐','唐诗','tang','','[]','石甃通渠引御波，綠槐陰裏五侯家。',64,'全唐诗/poet.tang.37000.json','["石甃通渠引御波，綠槐陰裏五侯家。", "地衣鎮角香獅子，簾額侵鉤繡辟邪。", "按徹清歌天未曉，飲回深院漏猶賒。", "四鄰池館吞將盡，尚自堆金爲買花。"]'),
('07e3a998-af60-482d-b36d-d153e06eedfa','陳宮','秦韜玉','唐','唐诗','tang','','[]','臨春高閣擬瀛洲，貪寵張妃作勝遊。',64,'全唐诗/poet.tang.37000.json','["臨春高閣擬瀛洲，貪寵張妃作勝遊。", "便把江山爲己有，豈知臺榭是身讐。", "金城暗逐歌聲碎，鐵甕潛隨舞勢休。", "誰識古宮堪恨處，井桐吟雨不勝秋。"]'),
('0f39da55-a75b-48e5-bd04-47c34075715e','送友人罷舉授南陵令','秦韜玉','唐','唐诗','tang','','[]','共言愁是酌離杯，況值弦歌枉大才。',64,'全唐诗/poet.tang.37000.json','["共言愁是酌離杯，況值弦歌枉大才。", "獻賦未爲龍化去，除書猶喜鳳銜來。", "花明驛路燕脂暖，山入江亭罨畫開。", "莫把新詩題別處，謝家臨水有池臺。"]'),
('54203781-255b-4e71-9ed9-b512cb4cbcfa','投知己','秦韜玉','唐','唐诗','tang','','[]','爐中九轉鍊雖成，教主看時亦自驚。',64,'全唐诗/poet.tang.37000.json','["爐中九轉鍊雖成，教主看時亦自驚。", "羣嶽竝天先減翠，大江臨海恐無聲。", "賦歸已罷吳門釣，身老仍拋楚岸耕。", "唯有太平方寸血，今朝盡向隗臺傾。"]'),
('1614e75f-db2f-4cba-b942-b3b1f560984f','牡丹','秦韜玉','唐','唐诗','tang','','[]','折妖放豔有誰催，疑就仙中旋折來。',64,'全唐诗/poet.tang.37000.json','["折妖放豔有誰催，疑就仙中旋折來。", "圖把一春皆占斷，固留三月始教開。", "壓枝金蘂香如撲，逐朵檀心巧勝裁。", "好是酒闌絲竹罷，倚風含笑向樓臺。"]'),
('7e596bac-0a8e-4a7f-a08b-fce9cf8ed051','春遊','秦韜玉','唐','唐诗','tang','','[]','選勝逢君敘解攜，思和芳草遠煙迷。',64,'全唐诗/poet.tang.37000.json','["選勝逢君敘解攜，思和芳草遠煙迷。", "小梅香裏黃鶯囀，垂柳陰中白馬嘶。", "春引美人歌遍熟，風牽公子酒旗低。", "早知有此關身事，悔不前年住越溪。"]'),
('12a04b9e-2795-4392-89a5-c7289e3981ab','仙掌','秦韜玉','唐','唐诗','tang','','[]','萬仞連峰積翠新，靈蹤依舊印輪巡。',64,'全唐诗/poet.tang.37000.json','["萬仞連峰積翠新，靈蹤依舊印輪巡。", "何如捧日安皇道，莫把回山示世人。", "已擘峻流穿太嶽，長扶王氣擁彊秦。", "爲余勢負天工背，索取風雲際會身。"]'),
('1107ce99-1241-4315-a6cc-715bf2a50163','燕子','秦韜玉','唐','唐诗','tang','','[]','不知大廈許栖無，頻已銜泥到座隅。',32,'全唐诗/poet.tang.37000.json','["不知大廈許栖無，頻已銜泥到座隅。", "曾與佳人竝頭語，幾回拋却繡工夫。"]'),
('d4d7ca82-7973-41d7-9ca9-670f6d012a42','奉和春日玩雪','秦韜玉','唐','唐诗','tang','','[]','北闕同雲掩曉霞，東風春雪滿山家。',32,'全唐诗/poet.tang.37000.json','["北闕同雲掩曉霞，東風春雪滿山家。", "瓊章定少千人和，銀樹先開六出花。"]'),
('7eaf5b15-536b-41f3-9388-a724ebca48a3','獨坐吟','秦韜玉','唐','唐诗','tang','','[]','客愁不盡本如水，草色含情更無已。',32,'全唐诗/poet.tang.37000.json','["客愁不盡本如水，草色含情更無已。", "又覺春愁似草生，何人種在情田裏。"]'),
('bb275c33-9e5a-4a69-a7f4-b3febd48a211','採茶歌','秦韜玉','唐','唐诗','tang','','[]','天柱香芽露香發，爛研瑟瑟穿荻篾。',112,'全唐诗/poet.tang.37000.json','["天柱香芽露香發，爛研瑟瑟穿荻篾。", "太守憐才寄野人，山童碾破團團月。", "倚雲便酌泉聲煮，獸炭潛然蚪珠吐。", "看著晴天早日明，鼎中颯颯篩風雨。", "老翠香塵下纔熟，攪時繞筯天雲綠。", "耽書病酒兩多情，坐對閩甌睡先足。", "洗我胸中幽思清，鬼神應愁歌欲成。"]'),
('9bb9ebc2-8a9b-4b51-8f65-61acadf1a755','貴公子行','秦韜玉','唐','唐诗','tang','','[]','堦前莎毬綠不捲，銀龜噴香挽不斷。',80,'全唐诗/poet.tang.37000.json','["堦前莎毬綠不捲，銀龜噴香挽不斷。", "亂花織錦柳撚線，妝點池臺畫屏展。", "主人公業傳國初，六親聯絡馳朝車。", "鬬雞走狗家世事，抱來皆佩黃金魚。", "却笑儒生把書卷，學得顏回忍飢面。"]'),
('ef387db3-a26a-4cee-ab3d-a0ea909e7ee3','吹笙歌','秦韜玉','唐','唐诗','tang','','[]','信陵名重憐高才，見我長吹青眼開。',144,'全唐诗/poet.tang.37000.json','["信陵名重憐高才，見我長吹青眼開。", "便出燕姬再傾醑，此時花下逢仙侶。", "彎彎狂月壓秋波，兩條黃金𨴋黃霧。", "逸豔初因醉態見，濃春可是韶光與。", "纖纖軟玉捧暖笙，深思香風吹不去。", "檀脣呼吸宮商改，怨情漸逐清新舉。", "岐山取得嬌鳳雛，管中藏著輕輕語。", "好笑襄王大迂闊，曾臥巫雲見神女。", "銀鎖金簧不得聽，空勞翠輦衝泥雨。"]'),
('95378a96-d39f-4f94-bbe4-c4eac45e505f','咏手','秦韜玉','唐','唐诗','tang','','[]','一雙十指玉纖纖，不是風流物不拈。',64,'全唐诗/poet.tang.37000.json','["一雙十指玉纖纖，不是風流物不拈。", "鸞鏡巧梳勻翠黛，畫樓閑望擘珠簾。", "金杯有喜輕輕點，銀鴨無香旋旋添。", "因把翦刀嫌道冷，泥人呵了弄人髯。"]'),
('10596b7b-416e-4bec-8bcf-fc413e424f7e','句','秦韜玉','唐','唐诗','tang','','[]','女媧羅裙長百尺，搭在湘江作山色。',16,'全唐诗/poet.tang.37000.json','["女媧羅裙長百尺，搭在湘江作山色。"]'),
('64989685-e334-4ab5-80d1-c48e0cdb2523','逢韓喜','唐彥謙','唐','唐诗','tang','','[]','相逢渾不覺，祗似茂陵貧。',48,'全唐诗/poet.tang.37000.json','["相逢渾不覺，祗似茂陵貧。", "褭褭花驕客，瀟瀟雨淨春。", "借書消茗困，索句寫梅真。", "此去青雲上，知君有幾人。"]'),
('2cae8789-f6f3-4a4c-a097-ca085f612652','夜坐示友','唐彥謙','唐','唐诗','tang','','[]','夜久燭花落，淒聲生遠林。',48,'全唐诗/poet.tang.37000.json','["夜久燭花落，淒聲生遠林。", "有懷嫌會淺，無事又秋深。", "黃葉歸田夢，白頭行路吟。", "山中亦可樂，不似此同襟。"]'),
('c7105e66-cc76-4aea-9dc5-1ae66d084ae0','梅亭','唐彥謙','唐','唐诗','tang','','[]','東海窮詩客，西風古驛亭。',48,'全唐诗/poet.tang.37000.json','["東海窮詩客，西風古驛亭。", "髮從殘歲白，山入故鄉青。", "世事徒三窟，兒曹且一經。", "丁寧速賒酒，煮栗試砂瓶。"]'),
('39b5fa24-1a62-4561-b55e-f5fb4bd12cf8','歲除','唐彥謙','唐','唐诗','tang','','[]','索索風搜客，沈沈雨洗年。',48,'全唐诗/poet.tang.37000.json','["索索風搜客，沈沈雨洗年。", "殘林生獵跡，歸鳥避窰煙。", "節物杯漿外，溪山鬢影前。", "行藏都未定，筆硯或能捐。"]'),
('ccf966f4-c584-4986-9986-b9a75d4ed807','詠月','唐彥謙','唐','唐诗','tang','','[]','陰盛此宵中，多爲雨與風。',48,'全唐诗/poet.tang.37000.json','["陰盛此宵中，多爲雨與風。", "坐無風雨至，看與雪霜同。", "抱濕離遙海，傾寒向遠空。", "年年不相值，還似道難通。"]'),
('0331b114-aae8-4961-954e-94b82c41c46a','聞應德茂先離棠溪','唐彥謙','唐','唐诗','tang','','[]','落日蘆花雨，行人穀樹村。',48,'全唐诗/poet.tang.37000.json','["落日蘆花雨，行人穀樹村。", "青山時問路，紅葉自知門。", "苜蓿窮詩味，芭蕉醉墨痕。", "端知棄城市，經席許頻溫。"]'),
('e39c50ce-b9cf-4303-9171-e06e9b350187','松','唐彥謙','唐','唐诗','tang','','[]','託根蟠泰華，倚幹蝕莓苔。',24,'全唐诗/poet.tang.37000.json','["託根蟠泰華，倚幹蝕莓苔。", "誰云山澤間，而無梁棟材。"]'),
('7dd04aff-5565-475f-a1db-29542024857c','梅','唐彥謙','唐','唐诗','tang','','[]','玉人下瑤臺，香風動輕素。',24,'全唐诗/poet.tang.37000.json','["玉人下瑤臺，香風動輕素。", "畫角弄江城，鳴璫月中墮。"]'),
('06e27167-42e1-4f14-80c4-39ecd14e5e50','蘭二首 一','唐彥謙','唐','唐诗','tang','','[]','清風搖翠環，涼露滴蒼玉。',24,'全唐诗/poet.tang.37000.json','["清風搖翠環，涼露滴蒼玉。", "美人胡不紉，幽香藹空谷。"]'),
('bc550f77-d512-4704-8f8a-27c63e8fc6e2','蘭二首 二','唐彥謙','唐','唐诗','tang','','[]','謝庭漫芳草，楚畹多綠莎。',24,'全唐诗/poet.tang.37000.json','["謝庭漫芳草，楚畹多綠莎。", "于焉忽相見，歲晏將如何。"]'),
('081f7f9a-8ad8-44c6-8168-99ce1f59429f','葡萄','唐彥謙','唐','唐诗','tang','','[]','金谷風露涼，綠珠醉初醒。',24,'全唐诗/poet.tang.37000.json','["金谷風露涼，綠珠醉初醒。", "珠帳夜不收，月明墮清影。"]'),
('03385f5d-ddf3-4c0b-a458-acac97af8266','春草','唐彥謙','唐','唐诗','tang','','[]','隨夢入池塘，無心在金谷。',24,'全唐诗/poet.tang.37000.json','["隨夢入池塘，無心在金谷。", "春風自年年，吹遍天涯綠。"]'),
('94e6b597-a9a6-44c6-8969-3b312dc5f96a','漁','唐彥謙','唐','唐诗','tang','','[]','相聚即爲鄰，煙火自成簇。',24,'全唐诗/poet.tang.37000.json','["相聚即爲鄰，煙火自成簇。", "約伴過前溪，撐破蘼蕪綠。"]'),
('6d5b4d3e-ba31-4d96-8822-39a7bf42a43d','留別四首 一','唐彥謙','唐','唐诗','tang','','[]','鵬程三萬里，別酒一千鍾。',24,'全唐诗/poet.tang.37000.json','["鵬程三萬里，別酒一千鍾。", "好景當三月，春光上國濃。"]'),
('6082fff3-b346-4008-a300-e8de923ded57','留別四首 二','唐彥謙','唐','唐诗','tang','','[]','野花紅滴滴，江燕語喃喃。',24,'全唐诗/poet.tang.37000.json','["野花紅滴滴，江燕語喃喃。", "鼓吹翻新調，都亭酒正酣。"]'),
('f9cfa0c8-7420-45d9-9e0e-e1eee2f7e59d','留別四首 三','唐彥謙','唐','唐诗','tang','','[]','登庸趨俊乂，廁用野無遺。',24,'全唐诗/poet.tang.37000.json','["登庸趨俊乂，廁用野無遺。", "起喜賡歌日，明良際會時。"]'),
('f2f17f65-ee52-4be0-9ada-98d1202ee9f3','留別四首 四','唐彥謙','唐','唐诗','tang','','[]','鹽車淹素志，長坂入青雲。',24,'全唐诗/poet.tang.37000.json','["鹽車淹素志，長坂入青雲。", "老驥春風裏，奔騰獨異羣。"]'),
('58c8c04c-422c-45c2-beab-04e0822d6087','秋葵','唐彥謙','唐','唐诗','tang','','[]','月瓣團欒翦赭羅，長條排蘂綴鳴珂。',32,'全唐诗/poet.tang.37000.json','["月瓣團欒翦赭羅，長條排蘂綴鳴珂。", "傾陽一點丹心在，承得中天雨露多。"]'),
('fdd71b12-08d6-4008-baee-fe995c85a334','春草','唐彥謙','唐','唐诗','tang','','["\u5199\u8349", "\u6625\u5929", "\u601d\u5f52"]','天北天南遶路邊，托根無處不延綿。',32,'全唐诗/poet.tang.37000.json','["天北天南遶路邊，托根無處不延綿。", "萋萋總是無情物，吹綠東風又一年。"]'),
('2ec6eead-7c35-431b-9a5e-f3a716462403','春日偶成','唐彥謙','唐','唐诗','tang','','[]','𥱧箏簫管和琵琶，興滿金尊酒量賒。',32,'全唐诗/poet.tang.37000.json','["𥱧箏簫管和琵琶，興滿金尊酒量賒。", "歌舞留春春似海，美人顏色正如花。"]'),
('255f05f4-5acf-4e61-af70-70e84435567f','秋日感懷','唐彥謙','唐','唐诗','tang','','[]','溪上芙蓉映醉顏，悲秋宋玉鬢毛斑。',32,'全唐诗/poet.tang.37000.json','["溪上芙蓉映醉顏，悲秋宋玉鬢毛斑。", "無情最恨東流水，暗逐芳年去不還。"]'),
('cb89362f-3e60-4230-a1b9-0a7407359e20','七夕','唐彥謙','唐','唐诗','tang','','[]','會合無由歎久違，一年一度是緣非。',32,'全唐诗/poet.tang.37000.json','["會合無由歎久違，一年一度是緣非。", "而予願乞天孫巧，五色紉針補袞衣。"]'),
('2fa4ecca-3fd6-409d-a15c-25ba0da853a2','懷友','唐彥謙','唐','唐诗','tang','','[]','金井涼生梧葉秋，閑看新月上簾鉤。',32,'全唐诗/poet.tang.37000.json','["金井涼生梧葉秋，閑看新月上簾鉤。", "冰壺總憶人如玉，目斷重雲十二樓。"]'),
('b51c869d-347b-44c0-95d7-32bdf0a9627b','翡翠','唐彥謙','唐','唐诗','tang','','[]','莎草江汀漫晚潮，翠華香撲水光遙。',32,'全唐诗/poet.tang.37000.json','["莎草江汀漫晚潮，翠華香撲水光遙。", "玉樓春暖笙歌夜，妝點花鈿上舞翹。"]'),
('f2d32099-1937-4a49-b38b-4ec046e582c5','詠馬二首 一','唐彥謙','唐','唐诗','tang','','[]','紫雲團影電飛瞳，駿骨龍媒自不同。',32,'全唐诗/poet.tang.37000.json','["紫雲團影電飛瞳，駿骨龍媒自不同。", "騎過玉樓金轡響，一聲嘶斷落花風。"]'),
('0758d6d7-cc68-496e-be72-6cbb9d38e9e1','詠馬二首 二','唐彥謙','唐','唐诗','tang','','[]','崚嶒高聳骨如山，遠放春郊苜蓿間。',32,'全唐诗/poet.tang.37000.json','["崚嶒高聳骨如山，遠放春郊苜蓿間。", "百戰沙場汗流血，夢魂猶在玉門關。"]'),
('af3b2080-4db2-4b03-9751-2f8abdc7cae0','留別','唐彥謙','唐','唐诗','tang','','[]','丹湖湖上送行舟，白鴈啼殘蘆葉秋。',32,'全唐诗/poet.tang.37000.json','["丹湖湖上送行舟，白鴈啼殘蘆葉秋。", "采石江頭舊時路，題詩還憶水邊樓。"]'),
('80c82b2d-c213-458e-af89-6ca8f199edbb','詠竹','唐彥謙','唐','唐诗','tang','','[]','醉臥涼陰沁骨清，石牀冰簟夢難成。',32,'全唐诗/poet.tang.37000.json','["醉臥涼陰沁骨清，石牀冰簟夢難成。", "月明午夜生虛籟，悞聽風聲是雨聲。"]'),
('7f76f186-826c-4835-afc8-cb9577864a99','憶孟浩然','唐彥謙','唐','唐诗','tang','','[]','郊外淩兢西復東，雪晴驢背興無窮。',32,'全唐诗/poet.tang.37000.json','["郊外淩兢西復東，雪晴驢背興無窮。", "句搜明月梨花內，趣入春風柳絮中。"]'),
('e71a16f4-65b3-479d-b5fb-01289680d5a3','寄友三首 一','唐彥謙','唐','唐诗','tang','','[]','新酒秦淮縮項鯿，凌霄花下共流連。',32,'全唐诗/poet.tang.37000.json','["新酒秦淮縮項鯿，凌霄花下共流連。", "別來客邸空翹首，細雨春風憶往年。"]'),
('09ef6214-c590-4634-afee-862ccf68694f','寄友三首 二','唐彥謙','唐','唐诗','tang','','[]','寒燈孤對擁青氈，牢落何如似客邊。',32,'全唐诗/poet.tang.37000.json','["寒燈孤對擁青氈，牢落何如似客邊。", "却憶花前酣後飲，醉呼明月上遙天。"]'),
('3fb87172-2ffd-49e4-bfe8-a15a09d56fd8','寄友三首 三','唐彥謙','唐','唐诗','tang','','[]','客裏逢春一惘然，梅花落盡柳如煙。',32,'全唐诗/poet.tang.37000.json','["客裏逢春一惘然，梅花落盡柳如煙。", "無情最恨東來鴈，底事音書不肯傳。"]'),
('b26f3bf0-fdc9-4fc8-b2ac-554f9488943c','無題十首 一','唐彥謙','唐','唐诗','tang','','[]','細草鋪茵綠滿堤，燕飛晴日正遲遲。',32,'全唐诗/poet.tang.37000.json','["細草鋪茵綠滿堤，燕飛晴日正遲遲。", "尋芳陌上花如錦，折得東風第一枝。"]'),
('7d41ca77-a262-4cbf-bf12-aecb342c4620','無題十首 二','唐彥謙','唐','唐诗','tang','','[]','錦箏銀甲響鵾弦，勾引春聲上綺筵。',32,'全唐诗/poet.tang.37000.json','["錦箏銀甲響鵾弦，勾引春聲上綺筵。", "醉倚闌干花下月，犀梳斜嚲鬢雲邊。"]'),
('9b533958-2123-42f8-9e45-468fd58be793','無題十首 三','唐彥謙','唐','唐诗','tang','','[]','楚雲湘雨會陽臺，錦帳芙蓉向夜開。',32,'全唐诗/poet.tang.37000.json','["楚雲湘雨會陽臺，錦帳芙蓉向夜開。", "吹罷玉簫春似海，一雙綵鳳忽飛來。"]'),
('bbe19bc5-e35a-4153-8b68-662cec25fb52','無題十首 四','唐彥謙','唐','唐诗','tang','','[]','春江新水促歸航，惜別花前酒漫觴。',32,'全唐诗/poet.tang.37000.json','["春江新水促歸航，惜別花前酒漫觴。", "倒盡銀瓶渾不醉，却憐和淚入愁腸。"]'),
('63d12006-4098-4b8c-b4b2-7c2b1e3fa900','無題十首 五','唐彥謙','唐','唐诗','tang','','[]','誰知別易會應難，目斷青鸞信渺漫。',32,'全唐诗/poet.tang.37000.json','["誰知別易會應難，目斷青鸞信渺漫。", "情似藍橋橋下水，年來流恨幾時乾。"]'),
('5b1ae6db-d26b-413c-8c6b-12c90aaf36e1','無題十首 六','唐彥謙','唐','唐诗','tang','','[]','漏滴銅龍夜已深，柳梢斜月弄疎陰。',32,'全唐诗/poet.tang.37000.json','["漏滴銅龍夜已深，柳梢斜月弄疎陰。", "滿園芳草年年恨，剔盡燈花夜夜心。"]'),
('4790f2df-1115-4fd4-ab9a-6c3685c2fd62','無題十首 七','唐彥謙','唐','唐诗','tang','','[]','夜合庭前花正開，輕羅小扇爲誰裁。',32,'全唐诗/poet.tang.37000.json','["夜合庭前花正開，輕羅小扇爲誰裁。", "多情驚起雙蝴蝶，飛入巫山夢裏來。"]'),
('c2a7b41b-5511-42c0-afe5-40e35eee61ef','無題十首 八','唐彥謙','唐','唐诗','tang','','[]','憶別悠悠歲月長，酒兵無計敵愁腸。',32,'全唐诗/poet.tang.37000.json','["憶別悠悠歲月長，酒兵無計敵愁腸。", "柔絲漫折長亭柳，綰得同心欲寄將。"]'),
('8c3589a0-f4e8-4f0d-b317-a3baa9777b1d','無題十首 九','唐彥謙','唐','唐诗','tang','','[]','楊柳青青映畫樓，翠眉終日鎖離愁。',32,'全唐诗/poet.tang.37000.json','["楊柳青青映畫樓，翠眉終日鎖離愁。", "杜鵑啼落枝頭月，多爲傷春恨不休。"]'),
('57a26987-fab4-4906-8cab-a353d6d1d42d','無題十首 十','唐彥謙','唐','唐诗','tang','','[]','雲色鮫[綃]拭淚顏，一簾春雨杏花寒。',34,'全唐诗/poet.tang.37000.json','["雲色鮫[綃]拭淚顏，一簾春雨杏花寒。", "幾時重會鴛鴦侶，月下吹笙和綵鸞。"]'),
('9a6a3775-1061-4ddf-bb4b-32d6c18aa3d7','寄同上人','唐彥謙','唐','唐诗','tang','','[]','高高山頂寺，更有最高人。',48,'全唐诗/poet.tang.37000.json','["高高山頂寺，更有最高人。", "定起松鳴屋，吟圓月上身。", "雲藏三伏熱，水散百溪津。", "曾乞蘭花供，無書又過春。"]'),
('528912ae-4ed4-419b-b55d-17e47a939d79','夜坐','唐彥謙','唐','唐诗','tang','','[]','愁鬢丁年白，寒燈丙夜青。',48,'全唐诗/poet.tang.37000.json','["愁鬢丁年白，寒燈丙夜青。", "不眠驚戍鼓，久客厭郵鈴。", "洶洶城噴海，疎疎屋漏星。", "十年窮父子，相守慰飄零。"]'),
('a03dd94f-28f4-41d4-81da-82b05679a8d1','弔方干處士二首 一','唐彥謙','唐','唐诗','tang','','[]','不謂高名下，終全玉雪身。',48,'全唐诗/poet.tang.37000.json','["不謂高名下，終全玉雪身。", "交猶及前輩，語不似今人。", "別號行鳴鴈，遺編感獲麟。", "歛衣應自定，只著古衣巾。"]'),
('9e50c676-a91f-4b8d-b82f-e279e3281297','弔方干處士二首 二','唐彥謙','唐','唐诗','tang','','[]','不比他人死，何詩可挽君。',48,'全唐诗/poet.tang.37000.json','["不比他人死，何詩可挽君。", "淵明元嬾仕，東野別攻文。", "滄海諸公淚，青山處士墳。", "相看莫浪哭，私諡有前聞。"]'),
('6935344b-2703-4a3b-b0a1-30f417a06777','題證道寺','唐彥謙','唐','唐诗','tang','','[]','彎環青徑斜，自是野僧家。',48,'全唐诗/poet.tang.37000.json','["彎環青徑斜，自是野僧家。", "滿澗洗巖液，插天排石牙。", "爐寒餘栢子，架靜落藤花。", "記得逃兵日，門多貴客車。"]'),
('f6aa7994-73ee-485b-b541-2ac75212380e','宿趙𡸯別業','唐彥謙','唐','唐诗','tang','','[]','溪山兵後縣，風雪旅中人。',48,'全唐诗/poet.tang.37000.json','["溪山兵後縣，風雪旅中人。", "迫夜愁嚴鼓，衝寒託軟巾。", "摧藏名字在，疏率饌殽真。", "今代徐元直，高風自可親。"]'),
('603b4e13-9225-4e08-89f0-9a6a954a578c','原上','唐彥謙','唐','唐诗','tang','','[]','危橋橫古渡，村野帶平林。',48,'全唐诗/poet.tang.37000.json','["危橋橫古渡，村野帶平林。", "野騖寒塘靜，山禽曉樹深。", "雨微風矗□，雲暗雪侵尋。", "安道門前水，清遊豈獨吟。"]'),
('1885721d-a4b7-4483-b02b-64c932d424a2','寄臺省知己','唐彥謙','唐','唐诗','tang','','[]','久懷聲籍甚，千里致雙魚。',36,'全唐诗/poet.tang.37000.json','["久懷聲籍甚，千里致雙魚。", "宦路終推轂，親幃且著書。", "才名賈太傅，文學馬相如。"]'),
('67f2e8f5-4248-4eb0-a296-669d885d11c4','自詠','唐彥謙','唐','唐诗','tang','','[]','白髮三千丈，青春四十年。',48,'全唐诗/poet.tang.37000.json','["白髮三千丈，青春四十年。", "兩牙搖欲落，雙膝痺如攣。", "強仕非時彥，無聞惜昔賢。", "自期終見惡，未忍捨遺編。"]'),
('31fdc747-b9b7-4355-b12c-541439bf6865','遊陽明洞呈王理得諸君','唐彥謙','唐','唐诗','tang','','[]','禹穴蒼茫不可探，人傳靈笈鎖煙嵐。',64,'全唐诗/poet.tang.37000.json','["禹穴蒼茫不可探，人傳靈笈鎖煙嵐。", "初晴鶴點青邊嶂，欲雨龍移黑處潭。", "北斗齋壇天寂寂，東風仙洞草毿毿。", "堪憐尹叟非關吏，猶向江南逐老聃。"]'),
('577c2dbf-e1a8-4490-9705-6710141ed242','新豐','唐彥謙','唐','唐诗','tang','','[]','沛中歌舞百餘人，帝業功成里巷新。',64,'全唐诗/poet.tang.37000.json','["沛中歌舞百餘人，帝業功成里巷新。", "半夜素靈先哭楚，一星遺火下燒秦。", "貔貅掃盡無三戶，雞犬歸來識四鄰。", "惆悵故園前事遠，曉風長路起埃塵。"]'),
('b483d7dd-99c5-4918-8c51-a51e80c2271a','拜越公墓因遊定水寺有懷源老','唐彥謙','唐','唐诗','tang','','[]','越公已作飛仙去，猶得潭潭好墓田。',64,'全唐诗/poet.tang.37000.json','["越公已作飛仙去，猶得潭潭好墓田。", "老樹背風深拓地，野雲依海細分天。", "青峰曉接鳴鐘寺，玉井秋澄試茗泉。", "我與源公舊相識，遺言瀟灑有人傳。"]'),
('34663093-23f6-4458-85f1-db5fbf73a002','任潛謀隱之作','唐彥謙','唐','唐诗','tang','','[]','江邊秋日逢任子，大理索詩吾欲忘。',64,'全唐诗/poet.tang.37000.json','["江邊秋日逢任子，大理索詩吾欲忘。", "爲問山資何次第，祗餘丹訣轉淒涼。", "黃金范蠡曾辭祿，白首虞翻未信方。", "千古浮雲共歸思，曉風城郭水花香。"]'),
('271fcb79-da38-4412-8ea6-f18ef8bd443d','晚秋遊中溪','唐彥謙','唐','唐诗','tang','','[]','淡竹岡前沙鴈飛，小花尖下柘丸肥。',64,'全唐诗/poet.tang.37000.json','["淡竹岡前沙鴈飛，小花尖下柘丸肥。", "山雲不卷雨自薄，天氣欲寒人正歸。", "招伴祗須新稻酒，臨風猶有舊苔磯。", "故人舊業依稀在，怪石老松今是非。"]'),
('338b5d41-fd23-4a41-8fb1-b322407a4085','寄陳少府兼簡叔高','唐彥謙','唐','唐诗','tang','','[]','懷人路絕雲歸海，避俗門深草蔽丘。',64,'全唐诗/poet.tang.37000.json','["懷人路絕雲歸海，避俗門深草蔽丘。", "萬事漸消閑客夢，一年虛白少年頭。", "山螿啼緩從除架，淮鴈來多莫上樓。", "近日鄰家有新釀，每逢詩伴得淹留。"]'),
('fc317457-aed4-4b23-aab3-f2f3e4f68403','過清涼王導墓下','唐彥謙','唐','唐诗','tang','','[]','江左風流廊廟人，荒墳拋與梵宮鄰。',64,'全唐诗/poet.tang.37000.json','["江左風流廊廟人，荒墳拋與梵宮鄰。", "多年羊虎猶眠石，敗壁貂蟬祗貯塵。", "萬古雲山同白骨，一庭花木自青春。", "永思陵下猶淒切，廢屋寒風吹野薪。"]'),
('c0f8681e-77bd-4d66-a365-885d5ecb72b0','第三溪','唐彥謙','唐','唐诗','tang','','[]','日晏霜濃十二月，林疎石瘦第三溪。',64,'全唐诗/poet.tang.37000.json','["日晏霜濃十二月，林疎石瘦第三溪。", "雲沙有徑縈寒燒，松屋無人聞晝雞。", "幾聚衣冠埋作土，當年歌舞醉如泥。", "早知涉世真成夢，不棄山田春雨犁。"]'),
('4a6bbc1a-c70c-4a4e-abac-9cc96c8b50c5','蒲津河亭','唐彥謙','唐','唐诗','tang','','[]','宿雨清秋霽景澂，廣亭高樹向晨興。',64,'全唐诗/poet.tang.37000.json','["宿雨清秋霽景澂，廣亭高樹向晨興。", "煙橫博望乘槎水，日上文王避雨陵。", "孤棹夷猶期獨往，曲闌愁絕每長憑。", "思鄉懷古多傷別，況此哀吟意不勝。"]'),
('b317cc3c-a64f-419d-9f29-e321996c400b','毘陵道中','唐彥謙','唐','唐诗','tang','','[]','百年只有百清明，狼狽今年又避兵。',64,'全唐诗/poet.tang.37000.json','["百年只有百清明，狼狽今年又避兵。", "煙火誰開寒食禁，簪裾那復麗人行。", "禾麻地廢生邊氣，草木春寒起戰聲。", "渺渺飛鴻天斷處，古來還是闔閭城。"]'),
('9e11dca4-f120-4dae-b101-39fb53524e0b','越城待旦','唐彥謙','唐','唐诗','tang','','[]','策策虛樓竹隔明，悲來展轉向誰傾。',66,'全唐诗/poet.tang.37000.json','["策策虛樓竹隔明，悲來展轉向誰傾。", "天寒[胡]鴈出萬里，月落越雞啼四更。", "爲底朱顏成老色，看人青史上新名。", "清溪白石村村有，五尺烏犍託此生。"]'),
('c2c7c0a9-1a38-4066-bec5-63d39e68f59f','過浩然先生墓','唐彥謙','唐','唐诗','tang','','[]','人間萬卷龐眉老，眼見堂堂入草萊。',64,'全唐诗/poet.tang.37000.json','["人間萬卷龐眉老，眼見堂堂入草萊。", "行客須當下馬過，故交誰復裹雞來。", "山花不語如聽講，溪水無情自薦哀。", "猶勝黃金買碑碣，百年名字已煙埃。"]'),
('83f89996-3722-47a9-9612-2a4220e216cf','贈孟德茂','唐彥謙','唐','唐诗','tang','','[]','江海悠悠雪欲飛，抱書空出又空歸。',64,'全唐诗/poet.tang.37000.json','["江海悠悠雪欲飛，抱書空出又空歸。", "沙頭人滿鷗應笑，船上酒香魚正肥。", "塵土竟成誰計是，山林又悔一年非。", "平生萬卷應夫子，兩世功名窮布衣。"]'),
('a662fc8d-7925-4c6c-a452-157b7a6c6817','秋霽豐德寺與玄貞師詠月','唐彥謙','唐','唐诗','tang','','[]','露冷風輕霽魄圓，高樓更在碧山巔。',64,'全唐诗/poet.tang.37000.json','["露冷風輕霽魄圓，高樓更在碧山巔。", "四溟水合疑無地，八月槎通好上天。", "黯黯星辰環紫極，喧喧朝市匝青煙。", "夜深獨與巖僧語，羣動消聲舉世眠。"]'),
('b5495ffe-9dbd-48f1-9ae9-15b1987dd29e','長陵','唐彥謙','唐','唐诗','tang','','[]','長安高闕此安劉，祔葬纍纍盡列侯。',66,'全唐诗/poet.tang.37000.json','["長安高闕此安劉，祔葬纍纍盡列侯。", "豐上舊居無故里，沛中原廟對荒丘。", "耳聞明主提三尺，眼見愚民盜一[坯]。", "千載腐儒騎瘦馬，渭城斜月重回頭。"]'),
('54b97126-de66-4a88-bf04-6947ab1d0273','留別','唐彥謙','唐','唐诗','tang','','[]','西入潼關路，何時更盍簪。',48,'全唐诗/poet.tang.37000.json','["西入潼關路，何時更盍簪。", "年來人事改，老去鬢毛侵。", "花染離筵淚，葵傾報國心。", "龍潭千尺水，不似別情深。"]'),
('881a4c8b-4bb3-4be8-909a-e8760a044840','宿獨留','唐彥謙','唐','唐诗','tang','','[]','日晚宿留城，人家半掩門。',48,'全唐诗/poet.tang.37000.json','["日晚宿留城，人家半掩門。", "羣鴉棲老樹，一犬吠荒村。", "爭買魚添價，新篘酒帶渾。", "船頭對新月，誰與共清論。"]'),
('7101a032-e7cb-4efd-b08e-837c64c31da5','客中感懷','唐彥謙','唐','唐诗','tang','','[]','客路三千里，西風兩鬢塵。',48,'全唐诗/poet.tang.37000.json','["客路三千里，西風兩鬢塵。", "貪名笑吳起，說國歎蘇秦。", "託興非耽酒，思家豈爲蒪。", "可憐今夜月，獨照異鄉人。"]'),
('312e4947-9f21-40c6-b08b-c6019318ab5a','過三山寺','唐彥謙','唐','唐诗','tang','','[]','三山江上寺，宮殿望岧嶤。',48,'全唐诗/poet.tang.37000.json','["三山江上寺，宮殿望岧嶤。", "石徑侵高樹，沙灘半種苗。", "一僧歸晚日，羣鷺宿寒潮。", "遙聽風鈴語，興亡話六朝。"]'),
('c235dea5-874d-49d9-be13-ca805c3faeba','望夫石','唐彥謙','唐','唐诗','tang','','[]','江上見危磯，人形立翠微。',48,'全唐诗/poet.tang.37000.json','["江上見危磯，人形立翠微。", "妾來終日望，夫去幾時歸。", "明月空懸鏡，蒼苔漫補衣。", "可憐雙淚眼，千古斷斜暉。"]'),
('911ab65d-b60a-4282-9a0b-8d1b655ff836','過湖口','唐彥謙','唐','唐诗','tang','','[]','江湖分兩路，此地是通津。',48,'全唐诗/poet.tang.37000.json','["江湖分兩路，此地是通津。", "雲淨山浮翠，風高浪潑銀。", "人行俱是客，舟住即爲鄰。", "俯仰煙波內，蜉蝣寄此身。"]'),
('2ed1b799-3b07-497e-a2cd-532f68a7424f','夜泊東溪有懷','唐彥謙','唐','唐诗','tang','','[]','水昏天色晚，崖下泊行舟。',48,'全唐诗/poet.tang.37000.json','["水昏天色晚，崖下泊行舟。", "獨客傷歸鴈，孤眠歎野鷗。", "溪聲牽別恨，鄉夢惹離愁。", "酒醒推篷坐，淒涼望女牛。"]'),
('c2e1c1b3-a609-4ce6-a4c3-e7c5a76a5c41','登廬山','唐彥謙','唐','唐诗','tang','','["\u5e90\u5c71"]','五老峰巔望，天涯在目前。',48,'全唐诗/poet.tang.37000.json','["五老峰巔望，天涯在目前。", "湘潭浮夜雨，巴蜀暝寒煙。", "泰華根同峙，嵩衡脈共聯。", "憑虛有仙骨，日月看推遷。"]'),
('609e40a8-0cea-4802-aecf-4c938e7f1cf4','金陵九日','唐彥謙','唐','唐诗','tang','','[]','野菊西風滿路香，雨花臺上集壺觴。',64,'全唐诗/poet.tang.37000.json','["野菊西風滿路香，雨花臺上集壺觴。", "九重天近瞻鍾阜，五色雲中望建章。", "綠酒莫辭今日醉，黃金難買少年狂。", "清歌驚起南飛鴈，散作秋聲送夕陽。"]'),
('8f329a3a-7ec3-4cb4-be32-69ad781f1e6f','遊清涼寺','唐彥謙','唐','唐诗','tang','','[]','白雲紅樹路紆縈，古殿長廊次第行。',64,'全唐诗/poet.tang.37000.json','["白雲紅樹路紆縈，古殿長廊次第行。", "南望水連桃葉渡，北來山枕石頭城。", "一塵不到心源淨，萬有俱空眼界清。", "竹院逢僧舊曾識，旋披禪衲爲相迎。"]'),
('5bb43f46-b1c1-4e1b-b3db-ad15aa8d9bab','高平九日','唐彥謙','唐','唐诗','tang','','[]','雲淨南山紫翠浮，憑陵絕頂望悠悠。',64,'全唐诗/poet.tang.37000.json','["雲淨南山紫翠浮，憑陵絕頂望悠悠。", "偶逢佳節牽詩興，漫把芳尊遣客愁。", "霜染鴉楓迎日醉，寒衝涇水帶冰流。", "烏紗頻岸西風裏，笑插黃花滿鬢秋。"]'),
('37cdfb9c-d9b4-4be0-84e5-12dae67601a0','金陵懷古','唐彥謙','唐','唐诗','tang','','[]','碧樹涼生宿雨收，荷花荷葉滿汀洲。',64,'全唐诗/poet.tang.37000.json','["碧樹涼生宿雨收，荷花荷葉滿汀洲。", "登高有酒渾忘醉，慨古無言獨倚樓。", "宮殿六朝遺古跡，衣冠千古漫荒丘。", "太平時節殊風景，山自青青水自流。"]'),
('3453f51a-9369-4ee1-b812-d4d092ec1d47','道中逢故人','唐彥謙','唐','唐诗','tang','','[]','蘭陵市上忽相逢，敘別殷勤興倍濃。',64,'全唐诗/poet.tang.37000.json','["蘭陵市上忽相逢，敘別殷勤興倍濃。", "良會若同雞黍約，暫時不放酒杯空。", "愁牽白髮三千丈，路入青山幾萬重。", "行色一鞭催去馬，畫橋嘶斷落花風。"]'),
('c289db79-6cac-4efb-a20c-40f202ca6fa4','早行遇雪','唐彥謙','唐','唐诗','tang','','[]','下馬天未明，風高雪何急。',60,'全唐诗/poet.tang.37000.json','["下馬天未明，風高雪何急。", "須臾路欲迷，頃刻山盡白。", "雞犬寂無聲，曙光射寒色。", "荒村絕煙火，髯凍布袍濕。", "王事不可緩，行行動悽惻。"]'),
('8e3ac260-574e-4a0e-963e-060ea85b1f93','樊登見寄四首 一','唐彥謙','唐','唐诗','tang','','[]','新辭翦秋水，洗我胸中塵。',36,'全唐诗/poet.tang.37000.json','["新辭翦秋水，洗我胸中塵。", "無由愜良會，極目空懷人。", "醉來拔劍歌，字字皆陽春。"]'),
('9ae15346-d080-411b-ad5a-aea06d3ed27b','樊登見寄四首 二','唐彥謙','唐','唐诗','tang','','[]','輕黃著柳條，新春喜更始。',36,'全唐诗/poet.tang.37000.json','["輕黃著柳條，新春喜更始。", "感時重搔首，悵望不能已。", "無由託深情，傾瀉芳尊裏。"]'),
('b62d7aaa-f661-4f70-b8d3-9040fec21030','樊登見寄四首 三','唐彥謙','唐','唐诗','tang','','[]','明月入我室，天風吹我袍。',36,'全唐诗/poet.tang.37000.json','["明月入我室，天風吹我袍。", "良夜最岑寂，旅況何蕭條。", "馳情望海波，一鶴鳴九臯。"]'),
('fd5fc5b0-1f4a-499b-b917-41ec1ac230f6','樊登見寄四首 四','唐彥謙','唐','唐诗','tang','','[]','悠悠括城北，眄眄巖泉西。',36,'全唐诗/poet.tang.37000.json','["悠悠括城北，眄眄巖泉西。", "宿草暝煙綠，苦竹含雲低。", "幽懷不可託，鷓鴣空自啼。"]'),
('2295674c-2940-4293-80b3-ded15d21e0b4','春風四首 一','唐彥謙','唐','唐诗','tang','','[]','春風吹愁端，散漫不可收。',24,'全唐诗/poet.tang.37000.json','["春風吹愁端，散漫不可收。", "不如古溪水，祗望鄉江流。"]'),
('4e0b2b0f-3655-4942-a07d-9158a9056a48','春風四首 二','唐彥謙','唐','唐诗','tang','','[]','新花紅爍爍，舊花滿山白。',24,'全唐诗/poet.tang.37000.json','["新花紅爍爍，舊花滿山白。", "昔日金張門，狼籍餘廢宅。"]'),
('d0bc16d7-2fa1-4e90-8b9e-cdb7b06ef0a2','春風四首 三','唐彥謙','唐','唐诗','tang','','[]','回頭語春風，莫向新花叢。',24,'全唐诗/poet.tang.37000.json','["回頭語春風，莫向新花叢。", "我見朱顏人，多金亦成翁。"]'),
('ef9f6434-79a8-41e1-b2e7-6a2b2eb62ba9','春風四首 四','唐彥謙','唐','唐诗','tang','','[]','多金不足惜，丹砂亦何益。',24,'全唐诗/poet.tang.37000.json','["多金不足惜，丹砂亦何益。", "更種明年花，春風自相識。"]'),
('dc631957-b3c5-4cca-8497-0173c8d58445','感物二首 一','唐彥謙','唐','唐诗','tang','','[]','騄驥初失羣，亦自矜趫騰。',72,'全唐诗/poet.tang.37000.json','["騄驥初失羣，亦自矜趫騰。", "俛仰歲時久，帖然困蚊蠅。", "豪鯨逸其穴，尺水成滄溟。", "豈無魚鼈交，望望爲所憎。", "物理有翕張，達人同廢興。", "幸無怵迫憂，聊復曲吾肱。"]'),
('890225bb-b8ae-412d-af82-34a5c4e3dad2','感物二首 二','唐彥謙','唐','唐诗','tang','','[]','魚目出泥沙，空村百金珍。',72,'全唐诗/poet.tang.37000.json','["魚目出泥沙，空村百金珍。", "豫章值擁輳，細細供蒸薪。", "論材何必多，適用即能神。", "託交何必深，寡求永相親。", "鮑叔拙羇魯，張生窮厄陳。", "茫然扳援際，豈意出風塵。"]'),
('df00165c-5791-49fc-8460-bb85bcdcf2d3','和陶淵明貧士詩七首 一','唐彥謙','唐','唐诗','tang','','[]','貧賤如故舊，少壯即相依。',72,'全唐诗/poet.tang.37000.json','["貧賤如故舊，少壯即相依。", "中心不敢厭，但覺少光輝。", "向來乘時士，亦有能奮飛。", "一朝權勢歇，欲退無所歸。", "不如行其素，辛苦奈寒飢。", "人生繫天運，何用發深悲。"]'),
('d0d2914b-1f0b-4c3f-9d2a-6b5e0eff49cb','和陶淵明貧士詩七首 二','唐彥謙','唐','唐诗','tang','','[]','我居在窮巷，來往無華軒。',72,'全唐诗/poet.tang.37000.json','["我居在窮巷，來往無華軒。", "辛勤衣食物，出此二畝園。", "薤菘鬱朝露，桑柘浮春煙。", "以茲亂心曲，智計無他奸。", "擇勝不在奢，興至發清言。", "相逢樵牧徒，混混誰愚賢。"]'),
('59bc723c-5435-452c-b26a-ddac39c11033','和陶淵明貧士詩七首 三','唐彥謙','唐','唐诗','tang','','[]','松風四山來，清宵響瑤琴。',72,'全唐诗/poet.tang.37000.json','["松風四山來，清宵響瑤琴。", "聽之不能寐，中有怨歎音。", "旦起繞其樹，磈砢不計尋。", "清陰可敷席，有酒誰與斟。", "由來大度士，不受流俗侵。", "浩歌相倡答，慰此霜雪心。"]'),
('d4a9d808-4aaf-4273-9e81-645b3c8dfbc6','和陶淵明貧士詩七首 四','唐彥謙','唐','唐诗','tang','','[]','中年涉事熟，欲學唾面婁。',72,'全唐诗/poet.tang.37000.json','["中年涉事熟，欲學唾面婁。", "逡巡避少年，赴穢不敢詶。", "旁人吁已甚，自喜計慮周。", "微勞消厚疚，殘辱勝深憂。", "從知爲下安，處上反無儔。", "人生各有志，勇懦從所求。"]'),
('3e07ebdc-44cc-49e0-94be-c05ffb83976e','和陶淵明貧士詩七首 五','唐彥謙','唐','唐诗','tang','','[]','古人重畎畝，有祿不待干。',72,'全唐诗/poet.tang.37000.json','["古人重畎畝，有祿不待干。", "德成祿自至，釋耒列王官。", "不仕亦不貧，本自足饔飱。", "後世恥躬耕，號呼脫飢寒。", "我生千𥜥後，念此愧在顏。", "爲農倘可飽，何用出柴關。"]'),
('dbdc0235-e690-4e41-aff7-b5e96488d6e9','和陶淵明貧士詩七首 六','唐彥謙','唐','唐诗','tang','','[]','村郊多父老，面垢頭如蓬。',72,'全唐诗/poet.tang.37000.json','["村郊多父老，面垢頭如蓬。", "我嘗使之年，言語不待工。", "古來名節士，敢望彭城龔。", "有叟誚其後，更恨道不通。", "鄙哉譊譊者，爲隘不爲通。", "低頭拜野老，負米吾願從。"]'),
('2c2f5d7d-fcff-47a1-aefd-dbaa120f050a','和陶淵明貧士詩七首 七','唐彥謙','唐','唐诗','tang','','[]','去年秋事荒，販糴仰鄰州。',72,'全唐诗/poet.tang.37000.json','["去年秋事荒，販糴仰鄰州。", "健者道路間，什百成朋儔。", "今年漸向熟，庶幾民不流。", "書生自無田，與衆同喜憂。", "作詩勞鄰曲，有倡誰與詶。", "亦無采詩者，此修何可修。"]'),
('de222d04-df95-42a1-9205-1d67d74c72a2','舟中望紫巖','唐彥謙','唐','唐诗','tang','','[]','近山如畫牆，遠山如帚長。',96,'全唐诗/poet.tang.37000.json','["近山如畫牆，遠山如帚長。", "我從雲中來，回頭白茫茫。", "惜去乃爾覺，常時自相忘。", "相忘豈不佳，遣此懷春傷。", "飄灑從何來，衣巾濕微涼。", "初疑風雨集，冉冉遊塵黃。", "無歸亦自可，信美非吾鄉。", "登舟望東雲，猶向帆端翔。"]'),
('46c76122-f22a-41f6-ac04-c509a7a566c7','九日遊中溪','唐彥謙','唐','唐诗','tang','','[]','悠悠循澗行，磊磊據石坐。',84,'全唐诗/poet.tang.37000.json','["悠悠循澗行，磊磊據石坐。", "林垂短長雲，山綴丹碧顆。", "蓼花最無數，照水嬌婀娜。", "何知是節序，風日自清妥。", "羣童競時新，萬果間蔬蓏。", "欣然爲之醉，烏帽危不墮。", "此日山中懷，孟公不如我。"]'),
('eaf0d290-1442-46ee-aaca-21ecd0f3da3d','六[月]十三日上陳微博士 一','唐彥謙','唐','唐诗','tang','','[]','驕雲飛散雨，隨風爲有無。',48,'全唐诗/poet.tang.37000.json','["驕雲飛散雨，隨風爲有無。", "老農終歲心，望施在須臾。", "平生官田粟，長此禮義軀。", "置之且勿戚，一飽任妻孥。"]'),
('9d1bfbd3-1f80-4710-ac8c-ef9b682995b8','六[月]十三日上陳微博士 二','唐彥謙','唐','唐诗','tang','','[]','青青澤中蒲，九夏氣淒寒。',48,'全唐诗/poet.tang.37000.json','["青青澤中蒲，九夏氣淒寒。", "翾翾翠碧羽，照影蒼溪間。", "巢由薄天下，俗士榮一官。", "小大各有適，自全良獨難。"]'),
('59bcf9aa-9648-402e-9cce-1f148dbaad0e','六[月]十三日上陳微博士 三','唐彥謙','唐','唐诗','tang','','[]','窮居無公憂，私此長夏日。',48,'全唐诗/poet.tang.37000.json','["窮居無公憂，私此長夏日。", "蚊蠅如俗子，正爾相妒嫉。", "麾驅非吾任，遁避亦無術。", "惟當俟其定，靜坐萬慮一。"]'),
('36fbd78e-ae9a-4093-9ab4-0d6f7c15dfb7','宿田家','唐彥謙','唐','唐诗','tang','','[]','落日下遙峰，荒村倦行履。',156,'全唐诗/poet.tang.37000.json','["落日下遙峰，荒村倦行履。", "停車息茅店，安寢正鼾睡。", "忽聞扣門急，云是下鄉隸。", "公文捧花柙，鷹隼駕聲勢。", "良民懼官府，聽之肝膽碎。", "阿母出搪塞，老脚走顛躓。", "小心事延欵，□餘糧復匱。", "東鄰借種雞，西舍覓芳醑。", "再飯不厭飽，一飲直呼醉。", "明朝怯見官，苦苦燈前跪。", "使我不成眠，爲渠滴清淚。", "民膏日已瘠，民力日愈弊。", "空懷伊尹心，何補堯舜治。"]'),
('c5c84dab-7f07-40b9-9abd-04f7eecacc5c','夏日訪友','唐彥謙','唐','唐诗','tang','','[]','[堤]樹生晝涼，濃陰撲空翠。',170,'全唐诗/poet.tang.37000.json','["[堤]樹生晝涼，濃陰撲空翠。", "孤舟喚野渡，村疃入幽邃。", "高軒俯清流，一犬隔花吠。", "童子立門牆，問我向何處？", "主人聞故舊，出迎時倒屣。", "驚迓敘間闊，屈指越寒暑。", "殷勤爲延欵，偶爾得良會。", "春盤擘紫蝦，冰鯉斫銀鱠。", "荷梗白玉香，荇菜青絲脆。", "臘酒擊泥封，羅列總新味。", "移席臨湖濱，對此有佳趣。", "流連送深杯，賓主共忘醉。", "清風岸烏紗，長揖謝君去。", "世事如浮雲，東西渺煙水。"]'),
('82bbc857-aee7-4b5d-a3ea-fd294d6a51a9','遊南明山','唐彥謙','唐','唐诗','tang','','[]','久聞南明山，共慕南明寺。',264,'全唐诗/poet.tang.37000.json','["久聞南明山，共慕南明寺。", "幾度欲登臨，日逐擾人事。", "于焉偶閑暇，鳴轡忽相聚。", "乘興樂遨遊，聊此托佳趣。", "涉水渡溪南，迢遙翠微裏。", "石磴千疊斜，峭壁半空起。", "白雲鎖峰腰，紅葉暗溪嘴。", "長藤絡虛巖，疎花映寒水。", "金銀拱梵剎，丹青照廊宇。", "石梁臥秋溟，風鈴作簷語。", "深洞結苔陰，嵐氣滴晴雨。", "羊腸轉咫尺，鳥道轉千里。", "屈曲到禪房，上人喜延竚。", "香分宿火薰，茶汲清泉煮。", "投閑息萬機，三生有宿契。", "行廚出盤飧，擔甕倒芳醑。", "脫冠挂長松，白石籍憑倚。", "宦途勞營營，暫此滌塵慮。", "鬮令促傳觴，投壺更聯句。", "興來較勝負，醉後忘爾汝。", "忽聞吼蒲牢，落日下雲嶼。", "長嘯出煙蘿，揚鞭賦歸去。"]'),
('3998ea07-b8ae-4c99-bafe-56f050ab6fc2','索蝦','唐彥謙','唐','唐诗','tang','','[]','姑孰多紫蝦，獨有湖陽優。',161,'全唐诗/poet.tang.37000.json','["姑孰多紫蝦，獨有湖陽優。", "出產在四時，極美宜於秋。", "雙箝鼓繁鬚，當頂抽長矛。", "鞠躬見湯王，封作朱衣侯。", "所以供盤餐，羅列同珍羞。", "蒜友日相親，瓜朋時與儔。", "既名釣詩釣，又作鉤詩鉤。", "于時同相訪，數日承欵留。", "厭飲多美味，獨此心相投。", "別來歲云久，馳想空悠悠。", "銜杯動遐思，{拶扌=口}口涎空流。", "封緘託雙鯉，于焉來遠求。", "慷慨胡隱君，果肯分惠否。"]'),
('5d29ab50-078c-4fa8-bb57-d106e5768cf1','採桑女','唐彥謙','唐','唐诗','tang','','[]','春風吹蠶細如蟻，桑芽纔努青鴉嘴。',64,'全唐诗/poet.tang.37000.json','["春風吹蠶細如蟻，桑芽纔努青鴉嘴。", "侵晨探采誰家女，手挽長條淚如雨。", "去歲初眠當此時，今歲春寒葉放遲。", "愁聽門外催里胥，官家二月收新絲。"]'),
('0808478b-7cea-4153-a2e6-a55df5fc0f7f','送許戶曹','唐彥謙','唐','唐诗','tang','','[]','沙頭小燕鳴春和，楊柳垂絲煙倒拖。',64,'全唐诗/poet.tang.37000.json','["沙頭小燕鳴春和，楊柳垂絲煙倒拖。", "將軍樓船發浩歌，雲檣高插天嵯峨。", "白虹走香傾翠壺，勸飲花前金叵羅。", "神鰲駕粟升天河，新承雨澤浮恩波。"]'),
('19510682-4733-4378-951b-9c41ca81b25d','詠葡萄','唐彥謙','唐','唐诗','tang','','[]','西園晚霽浮嫩涼，開尊漫摘葡萄嘗。',128,'全唐诗/poet.tang.37000.json','["西園晚霽浮嫩涼，開尊漫摘葡萄嘗。", "滿架高撐紫絡索，一枝斜嚲金琅璫。", "天風颼颼葉栩栩，蝴蝶聲乾作晴雨。", "神蛟清夜蟄寒潭，萬片濕雲飛不起。", "石家美人金谷遊，羅幃翠幕珊瑚鉤。", "玉盤新薦入華屋，珠帳高懸夜不收。", "勝遊記得當年景，清氣逼人毛骨冷。", "笑呼明鏡上遙天，醉倚銀牀弄秋影。"]'),
('7f93f70e-dfd1-4e3c-94d0-e9b9dbd3b047','蟹','唐彥謙','唐','唐诗','tang','','[]','湖田十月清霜墮，晚稻初香蟹如虎。',197,'全唐诗/poet.tang.37000.json','["湖田十月清霜墮，晚稻初香蟹如虎。", "扳罾拖網取賽多，篾簍挑將水邊貨。", "縱橫連爪一尺長，秀凝鐵色含湖光。", "蟛蜞石蟹已曾食，使我一見驚非常。", "買之最厭黃髯老，償價十錢尚嫌少。", "漫誇丰味過蝤蛑，尖臍猶勝團臍好。", "充盤煮熟堆琳琅，橙膏醬渫調堪嚐。", "一斗擘開紅玉滿，雙螯{拶扌=口}出瓊酥香。", "岸頭沽得泥封酒，細嚼頻斟弗停手。", "西風張翰苦思鱸，如斯丰味能知否。", "物之可愛尤可憎，嘗聞取刺於青蠅。", "無腸公子固稱美，弗使當道禁橫行。"]'),
('64662db3-c24b-4f67-aa1c-178bc6099bc7','敘別','唐彥謙','唐','唐诗','tang','','[]','譙樓夜促蓮花漏，樹陰搖月蛟螭走。',96,'全唐诗/poet.tang.37000.json','["譙樓夜促蓮花漏，樹陰搖月蛟螭走。", "蟠拏對月吸深杯，月府清虛玉兔吼。", "翠盤擘脯臙脂香，碧碗敲冰分蔗漿。", "十載番思舊時事，好懷不似當年狂。", "夜合花香開小院，坐愛涼風吹醉面。", "酒中彈劍發清歌，白髮年來爲愁變。"]'),
('b7f4c840-02b2-48c5-8a14-db3f5597fa9d','緋桃','唐彥謙','唐','唐诗','tang','','[]','短牆荒圃四無鄰，烈火緋桃照地春。',64,'全唐诗/poet.tang.37000.json','["短牆荒圃四無鄰，烈火緋桃照地春。", "坐久好風休掩袂，夜來微雨已霑巾。", "敢同俗態期青眼，似有微詞動絳脣。", "盡日更無鄉井念，此時何必見秦人。"]'),
('144d0d58-a575-4e99-9050-53b71f64cd16','小院','唐彥謙','唐','唐诗','tang','','[]','小院無人夜，煙斜月轉明。',24,'全唐诗/poet.tang.37000.json','["小院無人夜，煙斜月轉明。", "清宵易惆悵，不必有離情。"]'),
('ff465038-6de0-465a-8d6e-7f42128e9632','春雪初霽杏花正芳月上夜吟','唐彥謙','唐','唐诗','tang','','[]','霽景明如練，繁英杏正芳。',24,'全唐诗/poet.tang.37000.json','["霽景明如練，繁英杏正芳。", "姮娥應有語，悔共雪爭光。"]'),
('bd3e86b9-9bd2-40c4-9222-54e281c5d5e9','文惠宮人','唐彥謙','唐','唐诗','tang','','[]','認得前家令，宮人淚滿裾。',24,'全唐诗/poet.tang.37000.json','["認得前家令，宮人淚滿裾。", "不知梁佐命，全是沈尚書。"]'),
('a5ec7fdd-25ff-4a63-888c-ec8d895a6d23','贈竇尊師','唐彥謙','唐','唐诗','tang','','[]','我愛竇高士，棄官仍在家。',24,'全唐诗/poet.tang.37000.json','["我愛竇高士，棄官仍在家。", "爲嫌句漏令，兼不要丹砂。"]'),
('431db2b4-b9e2-4065-b63d-82e770dfe395','穆天子傳','唐彥謙','唐','唐诗','tang','','[]','王母清歌玉琯悲，瑤臺應有再來期。',32,'全唐诗/poet.tang.37000.json','["王母清歌玉琯悲，瑤臺應有再來期。", "穆王不得重相見，恐爲無端哭盛姬。"]'),
('030e6ebf-6656-41fa-a9a4-ddb40c13cd9b','楚天','唐彥謙','唐','唐诗','tang','','[]','楚天遙望每長嚬，宋玉襄王盡作塵。',32,'全唐诗/poet.tang.37000.json','["楚天遙望每長嚬，宋玉襄王盡作塵。", "不會瑤姬朝與暮，更爲雲雨待何人。"]'),
('2cd58725-7972-4c0a-82c1-1208d7179e39','寄徐山人','唐彥謙','唐','唐诗','tang','','[]','一室清羸鶴體孤，氣和神瑩爽冰壺。',32,'全唐诗/poet.tang.37000.json','["一室清羸鶴體孤，氣和神瑩爽冰壺。", "吳中高士雖求死，不那稽山有謝敷。"]'),
('f60e740d-c075-46d3-b516-1c57e4fc73db','題宗人故帖','唐彥謙','唐','唐诗','tang','','[]','所忠無處訪相如，風笈塵編跡尚餘。',32,'全唐诗/poet.tang.37000.json','["所忠無處訪相如，風笈塵編跡尚餘。", "惟有孝標情最厚，一編遺在茂陵書。"]'),
('9b28945d-b672-4430-8e55-3116136a9daf','垂柳','唐彥謙','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u5782\u67f3"]','絆惹春風別有情，世間誰敢鬬輕盈。',32,'全唐诗/poet.tang.37000.json','["絆惹春風別有情，世間誰敢鬬輕盈。", "楚王江畔無端種，餓損纖腰學不成。"]'),
('f644689b-48e5-4b7f-ab7a-40c60db072c6','登興元城觀烽火','唐彥謙','唐','唐诗','tang','','[]','漢川城上角三呼，扈蹕防邊列萬夫。',34,'全唐诗/poet.tang.37000.json','["漢川城上角三呼，扈蹕防邊列萬夫。", "[褒]姒冢前烽火起，不知泉下破顏無。"]'),
('855bb890-046d-4422-bc25-93866f17a472','鄧艾廟','唐彥謙','唐','唐诗','tang','','[]','昭烈遺黎死尚羞，揮刀斫石恨譙周。',32,'全唐诗/poet.tang.37000.json','["昭烈遺黎死尚羞，揮刀斫石恨譙周。", "如何千載留遺廟，血食巴山伴武侯。"]'),
('cfe27dcc-74c9-41b5-9978-048df211d2ec','曲江春望','唐彥謙','唐','唐诗','tang','','[]','杏豔桃光奪晚霞，樂遊無廟有年華。',32,'全唐诗/poet.tang.37000.json','["杏豔桃光奪晚霞，樂遊無廟有年華。", "漢朝冠蓋皆陵墓，十里宜春漢苑花。"]'),
('4bb1e5d6-490e-460e-b20c-f8af71e35740','漢殿','唐彥謙','唐','唐诗','tang','','[]','鳥去雲飛意不通，夜壇斜月轉松風。',32,'全唐诗/poet.tang.37000.json','["鳥去雲飛意不通，夜壇斜月轉松風。", "君主寂慮無消息，却就閑人覓巨公。"]'),
('98c60d7c-086d-4754-9dd9-16523bd6233d','賀李昌時禁苑新命','唐彥謙','唐','唐诗','tang','','[]','振鷺翔鸞集禁闈，玉堂珠樹瑩風儀。',32,'全唐诗/poet.tang.37000.json','["振鷺翔鸞集禁闈，玉堂珠樹瑩風儀。", "不知新到靈和殿，張緒何如柳一枝。"]'),
('30fcb6f0-962f-4d35-a0ea-076c1db5229f','牡丹','唐彥謙','唐','唐诗','tang','','[]','顏色無因饒錦繡，馨香惟解掩蘭蓀。',32,'全唐诗/poet.tang.37000.json','["顏色無因饒錦繡，馨香惟解掩蘭蓀。", "那堪更被煙蒙蔽，南國西施泣斷魂。"]'),
('91a574b5-9b5f-450e-b950-7d8cfb9d99e1','羅江驛','唐彥謙','唐','唐诗','tang','','[]','數枝高柳帶鳴鴉，一樹山榴自落花。',32,'全唐诗/poet.tang.37000.json','["數枝高柳帶鳴鴉，一樹山榴自落花。", "已是向來多淚眼，短亭回首在天涯。"]'),
('602256c1-8faf-43e2-88a2-46f771e67390','奏捷西蜀題沲江驛','唐彥謙','唐','唐诗','tang','','[]','野客乘軺非所宜，況將儒懦報戎機。',32,'全唐诗/poet.tang.37000.json','["野客乘軺非所宜，況將儒懦報戎機。", "錦江不識臨邛酒，且免相如渴病歸。"]'),
('455d3be6-fabb-42de-a545-f9d5913d8552','春早落英','唐彥謙','唐','唐诗','tang','','[]','紛紛從此見花殘，轉覺長繩繫日難。',32,'全唐诗/poet.tang.37000.json','["紛紛從此見花殘，轉覺長繩繫日難。", "樓上有愁春不淺，小桃風雪凭闌干。"]'),
('58694f54-5ba7-4322-96e6-cacb0f90ee9d','仲山','唐彥謙','唐','唐诗','tang','','[]','千載遺蹤寄薜蘿，沛中鄉里舊山河。',32,'全唐诗/poet.tang.37000.json','["千載遺蹤寄薜蘿，沛中鄉里舊山河。", "長陵亦是閑丘隴，異日誰知與仲多。"]'),
('d75e25c2-9637-4ef5-9a8a-1fc725ec5073','漢嗣','唐彥謙','唐','唐诗','tang','','[]','漢嗣安危繫數君，高皇決意勢難分。',32,'全唐诗/poet.tang.37000.json','["漢嗣安危繫數君，高皇決意勢難分。", "張良口辨周昌吃，同建儲宮第一勛。"]'),
('ac29d66c-fdca-421f-bd78-3b4a3c5bc288','四老廟','唐彥謙','唐','唐诗','tang','','[]','四漢儲宮定不傾，可能園綺勝良平。',32,'全唐诗/poet.tang.37000.json','["四漢儲宮定不傾，可能園綺勝良平。", "舉朝公將無全策，借請閑人羽翼成。"]'),
('8b5d3234-12a2-44fa-b041-2d4d14bf2e37','南梁戲題漢高廟','唐彥謙','唐','唐诗','tang','','[]','數載從軍似武夫，今隨戎捷氣偏粗。',32,'全唐诗/poet.tang.37000.json','["數載從軍似武夫，今隨戎捷氣偏粗。", "漢皇若問何爲者，免道高陽舊酒徒。"]'),
('0ada1932-6bb4-4afd-bfc3-d725de468653','洛神','唐彥謙','唐','唐诗','tang','','[]','人世仙家本自殊，何須相見向中途。',32,'全唐诗/poet.tang.37000.json','["人世仙家本自殊，何須相見向中途。", "驚鴻瞥過遊龍去，漫惱陳王一事無。"]'),
('232c82ad-4d7d-493f-9c7b-e831efd12de6','初秋到慈州冬首換絳牧','唐彥謙','唐','唐诗','tang','','[]','秋杪方攀玉樹枝，隔年無計待春暉。',32,'全唐诗/poet.tang.37000.json','["秋杪方攀玉樹枝，隔年無計待春暉。", "自嫌暫作仙城守，不逐鶯來共燕飛。"]'),
('e9067b4b-545b-4ba0-bcf7-7610f045b151','重經馮家舊里','唐彥謙','唐','唐诗','tang','','[]','馮家舊宅閉柴關，修竹猶存潏水灣。',32,'全唐诗/poet.tang.37000.json','["馮家舊宅閉柴關，修竹猶存潏水灣。", "應繫星辰天上去，不留英骨葬人間。"]'),
('efd3d75e-47af-415c-ac44-58496b3d6c0c','克復後登安國寺閣','唐彥謙','唐','唐诗','tang','','[]','千門萬戶鞠蒿藜，斷燼遺垣一望迷。',32,'全唐诗/poet.tang.37000.json','["千門萬戶鞠蒿藜，斷燼遺垣一望迷。", "惆悵建章鴛瓦盡，夜來空見玉繩低。"]'),
('3ea2a84e-056d-4f2e-aa5b-8daeb551ed16','題虔僧室','唐彥謙','唐','唐诗','tang','','[]','何緣春恨貯離憂，欲入空門萬事休。',32,'全唐诗/poet.tang.37000.json','["何緣春恨貯離憂，欲入空門萬事休。", "水月定中何所謂，也嚬眉黛托腮愁。"]'),
('06092d41-d9be-42ce-9cfb-4ecf721f1571','見煬帝寶帳','唐彥謙','唐','唐诗','tang','','[]','漢文窮相作前王，慳惜明珠不斗量。',32,'全唐诗/poet.tang.37000.json','["漢文窮相作前王，慳惜明珠不斗量。", "翡翠鮫鮹何所直，千裨萬接上書囊。"]'),
('cccf5c24-df42-4ff0-a375-03ea498a9c6b','樓上偶題','唐彥謙','唐','唐诗','tang','','[]','塵土無因狎隱淪，青山一望每傷神。',32,'全唐诗/poet.tang.37000.json','["塵土無因狎隱淪，青山一望每傷神。", "可能前嶺空喬木，應有懷才抱器人。"]'),
('df48bd3a-b7d3-480c-bb79-44cc58f14dc3','親仁里聞猨','唐彥謙','唐','唐诗','tang','','[]','朱雀街東半夜驚，楚魂湘夢兩徒清。',32,'全唐诗/poet.tang.37000.json','["朱雀街東半夜驚，楚魂湘夢兩徒清。", "五更撩亂趨朝火，滿口塵埃亦數聲。"]'),
('a9061c12-c4f7-4a5f-8992-10ae993bb8b9','聞李瀆司勛下世','唐彥謙','唐','唐诗','tang','','[]','異鄉丹旐已飄揚，一顧深知實未亡。',32,'全唐诗/poet.tang.37000.json','["異鄉丹旐已飄揚，一顧深知實未亡。", "任被褚裒泉下笑，重將北面哭真長。"]'),
('9e1cffb8-087d-411a-bd77-6e806471cf25','試夜題省廊桂','唐彥謙','唐','唐诗','tang','','[]','麻衣穿穴兩京塵，十見東堂綠桂春。',32,'全唐诗/poet.tang.37000.json','["麻衣穿穴兩京塵，十見東堂綠桂春。", "今日競飛楊葉箭，魏舒休作畫籌人。"]'),
('d3421523-ee8f-4bf5-b8ea-ca8b44bd1082','竹風','唐彥謙','唐','唐诗','tang','','[]','竹映風窗數陣斜，旅人愁坐思無涯。',32,'全唐诗/poet.tang.37000.json','["竹映風窗數陣斜，旅人愁坐思無涯。", "夜來留得江湖夢，全爲乾聲似荻花。"]'),
('e69a0297-df11-47ef-873f-c6aca41da396','長溪秋望','唐彥謙','唐','唐诗','tang','','[]','柳短莎長溪水流，雨微煙暝立溪頭。',32,'全唐诗/poet.tang.37000.json','["柳短莎長溪水流，雨微煙暝立溪頭。", "寒鴉閃閃前山去，杜曲黃昏獨自愁。"]'),
('00870aca-493c-4b2d-9f68-1e84075a73f8','嚴子陵','唐彥謙','唐','唐诗','tang','','[]','嚴陵情性是真狂，抵觸三公傲帝王。',32,'全唐诗/poet.tang.37000.json','["嚴陵情性是真狂，抵觸三公傲帝王。", "不怕舊交嗔僭越，喚他侯霸作君房。"]'),
('798f18b6-31ad-4cbe-9ae4-ba0df75d7cd4','北齊','唐彥謙','唐','唐诗','tang','','[]','草草招提強據鞍，周師乘勝莫回看。',32,'全唐诗/poet.tang.37000.json','["草草招提強據鞍，周師乘勝莫回看。", "背城肯戰知虛實，爭奈人前忍笑難。"]'),
('f864b46c-5236-45de-b917-bc9b10c3a92e','楚世家','唐彥謙','唐','唐诗','tang','','[]','偏信由來惑是非，一言邪佞脫危機。',32,'全唐诗/poet.tang.37000.json','["偏信由來惑是非，一言邪佞脫危機。", "張儀重入懷王手，駟馬安車却放歸。"]'),
('aa9f1396-f682-4145-aed4-fc19c51553f9','驪山道中','唐彥謙','唐','唐诗','tang','','[]','月殿真妃下綵煙，漁陽追虜及湯泉。',32,'全唐诗/poet.tang.37000.json','["月殿真妃下綵煙，漁陽追虜及湯泉。", "君王指點新豐樹，幾不親留七寶鞭。"]'),
('1c1187bd-a1bf-4d1b-96f5-c29c242dd98e','韋曲','唐彥謙','唐','唐诗','tang','','[]','欲寫愁腸愧不才，多情練漉已低摧。',32,'全唐诗/poet.tang.37000.json','["欲寫愁腸愧不才，多情練漉已低摧。", "窮郊二月初離別，獨傍寒村嗅野梅。"]'),
('0218ab59-76a7-47c3-b198-aea1550fe62b','黃子陂荷花','唐彥謙','唐','唐诗','tang','','[]','十頃狂風撼麴塵，緣堤照水露紅新。',32,'全唐诗/poet.tang.37000.json','["十頃狂風撼麴塵，緣堤照水露紅新。", "世間花氣皆愁絕，恰是蓮香更惱人。"]'),
('a9c958e3-e3e9-4402-a53b-163d3d70becb','野行','唐彥謙','唐','唐诗','tang','','[]','蝶戀晚花終不去，鷗逢春水固難飛。',32,'全唐诗/poet.tang.37000.json','["蝶戀晚花終不去，鷗逢春水固難飛。", "野人心地都無著，伴蝶隨鷗亦不歸。"]'),
('9565761b-37c5-4462-8037-d7ac632cd3b5','興元沈氏莊','唐彥謙','唐','唐诗','tang','','[]','清淺縈紆一水間，竹岡藤樹小躋攀。',64,'全唐诗/poet.tang.37000.json','["清淺縈紆一水間，竹岡藤樹小躋攀。", "露沾荒草行人過，月上高林宿鳥還。", "江遶武侯籌筆地，雨昏張載勒銘山。", "異鄉一笑因酣醉，忘却愁來鬢髮斑。"]'),
('3302cfb7-a9f9-400d-a9f4-b3e561cb251b','亂後經表兄瓊華觀舊居','唐彥謙','唐','唐诗','tang','','[]','一去仙居似轉蓬，再經花謝倚春叢。',64,'全唐诗/poet.tang.37000.json','["一去仙居似轉蓬，再經花謝倚春叢。", "醉中篇什金聲在，別後音書錦字空。", "長憶映碑逢若士，未曾攜杖逐壺公。", "東風狼籍苔侵徑，蕙草香銷杏帶紅。"]'),
('02b91c1b-d64c-4361-99ca-0010e7951df0','秋霽夜吟寄友人','唐彥謙','唐','唐诗','tang','','[]','槐柳蕭疎溽暑收，金商頻伏火西流。',64,'全唐诗/poet.tang.37000.json','["槐柳蕭疎溽暑收，金商頻伏火西流。", "塵衣歲晚緣身賤，雨簟更深滿背秋。", "前事悲涼何足道，遠書慵懶未能修。", "惟思待月高梧下，更就東牀訪惠休。"]'),
('6e03d233-35b3-4f07-829b-d0f03c5afe04','賀李昌時禁苑新命','唐彥謙','唐','唐诗','tang','','[]','玉簡金文直上清，禁垣丹地閉嚴扃。',64,'全唐诗/poet.tang.37000.json','["玉簡金文直上清，禁垣丹地閉嚴扃。", "黃扉議政參元化，紫殿稱觴拂壽星。", "萬戶千門迷步武，非煙非霧隔儀形。", "塵中舊侶無音信，知道遼東鶴姓丁。"]'),
('ff0acb7a-48b5-44a1-b398-0ff34501a593','寄蔣二十四','唐彥謙','唐','唐诗','tang','','[]','鳥囀蜂飛日漸長，旅人情味悔思量。',64,'全唐诗/poet.tang.37000.json','["鳥囀蜂飛日漸長，旅人情味悔思量。", "禪門澹薄無心地，世事生疎欲面牆。", "二月雲煙迷柳色，九衢風土帶花香。", "大知高士禁愁寂，試倚闌干莫斷腸。"]'),
('dfc8ad54-32ef-4eff-8a00-959196d41164','寄懷','唐彥謙','唐','唐诗','tang','','[]','有客傷春復怨離，夕陽亭畔草青時。',64,'全唐诗/poet.tang.37000.json','["有客傷春復怨離，夕陽亭畔草青時。", "淚從紅蠟無由制，腸比朱弦恐更危。", "梅向好風惟是笑，柳因微雨不勝垂。", "雙溪未去饒歸夢，夜夜孤眠枕獨欹。"]'),
('9872ab82-b0ea-41ed-bd0a-936689efd466','送樊琯司業歸朝','唐彥謙','唐','唐诗','tang','','[]','近者蘇司業，文雄道最光。',264,'全唐诗/poet.tang.37000.json','["近者蘇司業，文雄道最光。", "夫君居太學，妙譽繼中行。", "汲郡陵初發，汾陰篋久亡。", "寂寥方倚席，容易忽升堂。", "去日應懸榻，來時定裂裳。", "愜心頻拾芥，應手屢穿楊。", "辯急如無敵，飛騰固自強。", "論心期舌在，問事畏頭長。", "駟馬終題柱，諸生悉面牆。", "啗螯譏爾雅，賣餅訴公羊。", "未見泥函谷，俄驚火建章。", "煙塵昏象魏，行在隔巴梁。", "紅粟填郿塢，青袍過壽陽。", "翦茅行殿濕，伐栢舊陵香。", "黌室青衿盡，渠門火斾揚。", "雲飛同去國，星散各殊方。", "賤子悲窮轍，當年亦擅場。", "齏辛尋幼婦，醴酒憶先生。", "聖域探姬孔，皇風樂禹湯。", "畏誅輕李喜，言命小臧倉。", "折樹休盤槊，沈鉤且釣璜。", "鴻都問詞客，他日莫相忘。"]'),
('023753df-cc33-4e0c-a14c-a5ca1ba11779','奉使岐下聞唐弘夫行軍爲賊所擒傷而有作','唐彥謙','唐','唐诗','tang','','[]','報國捐軀實壯夫，楚囚垂欲復神都。',64,'全唐诗/poet.tang.37000.json','["報國捐軀實壯夫，楚囚垂欲復神都。", "雲臺畫像皆何者，青史書名或不孤。", "散卒半隨袁校尉，寡妻休問辟司徒。", "聞君敗績無歸計，氣激星辰坐向隅。"]'),
('ef4a9cfd-853b-4655-a89f-efe7b793fd00','咸通中始聞禇河南歸葬陽翟是歲上平徐方大肆慶賞又詔八品錫其裔孫追敘風概因成二十韻','唐彥謙','唐','唐诗','tang','','[]','冊府藏餘烈，皇綱正本朝。',240,'全唐诗/poet.tang.37000.json','["冊府藏餘烈，皇綱正本朝。", "不聽還笏諫，幾覆綴旒祧。", "咫尺言終直，愴惶道已消。", "淚心傳位日，揮涕授遺朝。", "飛燕潛來趙，黃龍豈見譙。", "既迷秦帝鹿，難問賈生鵰。", "穆卜緘縢秘，金根轍跡遙。", "北軍那奪印，東海漫難橋。", "羅織黃門訟，笙簧白骨銷。", "炎方無信息，丹旐竟淪漂。", "邂逅江魚食，淒涼楚客招。", "文忠徒諡議，子卯但簫韶。", "未見公侯復，尋傷嗣續凋。", "流年隨水逝，高誼薄層霄。", "柱石林公遠，縑緗故國饒。", "奇蹤天驥活，遺軸錦鸞翹。", "近者淮夷戮，前年歸馬調。", "始聞移北葬，兼議蔭山苗。", "聖澤覃將溥，貞魂喜定飄。", "異時窮巷客，懷古漫成謠。"]'),
('c0ca11a0-a942-4e70-aeb5-e44abd63cddd','岐王宅','唐彥謙','唐','唐诗','tang','','[]','朱邸平臺隔禁闈，貴遊陳跡尚依稀。',64,'全唐诗/poet.tang.37000.json','["朱邸平臺隔禁闈，貴遊陳跡尚依稀。", "雲低雍畤祈年去，雨細長楊縱獵歸。", "申白賓朋傳道義，應劉文彩寄音徽。", "承平舊物惟君盡，猶寫雕鞍伴六飛。"]'),
('3456b884-d9a6-4474-9319-0939544418e7','東韋曲野思','唐彥謙','唐','唐诗','tang','','[]','淡霧輕雲匝四垂，綠塘秋望獨顰眉。',64,'全唐诗/poet.tang.37000.json','["淡霧輕雲匝四垂，綠塘秋望獨顰眉。", "野蓮隨水無人見，寒鷺窺魚共影知。", "九陌要津勞目擊，五湖閑夢誘心期。", "孤燈夜夜愁欹枕，一覺滄洲似昔時。"]'),
('b92d3185-92e6-44e1-9295-19324f45c730','上巳','唐彥謙','唐','唐诗','tang','','[]','上巳接寒食，鶯花寥落晨。',48,'全唐诗/poet.tang.37000.json','["上巳接寒食，鶯花寥落晨。", "微微潑火雨，草草踏青人。", "涼似三秋景，清無九陌塵。", "與余同病者，對此合傷神。"]'),
('3baf222e-20c7-4f89-afa5-b25ce7d80109','移莎','唐彥謙','唐','唐诗','tang','','[]','移從杜城曲，置在小齋東。',96,'全唐诗/poet.tang.37000.json','["移從杜城曲，置在小齋東。", "正是高秋裏，仍兼細雨中。", "結根方迸竹，疎蔭託高桐。", "苒苒齊芳草，飄飄笑斷蓬。", "片時留靜者，一夜響鳴蛩。", "野露通宵滴，溪煙盡日蒙。", "試才卑庾薤，求味笑周菘。", "只此霜栽好，他時贈伯翁。"]'),
('b5fce2d0-f012-4ef2-85f1-29a2ab3fbf3d','西明寺威公盆池新稻','唐彥謙','唐','唐诗','tang','','[]','爲笑江南種稻時，露蟬鳴後雨霏霏。',64,'全唐诗/poet.tang.37000.json','["爲笑江南種稻時，露蟬鳴後雨霏霏。", "蓮盆積潤分畦小，藻井垂陰擢秀稀。", "得地又生金象界，結根仍對水田衣。", "支公尚有三吳思，更使幽人憶釣磯。"]'),
('7cebb127-e2e6-423d-a597-340dc11ecfdf','紅葉','唐彥謙','唐','唐诗','tang','','[]','無處不飄揚，高樓臨道旁。',168,'全唐诗/poet.tang.37000.json','["無處不飄揚，高樓臨道旁。", "素娥前夕月，青女夜來霜。", "宿雨隨時潤，秋晴著物光。", "幽懷長若此，病眼更相妨。", "蜀紙裁深色，燕脂落靚粧。", "低叢侵小閣，倒影入迴塘。", "謝朓留霞綺，甘寧棄錦張。", "何人休遠道，是處有斜陽。", "薜荔垂書幌，梧桐墜井牀。", "晚風生旅館，寒籟近僧房。", "桂綠明淮甸，楓丹照楚鄉。", "鴈疎臨鄠杜，蟬急傍瀟湘。", "樹異桓宣武，園非顧辟疆。", "茂陵愁臥客，不自保危腸。"]'),
('e1d52dcd-dea7-4a3c-ae21-ced8ef9101b7','鸂鶒','唐彥謙','唐','唐诗','tang','','[]','一宿南塘煙雨時，好風搖動綠波微。',64,'全唐诗/poet.tang.37000.json','["一宿南塘煙雨時，好風搖動綠波微。", "驚離曉岸衝花去，暖下春汀照影飛。", "華屋撚弦彈鼓舞，綺窗含筆澹毛衣。", "畫屏見後長迴首，爭得雕籠莫放歸。"]'),
('fbcb90ca-0359-4083-a0ac-a93543f2d958','螢','唐彥謙','唐','唐诗','tang','','[]','日下蕪城莽蒼中，濕螢撩亂起衰叢。',64,'全唐诗/poet.tang.37000.json','["日下蕪城莽蒼中，濕螢撩亂起衰叢。", "寒煙陳后長門閉，夜雨隋家舊苑空。", "星散欲陵前檻月，影低如試北窗風。", "羇人此夕方愁緒，心似寒灰首似蓬。"]'),
('9da82499-8e6f-446b-b6bb-08cb8df2d285','夜蟬','唐彥謙','唐','唐诗','tang','','[]','翠竹高梧夾後溪，勁風危露雨淒淒。',64,'全唐诗/poet.tang.37000.json','["翠竹高梧夾後溪，勁風危露雨淒淒。", "那知北牖殘燈暗，又送西樓片月低。", "清夜更長應未已，遠煙尋斷莫頻嘶。", "羇人此夕如三歲，不整寒衾待曙雞。"]'),
('cf0a3350-3a21-45ab-b44a-a289d8ba2812','七夕','唐彥謙','唐','唐诗','tang','','[]','露白風清夜向晨，小星垂佩月埋輪。',64,'全唐诗/poet.tang.37000.json','["露白風清夜向晨，小星垂佩月埋輪。", "絳河浪淺休相隔，滄海波深尚作塵。", "天外鳳皇何寂寞，世間烏鵲漫辛勤。", "倚闌殿北斜樓上，多少通宵不寐人。"]'),
('94029bef-b2e6-4192-9162-8bf12dd05595','中秋夜玩月','唐彥謙','唐','唐诗','tang','','[]','一夜高樓萬景奇，碧天無際水無涯。',64,'全唐诗/poet.tang.37000.json','["一夜高樓萬景奇，碧天無際水無涯。", "只留皎月當層漢，並送浮雲出四維。", "霧靜不容玄豹隱，冰生惟恐夏蟲疑。", "坐來離思憂將曉，爭得嫦娥仔細知。"]'),
('69f7d71f-65d5-4553-83cf-bc5788e976f8','八月十六日夜月','唐彥謙','唐','唐诗','tang','','[]','斷腸佳賞固難期，昨夜銷魂更不疑。',64,'全唐诗/poet.tang.37000.json','["斷腸佳賞固難期，昨夜銷魂更不疑。", "丹桂影空蟾有露，綠槐陰在鵲無枝。", "賴將吟詠聊惆悵，早是疎頑耐別離。", "堪恨賈生曾慟哭，不緣清景爲憂時。"]'),
('65d079f5-4f62-46c1-aeb2-5b013034f2a7','送韋向之睦州謁使君','唐彥謙','唐','唐诗','tang','','[]','才子南遊多遠情，閑舟蕩漾任春行。',32,'全唐诗/poet.tang.37000.json','["才子南遊多遠情，閑舟蕩漾任春行。", "新安江上長如此，何似新安太守清。"]'),
('ddab0d90-c461-4812-b58c-24187819875c','春殘','唐彥謙','唐','唐诗','tang','','[]','景爲春時短，愁隨別夜長。',48,'全唐诗/poet.tang.37000.json','["景爲春時短，愁隨別夜長。", "暫碁寧號隱，輕醉不成鄉。", "風雨曾通夕，莓苔有衆芳。", "落花如便去，樓上即河梁。"]'),
('e2355765-ba7d-4e13-93d9-4520f07f015d','玫瑰','唐彥謙','唐','唐诗','tang','','[]','麝炷騰清燎，鮫紗覆綠蒙。',48,'全唐诗/poet.tang.37000.json','["麝炷騰清燎，鮫紗覆綠蒙。", "宮妝臨曉日，錦段落東風。", "無力春烟裏，多愁暮雨中。", "不知何事意，深淺兩般紅。"]'),
('37186186-dfdd-4f65-8107-39e80ed4c6cb','牡丹','唐彥謙','唐','唐诗','tang','','[]','真宰多情巧思新，固將能事送殘春。',64,'全唐诗/poet.tang.37000.json','["真宰多情巧思新，固將能事送殘春。", "爲雲爲雨徒虛語，傾國傾城不在人。", "開日綺霞應失色，落時青帝合傷神。", "嫦娥婺女曾相送，留下鵶黃作蘂塵。"]'),
('076bef5a-c7b6-4811-ba7c-f479dc78af6a','秋晚高樓','唐彥謙','唐','唐诗','tang','','[]','松拂疎窗竹映闌，素琴幽怨不成彈。',64,'全唐诗/poet.tang.37000.json','["松拂疎窗竹映闌，素琴幽怨不成彈。", "清宵霽極雲離岫，紫禁風高露滿盤。", "晚蝶飄零驚宿雨，暮鴉淩亂報秋寒。", "高樓瞪目歸鴻遠，如信嵇康欲畫難。"]'),
('98a42465-6314-49bb-b34a-1383d7009e22','離鸞','唐彥謙','唐','唐诗','tang','','[]','聞道離鸞思故鄉，也知情願嫁王昌。',64,'全唐诗/poet.tang.37000.json','["聞道離鸞思故鄉，也知情願嫁王昌。", "塵埃一別楊朱路，風月三年宋玉牆。", "下疾不成雙點淚，斷多難到九迴腸。", "庭前佳樹名梔子，試結同心寄謝娘。"]'),
('d5c2041e-3163-434d-9b52-3c788426e7a3','柳','唐彥謙','唐','唐诗','tang','','[]','春思春愁一萬枝，遠村遙岸寄相思。',64,'全唐诗/poet.tang.37000.json','["春思春愁一萬枝，遠村遙岸寄相思。", "西園有雨和苔長，南內無人拂檻垂。", "遊客寂寥緘遠恨，暮鶯啼呌惜芳時。", "晚來飛絮如霜鬢，恐爲多情管別離。"]'),
('0d2f0e90-02bc-439c-83e6-6036b9b00e38','春陰','唐彥謙','唐','唐诗','tang','','[]','一寸迴腸百慮侵，旅愁危涕兩爭禁。',64,'全唐诗/poet.tang.37000.json','["一寸迴腸百慮侵，旅愁危涕兩爭禁。", "天涯已有銷魂別，樓上寧無擁鼻吟。", "感事不關河裏笛，傷心應倍雍門琴。", "春雲更覺愁于我，閑蓋低村作暝陰。"]'),
('6744cdde-c480-48a0-a8f2-6d7e66463c2b','春深獨行馬上有作','唐彥謙','唐','唐诗','tang','','[]','日烈風高野草香，百花狼籍柳披猖。',64,'全唐诗/poet.tang.37000.json','["日烈風高野草香，百花狼籍柳披猖。", "連天瑞靄千門遠，夾道新陰九陌長。", "衆飲不歡逃席酒，獨行無味放遊韁。", "年來與問閑遊者，若箇傷春向路旁。"]'),
('8aea48ef-e54c-43a9-9ef2-8ab5ecd9e232','春雨','唐彥謙','唐','唐诗','tang','','[]','綺陌夜來雨，春樓寒望迷。',120,'全唐诗/poet.tang.37000.json','["綺陌夜來雨，春樓寒望迷。", "遠客迎燕戲，亂響隔鶯啼。", "有恨開蘭室，無言對李蹊。", "花欹渾拂檻，柳重欲垂堤。", "燈檠昏魚目，薰爐咽麝臍。", "別輕天北鶴，夢怯汝南雞。", "入戶侵羅幌，捎簷潤繡題。", "新豐樹已失，長信草初齊。", "亂蝶寒猶舞，驚烏暝不栖。", "庾郎盤馬地，却怕有春泥。"]'),
('7507ea80-0696-42ea-be71-69907ce74308','漢代','唐彥謙','唐','唐诗','tang','','[]','漢代金爲屋，吳宮綺作寮。',242,'全唐诗/poet.tang.37000.json','["漢代金爲屋，吳宮綺作寮。", "豔詞傳靜婉，新曲定妖嬈。", "箭響猶殘夢，籤聲報早朝。", "鮮明臨曉日，迴轉度春宵。", "半袖籠清鏡，前絲壓翠翹。", "靜多如有待，閑極似無憀。", "梓澤花猶滿，靈和柳未凋。", "障昏巫峽雨，屏掩浙江潮。", "未信潘名岳，應疑史姓蕭。", "漏因歌暫斷，燈爲雨頻挑。", "飲酒闌三雅，投壺賽百嬌。", "鈿蟬新翅重，金鴨舊香焦。", "水淨疑澄練，霞孤欲建標。", "別隨秦柱促，愁爲蜀弦么。", "玄[晏]難瘳痹，臨邛但發痟。", "聯詩徵弱絮，思友詠甘蕉。", "王氏憐諸謝，周郎定小喬。", "黼幃翹綵雉，波扇畫文鰩。", "荇密妨垂釣，荷欹欲度橋。", "不因衣帶水，誰覺路迢迢。"]'),
('144bfac6-f8f2-4b32-a3a9-17189f6fb0e7','牡丹','唐彥謙','唐','唐诗','tang','','[]','青帝於君事分偏，穠堆浮豔倚朱門。',32,'全唐诗/poet.tang.37000.json','["青帝於君事分偏，穠堆浮豔倚朱門。", "雖然占得笙歌地，將甚酬他雨露恩。"]'),
('7749544e-0338-421c-b565-63d1d31d54df','湘妃廟','唐彥謙','唐','唐诗','tang','','[]','劉表荒碑斷水濱，廟前幽草閉殘春。',64,'全唐诗/poet.tang.37000.json','["劉表荒碑斷水濱，廟前幽草閉殘春。", "已將愁淚留斑竹，又感悲風入白蘋。", "八族未來誰北拱，四凶猶在莫南巡。", "九峰相似堪疑處，望見蒼梧不見人。"]'),
('f88f3726-a90a-4de7-8204-19cbfeca9e4e','句','唐彥謙','唐','唐诗','tang','','[]','獨來成悵望，不去泥欄干。',12,'全唐诗/poet.tang.37000.json','["獨來成悵望，不去泥欄干。"]'),
('adfa7a6b-735f-4c8b-a660-9a85f2f32557','題甘露寺','周朴','唐','唐诗','tang','','[]','層閣疊危壁，瑞因千古名。',48,'全唐诗/poet.tang.37000.json','["層閣疊危壁，瑞因千古名。", "幾連揚子路，獨倚潤州城。", "雲近銜江色，鵰高背磬聲。", "僧居上方久，端坐見營營。"]'),
('9173198a-adfa-4a09-bf35-d36a31e54533','題玄公院','周朴','唐','唐诗','tang','','[]','院深塵自外，如佛值玄公。',48,'全唐诗/poet.tang.37000.json','["院深塵自外，如佛值玄公。", "常跡或非次，志門因得中。", "衣巾離暑氣，牀榻向涼風。", "是事不逾分，秪應明德同。"]'),
('ca467dd8-3d91-4a5d-884c-e10f5680aa34','福州東禪寺','周朴','唐','唐诗','tang','','[]','甌閩在郊外，師院號東禪。',48,'全唐诗/poet.tang.37000.json','["甌閩在郊外，師院號東禪。", "物得居來正，人經論後賢。", "瓟槽柳塞馬，蓋地月支綖。", "鸛鵲尚巢頂，誰堪舉世傳。"]'),
('aef1dfca-db03-4449-8b3e-296dfbd65bda','贈大溈和尚','周朴','唐','唐诗','tang','','[]','大溈清復深，萬象影沈沈。',48,'全唐诗/poet.tang.37000.json','["大溈清復深，萬象影沈沈。", "有客衣多毳，空門偈勝金。", "王侯皆作禮，陸子只來吟。", "我問師心處，師言無處心。"]'),
('4e9613ea-517b-45df-8fe3-74c6850e3330','秋夜不寐寄崔溫進士','周朴','唐','唐诗','tang','','[]','愁多難得寐，展轉讀書牀。',48,'全唐诗/poet.tang.37000.json','["愁多難得寐，展轉讀書牀。", "不是旅人病，豈知秋夜長。", "歸鄉憑遠夢，無夢更思鄉。", "枕上移窗月，分明是淚光。"]'),
('0c64097e-4738-4cd5-8234-ee75b1a1b6aa','春中途中寄南巴崔使君','周朴','唐','唐诗','tang','','[]','旅人遊汲汲，春氣又融融。',48,'全唐诗/poet.tang.37000.json','["旅人遊汲汲，春氣又融融。", "農事蛙聲裏，歸程草色中。", "獨慙出穀雨，未變暖天風。", "子玉和予去，應憐恨不窮。"]'),
('dd032b02-6b8b-4c74-828f-5bc73253e095','寄處士方干','周朴','唐','唐诗','tang','','[]','桐廬江水閑，終日對柴關。',48,'全唐诗/poet.tang.37000.json','["桐廬江水閑，終日對柴關。", "因想別離處，不知多少山。", "釣舟春岸泊，庭樹曉鶯還。", "莫便求棲隱，桂枝堪恨顏。"]'),
('93df7eb4-6e1b-4cb5-b278-56c889930906','寄塞北張符','周朴','唐','唐诗','tang','','[]','隴樹塞風吹，遼城角幾枝。',48,'全唐诗/poet.tang.37000.json','["隴樹塞風吹，遼城角幾枝。", "霜凝無暫歇，君貌莫應衰。", "萬里平沙際，一行邊鴈移。", "那堪朔煙起，家信正相離。"]'),
('88454909-4a51-4b48-be11-a36ea0aab22f','次梧州却寄永州使君','周朴','唐','唐诗','tang','','[]','隨風身不定，今夜在蒼梧。',48,'全唐诗/poet.tang.37000.json','["隨風身不定，今夜在蒼梧。", "客淚有時有，猨聲無處無。", "潮添瘴海闊，煙拂粤山孤。", "却憶零陵住，吟詩半玉壺。"]'),
('148a5b30-2fe5-467d-bdf7-b5e327770a4f','贈念經僧','周朴','唐','唐诗','tang','','[]','菴前古折碑，夜靜念經時。',48,'全唐诗/poet.tang.37000.json','["菴前古折碑，夜靜念經時。", "月皎海霞散，露濃山草垂。", "鬼聞拋故塚，禽聽離寒枝。", "想得天花墜，馨香拂白眉。"]'),
('dd9b236d-5f5a-4d7c-9a2d-efbfa49507a7','董嶺水','周朴','唐','唐诗','tang','','[]','湖州安吉縣，門與白雲齊。',48,'全唐诗/poet.tang.37000.json','["湖州安吉縣，門與白雲齊。", "禹力不到處，河聲流向西。", "去衙山色遠，近水月光低。", "中有高人在，沙中曳杖藜。"]'),
('afd85f67-caa1-4ff2-af35-523b3d1908d8','早春','周朴','唐','唐诗','tang','','[]','良夜歲應足，嚴風爲變春。',48,'全唐诗/poet.tang.37000.json','["良夜歲應足，嚴風爲變春。", "遍回寒作暖，通改舊成新。", "秀樹因馨雨，融冰雨泛蘋。", "韶光不偏黨，積漸煦疲民。"]'),
('4de3847c-0f6f-47ed-9f0d-708229932772','秋深','周朴','唐','唐诗','tang','','[]','柳色尚沈沈，風吹秋更深。',48,'全唐诗/poet.tang.37000.json','["柳色尚沈沈，風吹秋更深。", "山河空遠道，鄉國自鳴砧。", "巷有千家月，人無萬里心。", "長城哭崩後，寂絕至如今。"]'),
('42e1f1d2-bfd5-45c8-b800-6b9e4aae8a55','贈雙峰山和尚','周朴','唐','唐诗','tang','','[]','峩峩雙髻山，瀑布瀉雲間。',48,'全唐诗/poet.tang.37000.json','["峩峩雙髻山，瀑布瀉雲間。", "塵世自疑水，禪門長去關。", "茯神松不異，藏寶石俱閑。", "向此師清業，如何方可攀。"]'),
('1e94187b-8ccd-495d-a737-b1677735b703','贈無了禪師','周朴','唐','唐诗','tang','','[]','不學世所惜，是何無了公。',48,'全唐诗/poet.tang.37000.json','["不學世所惜，是何無了公。", "靈匡虛院外，虎跡亂山中。", "晝夜必連去，古今爭敢同。", "禪情豈堪問，問答更無窮。"]'),
('edb0d494-c237-43d8-a450-5f5136fff1b0','王霸壇','周朴','唐','唐诗','tang','','[]','王君上升處，信首古居前。',48,'全唐诗/poet.tang.37000.json','["王君上升處，信首古居前。", "皂樹即須朽，白龜應亦全。", "雲間猶一日，塵裏已千年。", "碧色壇如黛，時人誰可仙。"]'),
('af75607e-7a59-4dad-9d5c-1df896690654','送梁道士','周朴','唐','唐诗','tang','','[]','舊居桐栢觀，歸去愛安閑。',48,'全唐诗/poet.tang.37000.json','["舊居桐栢觀，歸去愛安閑。", "倒樹造新屋，化人修古壇。", "晚花霜後落，山雨夜深寒。", "應有同溪客，相尋學鍊丹。"]'),
('ec7329f3-4e6d-49e1-af7e-742cb7e3a143','邊思','周朴','唐','唐诗','tang','','[]','年高來遠戍，白首罷干戎。',48,'全唐诗/poet.tang.37000.json','["年高來遠戍，白首罷干戎。", "夜色薊門火，秋聲邊塞風。", "磧浮悲老馬，月滿引新弓。", "百戰陰山去，唯添上將雄。"]'),
('e8113c1d-dfb4-46a0-9596-0f254eb3aa43','哭陳庾','周朴','唐','唐诗','tang','','[]','繫馬向山立，一桮聊奠君。',48,'全唐诗/poet.tang.37000.json','["繫馬向山立，一桮聊奠君。", "野煙孤客路，寒草故人墳。", "琴韻歸流水，詩情寄白雲。", "日斜休哭後，松韻不堪聞。"]'),
('172e0de9-61de-4a49-ac01-8a354acf015a','宿玉泉寺','周朴','唐','唐诗','tang','','[]','野寺度殘夏，空房欲暮時。',48,'全唐诗/poet.tang.37000.json','["野寺度殘夏，空房欲暮時。", "夜聽猨不睡，秋思客先知。", "竹迥煙生薄，山高月上遲。", "又登塵路去，難與老僧期。"]'),
('48c7611e-eb2e-47ec-8d2e-7fd83ab844fb','題赤城中巖寺','周朴','唐','唐诗','tang','','[]','浮世師休話，晉時燈照巖。',48,'全唐诗/poet.tang.37000.json','["浮世師休話，晉時燈照巖。", "禽飛穿靜戶，藤結入高杉。", "存沒詩千首，廢興經數函。", "誰知將俗耳，來此避囂讒。"]'),
('d27ae6e7-0723-4dab-a402-aed1845d1b12','塞上行','周朴','唐','唐诗','tang','','[]','秦築長城在，連雲磧氣侵。',48,'全唐诗/poet.tang.37000.json','["秦築長城在，連雲磧氣侵。", "風吹邊草急，角絕塞鴻沈。", "世世征人往，年年戰骨深。", "遼天望鄉者，迴首盡霑襟。"]'),
('f4ad0f91-8da6-4627-aa01-ba3e11adf0e0','玉泉寺','周朴','唐','唐诗','tang','','[]','寺還名玉泉，澄水亦遭賢。',48,'全唐诗/poet.tang.37000.json','["寺還名玉泉，澄水亦遭賢。", "物尚猶如此，人爭合偶然。", "溪流雲斷外，山峻鳥飛還。", "初日長廊下，高僧正坐禪。"]'),
('1d6885a4-d11e-4428-80a8-fcf75d7a41aa','春宮怨','周朴','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5bab\u6028", "\u6625\u5929", "\u5199\u666f", "\u5973\u5b50", "\u4e94\u8a00\u5f8b\u8bd7"]','早被嬋娟誤，欲妝臨鏡慵。',48,'全唐诗/poet.tang.37000.json','["早被嬋娟誤，欲妝臨鏡慵。", "承恩不在貌，教妾若爲容。", "風暖鳥聲碎，日高花影重。", "年年越溪女，相憶采芙蓉。"]'),
('4bcdc4bc-0691-4adc-92b3-f81f25cf234c','宿劉溫書齋','周朴','唐','唐诗','tang','','[]','不掩盈窗日，天然格調高。',48,'全唐诗/poet.tang.37000.json','["不掩盈窗日，天然格調高。", "涼風移蟋蟀，落葉在離騷。", "迴筆挑燈燼，懸圖見海潮。", "因論三國志，空載幾英豪。"]'),
('9539b768-44d3-4717-bb53-0b200a4f63bd','登福州南澗寺','周朴','唐','唐诗','tang','','[]','萬里重山遶福州，南橫一道見溪流。',64,'全唐诗/poet.tang.37000.json','["萬里重山遶福州，南橫一道見溪流。", "天邊飛鳥東西沒，塵裏行人早晚休。", "曉日青山當大海，連雲古塹對高樓。", "那堪望斷他鄉目，只此蕭條自白頭。"]'),
('669bc8c6-6413-4dcc-a834-88a82403c6d0','望中懷古','周朴','唐','唐诗','tang','','[]','齊心樓上望浮雲，萬古千秋空姓名。',64,'全唐诗/poet.tang.37000.json','["齊心樓上望浮雲，萬古千秋空姓名。", "堯水永銷天際去，姬風一變世間平。", "高蹤盡共煙霞在，大道長將日月明。", "從此安然寰海內，後來無復謾相傾。"]'),
('8f8eb51c-6bef-472b-bf1c-93fbd249677c','昇山寺','周朴','唐','唐诗','tang','','[]','昇山自古道飛來，此是神功不可猜。',64,'全唐诗/poet.tang.37000.json','["昇山自古道飛來，此是神功不可猜。", "氣色雖然離禹穴，峰巒猶自接天台。", "巖邊折樹泉衝落，頂上浮雲日照開。", "南望閩城塵世界，千秋萬古卷塵埃。"]'),
('d63cf89e-c809-4b70-b190-cd27a51c45dc','哭李端','周朴','唐','唐诗','tang','','[]','三年翦拂感知音，哭向青山永夜心。',64,'全唐诗/poet.tang.37000.json','["三年翦拂感知音，哭向青山永夜心。", "竹在曉煙孤鳳去，劍荒秋水一龍沈。", "新墳日落松聲小，舊色春殘草色深。", "不及此時親執紼，石門遙想淚霑襟。"]'),
('7ac2d077-1ba7-48e6-994a-b7d152d5adbb','福州神光寺塔','周朴','唐','唐诗','tang','','[]','良匠用材爲塔了，神光寺更得高名。',64,'全唐诗/poet.tang.37000.json','["良匠用材爲塔了，神光寺更得高名。", "風雲會處千尋出，日月中時八面明。", "海水旋流倭國野，天文方戴福州城。", "相輪頂上望浮世，塵裏人心應總平。"]'),
('8f1a435f-9941-48bd-bf81-80fa01d04b48','福州開元寺塔','周朴','唐','唐诗','tang','','[]','開元寺裏七重塔，遙對方山影擬齊。',64,'全唐诗/poet.tang.37000.json','["開元寺裏七重塔，遙對方山影擬齊。", "雜俗人看離世界，孤高僧上覺天低。", "唯堪片片紫霞映，不與濛濛白霧迷。", "心若無私羅漢在，參差免向日虹西。"]'),
('2cb331b8-ffef-42be-ab42-e30fc2e7d383','春日秦國懷古','周朴','唐','唐诗','tang','','["\u6625\u5929", "\u6000\u53e4", "\u4f24\u6000"]','荒郊一望欲消魂，涇水縈紆傍遠村。',64,'全唐诗/poet.tang.37000.json','["荒郊一望欲消魂，涇水縈紆傍遠村。", "牛馬放多春草盡，原田耕破古碑存。", "雲和積雪蒼山晚，煙伴殘陽綠樹昏。", "數里黃沙行客路，不堪回首思秦原。"]'),
('c8e7a3ea-0e05-45fc-9468-362527d15798','春日遊北園寄韓侍郎','周朴','唐','唐诗','tang','','[]','灼灼春園晚色分，露珠千點映寒雲。',64,'全唐诗/poet.tang.37000.json','["灼灼春園晚色分，露珠千點映寒雲。", "多情舞蝶穿花去，解語流鶯隔水聞。", "冷酒桮中宜泛灩，暖風林下自氛氳。", "仙桃不肯全開拆，應借餘芳待使君。"]'),
('5b21673f-2700-4605-a4f2-78d0efaf1060','喜賀拔先輩衡陽除正字','周朴','唐','唐诗','tang','','[]','黃紙晴空墜一緘，聖朝恩澤洗冤讒。',64,'全唐诗/poet.tang.37000.json','["黃紙晴空墜一緘，聖朝恩澤洗冤讒。", "李膺門客爲閑客，梅福官銜改舊銜。", "名自石渠書典籍，香從芸閣著衣衫。", "寰中不用憂天旱，霖雨看看屬傅巖。"]'),
('549a98db-6f91-41d2-a98c-8f06b26a9ef2','客州賃居寄蕭郎中','周朴','唐','唐诗','tang','','[]','松店茅軒向水開，東頭舍賃一裴徊。',64,'全唐诗/poet.tang.37000.json','["松店茅軒向水開，東頭舍賃一裴徊。", "窗吟苦爲秋江靜，枕夢驚因曉角催。", "鄰舍見愁賒酒與，主人知去索錢來。", "眼看白筆爲霖雨，肯使紅鱗便曝腮。"]'),
('434fe02b-98e9-4068-912c-29e513cd811c','贈李裕先輩','周朴','唐','唐诗','tang','','[]','曉擎弓箭入初場，一發曾穿百步楊。',64,'全唐诗/poet.tang.37000.json','["曉擎弓箭入初場，一發曾穿百步楊。", "仙籍舊題前進士，聖朝新奏校書郎。", "馬疑金馬門前馬，香認芸香閣上香。", "閑伴李膺紅燭下，慢吟絲竹淺飛觴。"]'),
('62881fc4-7cf5-4e38-8e75-aacd47fdb453','桐栢觀','周朴','唐','唐诗','tang','','[]','東南一境清心目，有此千峰插翠微。',64,'全唐诗/poet.tang.37000.json','["東南一境清心目，有此千峰插翠微。", "人在下方衝月上，鶴從高處破煙飛。", "巖深水落寒侵骨，門靜花開色照衣。", "欲識蓬萊今便是，更於何處學忘機。"]'),
('eb3931b1-3b65-44f9-a979-1c749ac7d430','塞上','周朴','唐','唐诗','tang','','[]','受降城必破，回落隴頭移。',24,'全唐诗/poet.tang.37000.json','["受降城必破，回落隴頭移。", "蕃道北海北，謀生今始知。"]'),
('527b7fc3-3898-4e30-b649-f8a9cbf16353','塞上曲','周朴','唐','唐诗','tang','','["\u9ec4\u6cb3"]','一陣風來一陣砂，有人行處沒人家。',32,'全唐诗/poet.tang.37000.json','["一陣風來一陣砂，有人行處沒人家。", "黃河九曲冰先合，紫塞三春不見花。"]'),
('4dfd76b7-11e6-43d5-ab9d-8145553c4c5b','塞下曲','周朴','唐','唐诗','tang','','[]','石國胡兒向磧東，愛吹橫笛引秋風。',32,'全唐诗/poet.tang.37000.json','["石國胡兒向磧東，愛吹橫笛引秋風。", "夜來雲雨皆飛盡，月照平沙萬里空。"]'),
('6e794434-0677-4f98-a588-aca026ea2ea5','詠猨','周朴','唐','唐诗','tang','','[]','生在巫山更向西，不知何事到巴溪。',32,'全唐诗/poet.tang.37000.json','["生在巫山更向西，不知何事到巴溪。", "中宵爲憶秋雲伴，遙隔朱門向月啼。"]'),
('b021697a-0896-4e93-93a1-29e78e0817ac','桃花','周朴','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u6843\u82b1", "\u548f\u7269"]','桃花春色暖先開，明媚誰人不看來。',32,'全唐诗/poet.tang.37000.json','["桃花春色暖先開，明媚誰人不看來。", "可惜狂風吹落後，殷紅片片點莓苔。"]'),
('7b78ae39-ccbf-4836-a4d0-6dc37ed0ce3a','薛老峰','周朴','唐','唐诗','tang','','[]','薛老峰頭三箇字，須知此與石齊生。',32,'全唐诗/poet.tang.37000.json','["薛老峰頭三箇字，須知此與石齊生。", "直叫截斷蒼苔色，浮世人儕眼始明。"]'),
('81a259d8-fd33-49f0-820b-64228f1bba38','弔李羣玉','周朴','唐','唐诗','tang','','[]','羣玉詩名冠李唐，投詩換得校書郎。',32,'全唐诗/poet.tang.37000.json','["羣玉詩名冠李唐，投詩換得校書郎。", "吟魂醉魄知何處，空有幽蘭隔岸香。"]'),
('459c03be-e75f-4801-8732-d9cd022204a6','無等巌','周朴','唐','唐诗','tang','','[]','建造上方藤影裏，高僧往往似天台。',32,'全唐诗/poet.tang.37000.json','["建造上方藤影裏，高僧往往似天台。", "不知名樹簷前長，曾問道人巖下來。"]'),
('c3c6a742-bef3-40ef-9e4b-2205c6f4802d','句','周朴','唐','唐诗','tang','','[]','古陵寒雨集，高鳥夕陽明。',136,'全唐诗/poet.tang.37000.json','["古陵寒雨集，高鳥夕陽明。", "高情千里外，長嘯一聲初。", "月離山一丈，風吹花數苞。", "曉來山鳥鬧，雨過杏花稀。", "曲渚回灣鎖釣舟，平潮晚影沈清底。", "遠岳危欄等翠尖。", "白日纔離滄海底，清光先照戶窗前。", "連雲天塹有山色，極目海門無鴈行。", "可憐黃雀銜將去，從此莊周夢不成。", "禪是大溈詩是朴，大唐天子只三人。"]'),
('9475130c-3a09-49e2-ac32-eaf4866227a6','感興','鄭谷','唐','唐诗','tang','','[]','禾黍不陽豔，競栽桃李春。',24,'全唐诗/poet.tang.37000.json','["禾黍不陽豔，競栽桃李春。", "翻令力耕者，半作賣花人。"]'),
('e2e399d8-82da-454c-bbb0-388f4e589a30','望湘亭','鄭谷','唐','唐诗','tang','','[]','湘水似伊水，湘人非故人。',24,'全唐诗/poet.tang.37000.json','["湘水似伊水，湘人非故人。", "登臨獨無語，風柳自搖春。"]'),
('5d958afe-1ba1-4056-b2f3-68dda8805daf','採桑','鄭谷','唐','唐诗','tang','','[]','曉陌攜籠去，桑林路隔淮。',24,'全唐诗/poet.tang.37000.json','["曉陌攜籠去，桑林路隔淮。", "何如鬬百草，賭取鳳皇釵。"]'),
('f54ebdbc-a17a-4125-8d95-49bf7698810a','悶題','鄭谷','唐','唐诗','tang','','[]','落第春相困，無心惜落花。',24,'全唐诗/poet.tang.37000.json','["落第春相困，無心惜落花。", "荆山歸不得，歸得亦無家。"]'),
('06c0d244-7834-4623-b101-9672acd41f0a','中臺五題 乳毛松','鄭谷','唐','唐诗','tang','','[]','松格一何高，何人號乳毛。',24,'全唐诗/poet.tang.37000.json','["松格一何高，何人號乳毛。", "霜天寓直夜，媿爾伴閑曹。"]'),
('e306ef99-7a58-4d13-a94d-47352bb464dd','中臺五題 樗里子墓','鄭谷','唐','唐诗','tang','','[]','賢人骨已銷，墓樹幾榮凋。',24,'全唐诗/poet.tang.37000.json','["賢人骨已銷，墓樹幾榮凋。", "正直魂如在，齋心願一招。"]'),
('1118a7b2-5de0-4e5d-afcc-c66dd0875ddd','中臺五題 牡丹','鄭谷','唐','唐诗','tang','','[]','亂前看不足，亂後眼偏明。',24,'全唐诗/poet.tang.37000.json','["亂前看不足，亂後眼偏明。", "却得蓬蒿力，遮藏見太平。"]'),
('c7abfc59-e9b1-4478-b5d0-759557ea0329','中臺五題 玉蕊','鄭谷','唐','唐诗','tang','','[]','唐昌樹已荒，天意眷文昌。',24,'全唐诗/poet.tang.37000.json','["唐昌樹已荒，天意眷文昌。", "曉入微風起，春時雪滿牆。"]'),
('06120cbe-6b9c-4ad5-ad4a-b2a6c2c44004','中臺五題 石柱','鄭谷','唐','唐诗','tang','','[]','暴亂免遺折，森羅賢達名。',24,'全唐诗/poet.tang.37000.json','["暴亂免遺折，森羅賢達名。", "末郎何所取，叨繼外門榮。"]'),
('970f7083-a0a9-4d87-a8b0-af70f9c738c6','別同志','鄭谷','唐','唐诗','tang','','[]','所立共寒苦，平生同與遊。',48,'全唐诗/poet.tang.37000.json','["所立共寒苦，平生同與遊。", "相看臨遠水，獨自上孤舟。", "天澹滄浪晚，風悲蘭杜秋。", "前程吟此景，爲子上高樓。"]'),
('35e73f53-22fe-4c27-9c27-acd8cbfb3eeb','送進士盧棨東歸','鄭谷','唐','唐诗','tang','','[]','灞岸草萋萋，離觴我獨攜。',48,'全唐诗/poet.tang.37000.json','["灞岸草萋萋，離觴我獨攜。", "流年俱老大，失意又東西。", "曉楚山雲滿，春吳水樹低。", "到家梅雨歇，猶有子規啼。"]'),
('d5a2b004-a0cc-4884-b8ab-655f551d450b','從叔郎中諴輟自秋曹分符安陸屬羣盜倡熾流毒江壖竟以援兵不來城池失守例削今任却敘省銜退居荆漢之間頗得琴尊之趣因有寄獻','鄭谷','唐','唐诗','tang','','[]','華省稱前任，何慙削一麾。',48,'全唐诗/poet.tang.37000.json','["華省稱前任，何慙削一麾。", "滄洲失孤壘，白髮出重圍。", "苦節翻多難，空山自喜歸。", "悠悠清漢上，漁者日相依。"]'),
('8a4d09c8-2fcf-4ee3-b6ff-3c221b4ad57b','送徐渙端公南歸','鄭谷','唐','唐诗','tang','','[]','青衿離白社，朱綬始言歸。',48,'全唐诗/poet.tang.37000.json','["青衿離白社，朱綬始言歸。", "此去應多羨，初心盡不違。", "江帆和日落，越鳥近鄉飛。", "一路春風裏，楊花雪滿衣。"]'),
('bcb2d91c-5f92-47f0-8112-688bb12191f0','送祠部曹郎中鄴出守洋州','鄭谷','唐','唐诗','tang','','[]','爲儒欣出守，上路亦戎裝。',48,'全唐诗/poet.tang.37000.json','["爲儒欣出守，上路亦戎裝。", "舊製詩多諷，分憂俗必康。", "開懷江稻熟，寄信露橙香。", "郡閣清吟夜，寒星識望郎。"]'),
('fbca58f1-5ee9-4d70-ac74-901305f22195','送進士許彬','鄭谷','唐','唐诗','tang','','[]','泗上未休兵，壺關事可驚。',48,'全唐诗/poet.tang.37000.json','["泗上未休兵，壺關事可驚。", "流年催我老，遠道念君行。", "殘雪臨晴水，寒梅發故城。", "何當食新稻，歲稔又時平。"]'),
('97dd6f37-3469-4a2b-8e63-e7e188bb6743','次韻和王駕校書結綬見寄之什','鄭谷','唐','唐诗','tang','','[]','直應歸諫署，方肯別山村。',48,'全唐诗/poet.tang.37000.json','["直應歸諫署，方肯別山村。", "勤苦常同業，孤單共感恩。", "醉披仙鶴氅，吟扣野僧門。", "夢見君高趣，天涼自灌園。"]'),
('a0ebca0a-4fe8-47ec-bdf4-902134941923','祕閣伴直','鄭谷','唐','唐诗','tang','','[]','祕閣鎖書深，牆南列晚岑。',48,'全唐诗/poet.tang.37000.json','["祕閣鎖書深，牆南列晚岑。", "吏人同野鹿，庭木似山林。", "淺井寒蕪入，迴廊疊蘚侵。", "閑看薛稷鶴，共起五湖心。"]'),
('3d25649e-7389-4de2-a723-c0512223cef9','送太學顏明經及第東歸','鄭谷','唐','唐诗','tang','','[]','平楚干戈後，田園失耦耕。',48,'全唐诗/poet.tang.37000.json','["平楚干戈後，田園失耦耕。", "艱難登一第，離亂省諸兄。", "樹沒春江漲，人繁野渡晴。", "閑來思學館，猶夢雪窗明。"]'),
('3d353ba3-bf5c-4d53-97d8-7e7e00422034','送進士趙能卿下第南歸','鄭谷','唐','唐诗','tang','','[]','不歸何慰親，歸去舊風塵。',48,'全唐诗/poet.tang.37000.json','["不歸何慰親，歸去舊風塵。", "灑淚慙關吏，無言對越人。", "遠帆花月夜，微岸水天春。", "莫便隨漁釣，平生已苦辛。"]'),
('b35ef2a4-078a-41b7-9541-6b305d444485','送人遊邊','鄭谷','唐','唐诗','tang','','[]','春亦怯邊遊，此行風正秋。',48,'全唐诗/poet.tang.37000.json','["春亦怯邊遊，此行風正秋。", "別離逢雨夜，道路向雲州。", "磧樹藏城近，沙河漾日流。", "將軍方破虜，莫惜獻良籌。"]'),
('e9f97979-33f0-4409-9bc5-f22033fb9c88','送人之九江謁郡侯苗員外紳','鄭谷','唐','唐诗','tang','','[]','澤國尋知己，南浮不偶遊。',48,'全唐诗/poet.tang.37000.json','["澤國尋知己，南浮不偶遊。", "湓城分楚塞，廬岳對江州。", "曉飯臨孤嶼，春帆入亂流。", "雙旌相望處，月白庾公樓。"]'),
('0809abcc-ebe3-4894-aa5a-7742d0a45497','送許棠先輩之官涇縣','鄭谷','唐','唐诗','tang','','[]','白頭新作尉，縣在故山中。',48,'全唐诗/poet.tang.37000.json','["白頭新作尉，縣在故山中。", "高第能卑宦，前賢尚此風。", "蕪湖春蕩漾，梅雨晝溟濛。", "佐理人安後，篇章莫廢功。"]'),
('66bce220-92a1-498d-87c1-2fb07cc6c46b','送司封從叔員外徼赴華州裴尚書均辟','鄭谷','唐','唐诗','tang','','[]','如何拋錦帳，蓮府對蓮峰。',48,'全唐诗/poet.tang.37000.json','["如何拋錦帳，蓮府對蓮峰。", "舊有雲霞約，暫留鵷鷺蹤。", "敷溪秋雪岸，樹谷夕陽鐘。", "盡入新吟境，歸朝興莫慵。"]'),
('76dfced5-edc8-4e45-bc96-b016f2e80e55','送京參翁先輩歸閩中','鄭谷','唐','唐诗','tang','','[]','解印東歸去，人情此際多。',48,'全唐诗/poet.tang.37000.json','["解印東歸去，人情此際多。", "名高五七字，道勝兩重科。", "宿館明寒燒，吟船兀夜波。", "家山春更好，越鳥在庭柯。"]'),
('77644a16-9c16-4560-b8d5-7848efb235cb','贈別','鄭谷','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','南遊曾共遊，相別倍相留。',48,'全唐诗/poet.tang.37000.json','["南遊曾共遊，相別倍相留。", "行色迴燈曉，離聲滿竹秋。", "穩眠彭蠡浪，好醉岳陽樓。", "明日逢佳景，爲君成白頭。"]'),
('1475ea34-3848-4378-8f8e-56aa9e3acd68','南遊','鄭谷','唐','唐诗','tang','','[]','淒涼懷古意，湘浦弔靈均。',48,'全唐诗/poet.tang.37000.json','["淒涼懷古意，湘浦弔靈均。", "故國經新歲，扁舟寄病身。", "山城多曉瘴，澤國少晴春。", "漸遠無相識，青梅獨向人。"]'),
('78bcc825-2ec5-47da-9f31-20af2732e10d','巴賨旅寓寄朝中從叔','鄭谷','唐','唐诗','tang','','[]','驚秋思浩然，信美向巴天。',48,'全唐诗/poet.tang.37000.json','["驚秋思浩然，信美向巴天。", "獨倚臨江樹，初聞落日蟬。", "哀榮悲往事，漂泊念多年。", "未便甘休去，吾宗盡見憐。"]'),
('d83f1b02-75d7-46ad-9c73-2bee7429bf0d','寄司勳張員外學士','鄭谷','唐','唐诗','tang','','[]','平昔偏知我，司勳張外郎。',48,'全唐诗/poet.tang.37000.json','["平昔偏知我，司勳張外郎。", "昨來聞俶擾，憂甚欲顛狂。", "煙暝搔愁鬢，春陰賴酒鄉。", "江樓倚不得，橫笛數聲長。"]'),
('3fc6261b-efad-4f0f-8340-c558047e0f4f','寄邊上從事','鄭谷','唐','唐诗','tang','','[]','男兒懷壯節，何不事嫖姚？',48,'全唐诗/poet.tang.37000.json','["男兒懷壯節，何不事嫖姚？", "高疊觀諸寨，全師護大朝。", "淺山寒放馬，亂火夜防苗。", "下第春愁甚，勞君遠見招。"]'),
('b2a2a7d7-d0d9-4730-9ed4-0235f45e914e','寄左省韋起居序','鄭谷','唐','唐诗','tang','','[]','風神何蘊藉，張緒正當年。',48,'全唐诗/poet.tang.37000.json','["風神何蘊藉，張緒正當年。", "端簡爐香裏，濡毫洞案邊。", "飾裝無雨備，著述減春眠。", "旦夕應彌入，銀臺曉候宣。"]'),
('1e4f7010-1066-4c6a-91e7-00b1eb09cbab','寄贈藍田韋少府先輩','鄭谷','唐','唐诗','tang','','[]','王畿第一縣，縣尉是詞人。',48,'全唐诗/poet.tang.37000.json','["王畿第一縣，縣尉是詞人。", "館殿非初意，圖書是舊貧。", "斫冰泉竇響，賽雪廟松春。", "自此昇通籍，清華日近身。"]'),
('fa22927a-e512-48ce-b7c5-326418a3b2a3','寄懷元秀上人','鄭谷','唐','唐诗','tang','','[]','悠悠干祿利，草草廢漁樵。',48,'全唐诗/poet.tang.37000.json','["悠悠干祿利，草草廢漁樵。", "身世堪惆悵，風騷頗寂寥。", "高秋期野步，積雨放趨朝。", "得句如相憶，莎齋且見招。"]'),
('844d089f-dcdc-4686-85b0-9a39f894cac8','贈圓昉公','鄭谷','唐','唐诗','tang','','[]','天階讓紫衣，冷格鶴猶卑。',48,'全唐诗/poet.tang.37000.json','["天階讓紫衣，冷格鶴猶卑。", "道勝嫌名出，身閑覺老遲。", "晚香延宿火，寒磬度高枝。", "長說長松寺，他年與我期。"]'),
('3dfcb210-81f9-4bfa-91cb-07760c83cb9c','寄題方干處士','鄭谷','唐','唐诗','tang','','[]','山雪照湖水，漾舟湖畔歸。',48,'全唐诗/poet.tang.37000.json','["山雪照湖水，漾舟湖畔歸。", "松篁調遠籟，臺榭發清輝。", "野岫分閑徑，漁家並掩扉。", "暮年詩力在，新句更幽微。"]'),
('d83f0120-fe2f-403e-9c3f-a48b97e02596','寄獻湖州從叔員外','鄭谷','唐','唐诗','tang','','[]','顧渚山邊郡，溪將罨畫通。',72,'全唐诗/poet.tang.37000.json','["顧渚山邊郡，溪將罨畫通。", "遠看城郭裏，全在水雲中。", "西閣歸何晚，東吳興未窮。", "茶香紫筍露，洲迥白蘋風。", "歌緩眉低翠，杯明蠟翦紅。", "政成尋往事，輟棹問漁翁。"]'),
('392575e8-2a26-48a0-b16a-0af2e0c1213d','訪姨兄王斌渭口別墅','鄭谷','唐','唐诗','tang','','[]','枯桑河上村，寥落舊田園。',120,'全唐诗/poet.tang.37000.json','["枯桑河上村，寥落舊田園。", "少小曾來此，悲涼不可言。", "訪鄰多指塚，問路半移原。", "久歉家僮散，初晴野薺繁。", "客帆懸極浦，漁網曬危軒。", "苦澀詩盈篋，荒唐酒滿尊。", "高枝霜果在，幽渚暝禽喧。", "遠靄籠樵響，微煙起燒痕。", "哀榮孤族分，感激外兄恩。", "三宿忘歸去，圭峰恰對門。"]'),
('1232b7c5-52d7-4dd2-a1e1-9f546c5f54bd','放朝偶作','鄭谷','唐','唐诗','tang','','[]','寒極放朝天，欣聞半夜宣。',48,'全唐诗/poet.tang.37000.json','["寒極放朝天，欣聞半夜宣。", "時安逢密雪，日晏得高眠。", "擁褐同休假，吟詩賀有年。", "坐來幽興在，松亞小窗前。"]'),
('d226c9ea-34d0-4f8b-bdce-c176c10a2e70','順動後藍田偶作','鄭谷','唐','唐诗','tang','','[]','小諫昇中諫，三年侍玉除。',48,'全唐诗/poet.tang.37000.json','["小諫昇中諫，三年侍玉除。", "且言無所補，浩歎欲何如。", "宮闕飛灰燼，嬪嬙落里閭。", "藍峰秋更碧，霑灑望鑾輿。"]'),
('0be9014a-b079-4eaf-85e1-bcf389c4ca59','府中寓止寄趙大諫','鄭谷','唐','唐诗','tang','','[]','老作含香客，貧無僦舍錢。',48,'全唐诗/poet.tang.37000.json','["老作含香客，貧無僦舍錢。", "神州容寄跡，大尹是同年。", "密邇都忘倦，乖慵益見憐。", "雪風花月好，中夜便招延。"]'),
('1598d864-b035-4b18-95f6-a596474a7307','峽中寓止二首 一','鄭谷','唐','唐诗','tang','','[]','荆州未解圍，小縣結茅茨。',48,'全唐诗/poet.tang.37000.json','["荆州未解圍，小縣結茅茨。", "強對官人笑，甘爲野鶴欺。", "江春鋪網闊，市晚鬻蔬遲。", "子美猶如此，翻然不敢悲。"]'),
('44a3f6dd-62d4-4905-bd7a-ea183dc4fecd','峽中寓止二首 二','鄭谷','唐','唐诗','tang','','[]','傳聞殊不定，鑾輅幾時還。',48,'全唐诗/poet.tang.37000.json','["傳聞殊不定，鑾輅幾時還。", "俗易無常性，江清見老顏。", "夜船歸草市，春步上茶山。", "寨將來相問，兒童競啓關。"]'),
('79719c6a-fc74-4955-9a91-13e8c49beec1','顏惠詹事即孤姪舅氏謫官黔巫舟中相遇愴然有寄','鄭谷','唐','唐诗','tang','','[]','猶子在天末，念渠懷渭陽。',48,'全唐诗/poet.tang.37000.json','["猶子在天末，念渠懷渭陽。", "巴山偶會遇，江浦共悲涼。", "謫宦君何遠，窮遊我自強。", "瘴村三月暮，雨熟野梅黃。"]'),
('7f3204c7-b72f-4f0e-ae4c-4fb61849cdcc','訪題進士孫秦延福南街居','鄭谷','唐','唐诗','tang','','[]','多病久離索，相尋聊解顏。',48,'全唐诗/poet.tang.37000.json','["多病久離索，相尋聊解顏。", "短牆通御水，疎樹出南山。", "歲月何難老，園林未得還。", "無門共榮達，孤坐却如閑。"]'),
('60161877-54b7-421d-92ba-51c0fa9a2ae0','訪題進士張喬延興門外所居','鄭谷','唐','唐诗','tang','','[]','平生苦節同，旦夕會原東。',48,'全唐诗/poet.tang.37000.json','["平生苦節同，旦夕會原東。", "掩卷斜陽裏，看山落木中。", "星霜今欲老，江海業全空。", "近日文場內，因君起古風。"]'),
('8b7115fc-e5f8-4def-89a6-56f0559014df','寄南浦謫官','鄭谷','唐','唐诗','tang','','[]','多才翻得罪，天末抱窮憂。',48,'全唐诗/poet.tang.37000.json','["多才翻得罪，天末抱窮憂。", "白首爲遷客，青山繞萬州。", "醉敧梅障曉，歌厭竹枝秋。", "望闕懷鄉淚，荆江水共流。"]'),
('be57868c-6584-4ee1-87ac-b5e59ef81968','李夷遇侍御久滯水鄉因抒寄懷','鄭谷','唐','唐诗','tang','','[]','簪豸年何久，懸帆興甚長。',48,'全唐诗/poet.tang.37000.json','["簪豸年何久，懸帆興甚長。", "江流愛吳越，詩格愈齊梁。", "竹寺晴吟遠，蘭洲晚泊香。", "高閑徒自任，華省待爲郎。"]'),
('6faa3d59-1de6-4284-83d1-39c6c5e7dcef','寄膳部李郎中昌符','鄭谷','唐','唐诗','tang','','[]','鄠郊陪野步，早歲偶因詩。',48,'全唐诗/poet.tang.37000.json','["鄠郊陪野步，早歲偶因詩。", "自後吟新句，長愁減舊知。", "靜燈微落燼，寒硯旋生澌。", "夜夜冥搜苦，那能鬢不衰。"]'),
('42ee2a56-ac50-41c1-b9c3-2c5e8872193f','寄前水部賈員外嵩','鄭谷','唐','唐诗','tang','','[]','謝病別文昌，仙舟向越鄉。',48,'全唐诗/poet.tang.37000.json','["謝病別文昌，仙舟向越鄉。", "貴爲金馬客，雅稱水曹郎。", "白鷺同孤潔，清波共渺茫。", "相如詞賦外，騷雅趣何長。"]'),
('fe74ba79-c322-43f5-9390-43ee36154ea5','寄棊客','鄭谷','唐','唐诗','tang','','[]','松窗楸局穩，相顧思皆凝。',48,'全唐诗/poet.tang.37000.json','["松窗楸局穩，相顧思皆凝。", "幾局賭山果，一先饒海僧。", "覆圖聞夜雨，下子對秋燈。", "何日無羈束，期君向杜陵。"]'),
('222bcf1a-a0e6-41e8-91b9-1ae34ba60e95','聞進士許彬罷舉歸睦州悵然懷寄','鄭谷','唐','唐诗','tang','','[]','桐廬歸舊廬，垂老復樵漁。',48,'全唐诗/poet.tang.37000.json','["桐廬歸舊廬，垂老復樵漁。", "吾子雖言命，鄉人嬾讀書。", "煙舟撐晚浦，雨屐翦春蔬。", "異代名方振，哀吟莫廢初。"]'),
('f0f1ef55-b1a4-458b-8314-50efa095932a','長安夜坐寄懷湖外嵇處士','鄭谷','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','萬里念江海，浩然天地秋。',48,'全唐诗/poet.tang.37000.json','["萬里念江海，浩然天地秋。", "風高羣木落，夜久數星流。", "鐘絕分宮漏，螢微隔御溝。", "遙思洞庭上，葦露滴漁舟。"]'),
('da6f210d-321b-4692-9a87-42b5e444c76f','贈文士王雄','鄭谷','唐','唐诗','tang','','[]','知己竟何人，哀君尚苦辛。',48,'全唐诗/poet.tang.37000.json','["知己竟何人，哀君尚苦辛。", "圖書長在手，文學老於身。", "公道天難廢，貞姿世任嗔。", "小齋松菊靜，願卜子爲鄰。"]'),
('ca0c1dbf-78fc-45a8-b856-4652cc197744','贈富平李宰','鄭谷','唐','唐诗','tang','','[]','夫君清且貧，琴鶴最相親。',48,'全唐诗/poet.tang.37000.json','["夫君清且貧，琴鶴最相親。", "簡肅諸曹事，安閑一境人。", "陵山雲裏拜，渠路雨中巡。", "易得連宵醉，千缸石凍春。"]'),
('c1c80038-e979-4381-92ea-5e6d0a23e4bf','贈尚顏上人','鄭谷','唐','唐诗','tang','','[]','相尋喜可知，放錫便論詩。',48,'全唐诗/poet.tang.37000.json','["相尋喜可知，放錫便論詩。", "酷愛山兼水，唯應我與師。", "風雷吟不覺，猨鶴老爲期。", "近輩推棲白，其如趣向卑。"]'),
('26f3d1d1-5f6b-4b50-9134-3b82443697f2','贈泗口苗居士','鄭谷','唐','唐诗','tang','','[]','歲[晏]樂園林，維摩契道心。',50,'全唐诗/poet.tang.37000.json','["歲[晏]樂園林，維摩契道心。", "江雲寒不散，庭雪夜方深。", "酒勸漁人飲，詩憐稚子吟。", "四郊多壘日，勉我捨朝簪。"]'),
('cff7c426-c46e-4f4e-8575-50c02997d2ad','梁燭處士辭金陵相國杜公歸舊山因以寄贈','鄭谷','唐','唐诗','tang','','[]','相庭留不得，江野有苔磯。',48,'全唐诗/poet.tang.37000.json','["相庭留不得，江野有苔磯。", "兩浙尋山徧，孤舟載鶴歸。", "世間書讀盡，雲外客來稀。", "諫署搜賢急，應難惜布衣。"]'),
('5b10f825-4867-4311-8c18-81ec35423a9a','哭建州李員外頻','鄭谷','唐','唐诗','tang','','[]','令終歸故里，末歲道如初。',48,'全唐诗/poet.tang.37000.json','["令終歸故里，末歲道如初。", "舊友誰爲誌，清風豈易書。", "雨墳生野蕨，鄉奠釣江魚。", "獨夜吟還泣，前年伴直廬。"]'),
('300b6db6-c240-4aaa-91ad-1f0403e8cc36','哭進士李洞二首 一','鄭谷','唐','唐诗','tang','','[]','所惜絕吟聲，不悲君不榮。',48,'全唐诗/poet.tang.37000.json','["所惜絕吟聲，不悲君不榮。", "李端終薄宦，賈島得高名。", "旅葬新墳小，遺孤遠俗輕。", "猶疑隨計晚，昨夜草蟲鳴。"]'),
('d3acfa17-77e7-4676-8acb-6dd2fad0ad26','哭進士李洞二首 二','鄭谷','唐','唐诗','tang','','["\u957f\u6c5f"]','自聞東蜀病，唯我獨關情。',48,'全唐诗/poet.tang.37000.json','["自聞東蜀病，唯我獨關情。", "若近長江死，想君勝在生。", "瘴蒸丹旐溼，燈隔素帷清。", "塚樹僧栽後，新蟬一兩聲。"]'),
('cb9dcfa1-25b5-4611-be0a-350da38999e7','南康郡牧陸肱郎中辟許棠先輩爲郡從事因有寄贈','鄭谷','唐','唐诗','tang','','[]','末路思前侶，猶爲戀故巢。',48,'全唐诗/poet.tang.37000.json','["末路思前侶，猶爲戀故巢。", "江山多勝境，賓主是貧交。", "飲舫閑依葦，琴堂雅結茅。", "夜清僧伴宿，水月在松梢。"]'),
('e26dfc08-eb62-48de-b735-19f83e4d8ea4','久不得張喬消息','鄭谷','唐','唐诗','tang','','[]','天末去程孤，沿淮復向吳。',48,'全唐诗/poet.tang.37000.json','["天末去程孤，沿淮復向吳。", "亂離何處甚，安穩到家無。", "樹盡雲垂野，檣稀月滿湖。", "傷心繞村落，應少舊耕夫。"]'),
('eed2de63-331e-434f-891c-d862e2cfd997','題嵩高隱者居','鄭谷','唐','唐诗','tang','','[]','豈易訪仙蹤，雲蘿千萬重。',48,'全唐诗/poet.tang.37000.json','["豈易訪仙蹤，雲蘿千萬重。", "他年來卜隱，此景願相容。", "亂水林中路，深山雪裏鐘。", "見君琴酒樂，迴首興何慵。"]'),
('c9bf9abc-a7ff-41c0-8a45-8dff7736d001','趙璘郎中席上賦蝴蝶','鄭谷','唐','唐诗','tang','','[]','尋豔復尋香，似閑還似忙。',48,'全唐诗/poet.tang.37000.json','["尋豔復尋香，似閑還似忙。", "暖煙沈蕙徑，微雨宿花房。", "書幌輕隨夢，歌樓誤採粧。", "王孫深屬意，繡入舞衣裳。"]'),
('eb096f6d-1d57-430f-a0ad-9f218b3c1bfb','賀進士駱用錫登第','鄭谷','唐','唐诗','tang','','[]','苦辛垂二紀，擢第却霑裳。',48,'全唐诗/poet.tang.37000.json','["苦辛垂二紀，擢第却霑裳。", "春榜到春晚，一家榮一鄉。", "題名登塔喜，醵宴爲花忙。", "好是東歸日，高槐蕊半黃。"]'),
('0f58c478-8cb8-4fdb-94e3-db1ab8b63c46','興州東池','鄭谷','唐','唐诗','tang','','[]','南連乳郡流，闊碧侵晴樓。',48,'全唐诗/poet.tang.37000.json','["南連乳郡流，闊碧侵晴樓。", "徹底千峰影，無風一片秋。", "垂楊拂蓮葉，返照媚漁舟。", "鑑貌還惆悵，難遮兩鬢羞。"]'),
('5e1c59a6-0edc-4d3f-8a87-686b6694372a','渠江旅思','鄭谷','唐','唐诗','tang','','[]','流落復蹉跎，交親半逝波。',48,'全唐诗/poet.tang.37000.json','["流落復蹉跎，交親半逝波。", "謀生非不切，言命欲如何。", "故楚春田廢，窮巴瘴雨多。", "引人鄉淚盡，夜夜竹枝歌。"]'),
('dd70a78d-99a0-4416-ba4a-1c9df7369ba9','登杭州城','鄭谷','唐','唐诗','tang','','[]','漠漠江天外，登臨返照間。',48,'全唐诗/poet.tang.37000.json','["漠漠江天外，登臨返照間。", "潮來無別浦，木落見他山。", "沙鳥晴飛遠，漁人夜唱閑。", "歲窮歸未得，心逐片帆還。"]'),
('ee54b661-5efa-4e46-9de6-4c0cd5d97170','曲江','鄭谷','唐','唐诗','tang','','[]','細草岸西東，酒旗遙水風。',48,'全唐诗/poet.tang.37000.json','["細草岸西東，酒旗遙水風。", "樓臺在煙杪，鷗鷺下沙中。", "翠幄晴相接，芳洲夜暫空。", "何人賞秋景，興與此時同。"]'),
('f00a5d87-052e-455a-b7a2-ea2334595f4e','沙苑','鄭谷','唐','唐诗','tang','','[]','茫茫信馬行，不似近都城。',48,'全唐诗/poet.tang.37000.json','["茫茫信馬行，不似近都城。", "苑吏猶迷路，江人莫問程。", "聚來千嶂出，落去一川平。", "日暮客心速，愁聞鴈數聲。"]'),
('b65ae50c-c9f7-4a49-96c3-9be6fc7ef668','通川客舍','鄭谷','唐','唐诗','tang','','[]','奔走失前計，淹留非本心。',48,'全唐诗/poet.tang.37000.json','["奔走失前計，淹留非本心。", "已難消永夜，況復聽秋霖。", "漸解巴兒語，誰憐越客吟。", "黃花徒滿手，白髮不勝簪。"]'),
('2c52178e-dab1-4503-b237-ae684be73d5a','潼關道中','鄭谷','唐','唐诗','tang','','[]','白道曉霜迷，離燈照馬嘶。',48,'全唐诗/poet.tang.37000.json','["白道曉霜迷，離燈照馬嘶。", "秋風滿關樹，殘月隔河雞。", "來往非無倦，窮通豈易齊。", "何年歸故社，披雨翦春畦。"]'),
('372f68ec-80f0-4cde-96d7-838a6b685707','終南白鶴觀','鄭谷','唐','唐诗','tang','','[]','步步景通真，門前衆水分。',48,'全唐诗/poet.tang.37000.json','["步步景通真，門前衆水分。", "檉蘿諸洞合，鐘磬上清聞。", "古木千尋雪，寒山萬丈雲。", "終期掃壇級，來事紫陽君。"]'),
('1429477e-9ddb-4161-8db9-6b1080e65750','題興善寺寂上人院','鄭谷','唐','唐诗','tang','','["\u5e90\u5c71"]','客來風雨後，院靜似荒涼。',48,'全唐诗/poet.tang.37000.json','["客來風雨後，院靜似荒涼。", "罷講蛩離砌，思山葉滿廊。", "臘高興故疾，爐暖發餘香。", "自說匡廬側，杉陰半石牀。"]'),
('90006838-c447-4e1c-8c03-c83facd4bd62','題水部李羽員外招國里居','鄭谷','唐','唐诗','tang','','[]','野色入前軒，翛然琴與尊。',48,'全唐诗/poet.tang.37000.json','["野色入前軒，翛然琴與尊。", "畫僧依寺壁，栽葦學江村。", "自醞花前酒，誰敲雪裏門。", "不辭朝謁遠，唯要近慈恩。"]'),
('a58f9d42-feb5-4a5a-ab8c-ec9fdb4cb71a','信美寺岑上人','鄭谷','唐','唐诗','tang','','[]','巡禮諸方徧，湘南頗有緣。',48,'全唐诗/poet.tang.37000.json','["巡禮諸方徧，湘南頗有緣。", "焚香老山寺，乞食向江船。", "紗碧籠名畫，燈寒照淨禪。", "我來能永日，蓮漏滴堦前。"]'),
('6f41f7ef-b692-415d-98ae-2427a2aa8658','池上','鄭谷','唐','唐诗','tang','','[]','池榭愜幽獨，狂吟學解嘲。',48,'全唐诗/poet.tang.37000.json','["池榭愜幽獨，狂吟學解嘲。", "露荷香自在，風竹冷相敲。", "喪志嫌孤宦，忘機愛澹交。", "仙山如有分，必擬訪三茅。"]'),
('1b97a119-8ca5-4b5a-b32f-405a81b10393','遊貴侯城南林墅','鄭谷','唐','唐诗','tang','','[]','韋杜八九月，亭臺高下風。',48,'全唐诗/poet.tang.37000.json','["韋杜八九月，亭臺高下風。", "獨來新霽後，閑步澹煙中。", "荷密連池綠，柿繁和葉紅。", "主人貪貴達，清境屬鄰翁。"]'),
('a966d644-6313-473f-af5c-94823af3b15c','江行','鄭谷','唐','唐诗','tang','','[]','漂泊病難任，逢人淚滿襟。',48,'全唐诗/poet.tang.37000.json','["漂泊病難任，逢人淚滿襟。", "關東多事日，天末未歸心。", "夜雨荆江漲，春雲郢樹深。", "殷勤聽漁唱，漸次入吳音。"]'),
('ca55870b-64f4-428a-bd39-8a2d080cd873','舟次通泉精舍','鄭谷','唐','唐诗','tang','','[]','江清如洛汭，寺好似香山。',48,'全唐诗/poet.tang.37000.json','["江清如洛汭，寺好似香山。", "勞倦孤舟裏，登臨半日間。", "樹涼巢鶴健，巖響語僧閑。", "更共幽雲約，秋隨絳帳還。"]'),
('a2156336-cca1-461c-96b4-1f5dcf5f3cf2','水軒','鄭谷','唐','唐诗','tang','','[]','日日狎沙禽，偷安且放吟。',48,'全唐诗/poet.tang.37000.json','["日日狎沙禽，偷安且放吟。", "讀書老不入，愛酒病還深。", "歉後爲羈客，兵餘問故林。", "楊花滿牀席，搔首度春陰。"]'),
('951ba8b3-9879-43fa-b7ae-304b21ffbd7e','潯陽姚宰廳作','鄭谷','唐','唐诗','tang','','[]','縣幽公事稀，庭草是山薇。',48,'全唐诗/poet.tang.37000.json','["縣幽公事稀，庭草是山薇。", "足得招棊侶，何妨著道衣。", "野泉當案落，汀鷺入衙飛。", "寺去東林近，多應隔宿歸。"]'),
('28ad1b60-0ce3-4f80-98bf-dff98c2b3979','梓潼歲暮','鄭谷','唐','唐诗','tang','','[]','江城無宿雪，風物易爲春。',48,'全唐诗/poet.tang.37000.json','["江城無宿雪，風物易爲春。", "酒美消磨日，梅香著莫人。", "老吟窮景象，多難損精神。", "漸有還京望，綿州減戰塵。"]'),
('d7f2144f-e5d8-4ef7-97a8-22957d42a811','咸陽','鄭谷','唐','唐诗','tang','','[]','咸陽城下宿，往事可悲思。',48,'全唐诗/poet.tang.37000.json','["咸陽城下宿，往事可悲思。", "未有謀身計，頻遷反正期。", "凍河孤棹澀，老樹疊巢危。", "莫問今行止，漂漂不自知。"]'),
('5a4e98b2-d058-4981-b696-200351020e9c','長安感興','鄭谷','唐','唐诗','tang','','[]','徒勞悲喪亂，自古戒繁華。',48,'全唐诗/poet.tang.37000.json','["徒勞悲喪亂，自古戒繁華。", "落日狐兔徑，近年公相家。", "可悲聞玉笛，不見走香車。", "寂寞牆匡裏，春陰挫杏花。"]'),
('faace781-a5e0-4839-b36f-8c2f30f1923c','聞所知遊樊川有寄','鄭谷','唐','唐诗','tang','','[]','誰無泉石趣，朝下少同過。',48,'全唐诗/poet.tang.37000.json','["誰無泉石趣，朝下少同過。", "貪勝覺程近，愛閑經宿多。", "片沙留白鳥，高木引青蘿。", "醉把漁竿去，殷勤藉岸莎。"]'),
('8afe0123-e8cd-4859-8f7a-e67b98bcdb1d','張谷田舍','鄭谷','唐','唐诗','tang','','[]','縣官清且儉，深谷有人家。',48,'全唐诗/poet.tang.37000.json','["縣官清且儉，深谷有人家。", "一徑入寒竹，小橋穿野花。", "碓喧春澗滿，梯倚綠桑斜。", "自說年來稔，前村酒可賒。"]'),
('9345c5d2-2a0e-4c42-902f-e66cf08395fa','深居','鄭谷','唐','唐诗','tang','','[]','吾道有誰同，深居自固窮。',48,'全唐诗/poet.tang.37000.json','["吾道有誰同，深居自固窮。", "殷勤謝綠樹，朝夕惠清風。", "書滿閑窗下，琴橫野艇中。", "年來頭更白，雅稱釣魚翁。"]'),
('901e1011-4076-46b6-ae0c-06611a7868d1','端居','鄭谷','唐','唐诗','tang','','[]','葉葉下高梧，端居失所圖。',48,'全唐诗/poet.tang.37000.json','["葉葉下高梧，端居失所圖。", "亂離時輩少，風月夜吟孤。", "舊疾衰還有，窮愁醉暫無。", "秋光如水國，不語理霜鬚。"]'),
('c6527f09-3b56-4dc4-8b31-31dd6daba4d6','郊園','鄭谷','唐','唐诗','tang','','[]','相近復相尋，山僧與水禽。',48,'全唐诗/poet.tang.37000.json','["相近復相尋，山僧與水禽。", "煙蓑春釣靜，雪屋夜棊深。", "雅道誰開口，時風未醒心。", "溪光何以報，秪有醉和吟。"]'),
('bdaf8a32-59c0-4a7f-bc59-5ac03039d462','郊野','鄭谷','唐','唐诗','tang','','[]','蓼水菊籬邊，新晴有亂蟬。',48,'全唐诗/poet.tang.37000.json','["蓼水菊籬邊，新晴有亂蟬。", "秋光終寂寞，晚醉自留連。", "野溼禾中露，村閑社後天。", "題詩滿紅葉，何必浣花牋。"]'),
('64c961f5-8b17-490e-85ae-d5683209cdf9','旅寓洛南村舍','鄭谷','唐','唐诗','tang','','[]','村落清明近，鞦韆稚女誇。',48,'全唐诗/poet.tang.37000.json','["村落清明近，鞦韆稚女誇。", "春陰妨柳絮，月黑見棃花。", "白鳥窺魚網，青帘認酒家。", "幽棲雖自適，交友在京華。"]'),
('9edc670e-fba6-4ea4-a065-392c9c44d072','杏花','鄭谷','唐','唐诗','tang','','[]','不學梅欺雪，輕紅照碧池。',48,'全唐诗/poet.tang.37000.json','["不學梅欺雪，輕紅照碧池。", "小桃新謝後，雙燕却來時。", "香屬燈龍客，煙籠宿蝶枝。", "臨軒須貌取，風雨易離披。"]'),
('bcb3bfb5-5650-4e39-af14-db6e633330c0','水林檎花','鄭谷','唐','唐诗','tang','','[]','一露一朝新，簾櫳曉景分。',48,'全唐诗/poet.tang.37000.json','["一露一朝新，簾櫳曉景分。", "豔和蜂蝶動，香帶管弦聞。", "笑擬春無力，粧濃酒漸醺。", "直疑風起夜，飛去替行雲。"]'),
('76b50631-cdd2-48d5-b829-1d3e179049da','蓼花','鄭谷','唐','唐诗','tang','','[]','蔟蔟復悠悠，年年拂漫流。',48,'全唐诗/poet.tang.37000.json','["蔟蔟復悠悠，年年拂漫流。", "差池伴黃菊，冷澹過清秋。", "晚帶鳴蟲急，寒藏宿鷺愁。", "故溪歸不得，憑仗繫漁舟。"]'),
('af5e53b8-bbd0-445b-a602-02bdabf5d47d','江梅','鄭谷','唐','唐诗','tang','','[]','江梅且緩飛，前輩有歌詞。',48,'全唐诗/poet.tang.37000.json','["江梅且緩飛，前輩有歌詞。", "莫惜黃金縷，難忘白雪枝。", "吟看歸不得，醉嗅立如癡。", "和雨和煙折，含情寄所思。"]'),
('4025c151-c833-40b1-b6a9-0342bc6b816d','茘枝','鄭谷','唐','唐诗','tang','','[]','平昔誰相愛，驪山遇貴妃。',48,'全唐诗/poet.tang.37000.json','["平昔誰相愛，驪山遇貴妃。", "枉教生處遠，愁見摘來稀。", "晚奪紅霞色，晴欺瘴日威。", "南荒何所戀，爲爾即忘歸。"]'),
('7e12a588-8609-4627-a26d-db2e732a9927','駐蹕華下同年司封員外從翁許共遊西溪久違前契戲成寄贈','鄭谷','唐','唐诗','tang','','[]','北渚牽吟興，西溪爽共遊。',48,'全唐诗/poet.tang.37000.json','["北渚牽吟興，西溪爽共遊。", "指期乘禁馬，無暇狎沙鷗。", "縱目懷青島，澄心想碧流。", "明公非不愛，應待泛龍舟。"]'),
('639b6207-dfa0-4ec5-a043-32e1ae007fe1','谷自亂離之後在西蜀半紀之餘多寓止精舍與圓昉上人爲淨侶昉公於長松山舊齋嘗約他日訪會勞生多故遊宦數年曩契未諧忽聞謝世愴吟四韻以弔之','鄭谷','唐','唐诗','tang','','[]','每思聞淨話，雨夜對禪牀。',48,'全唐诗/poet.tang.37000.json','["每思聞淨話，雨夜對禪牀。", "未得重相見，秋燈照影堂。", "孤雲終負約，薄宦轉堪傷。", "夢繞長松塔，遙焚一炷香。"]'),
('f5dcd5e2-6b25-495b-8daf-8743c3782e75','投時相十韻','鄭谷','唐','唐诗','tang','','[]','何以保孤危，操修自不知。',120,'全唐诗/poet.tang.37000.json','["何以保孤危，操修自不知。", "衆中常杜口，夢裏亦吟詩。", "失計辭山早，非才得仕遲。", "薄冰安可履，暗室豈能欺。", "勤苦流螢信，吁嗟宿燕知。", "殘鐘殘漏曉，落葉落花時。", "故舊寒門少，文章外族衰。", "此生多轗軻，半世足漂離。", "省署隨清品，漁舟爽素期。", "戀恩休未遂，雙鬢漸成絲。"]'),
('f8e1cb8a-01e7-4fbf-b7d1-e3c3f4cc876b','喜秀上人相訪','鄭谷','唐','唐诗','tang','','[]','雪初開一徑，師忽扣雙扉。',48,'全唐诗/poet.tang.37000.json','["雪初開一徑，師忽扣雙扉。", "老大情相近，林泉約共歸。", "憂榮棲省署，孤僻謝朝衣。", "他夜松堂宿，論詩更入微。"]'),
('fb2629a7-6b44-45ea-8104-4f05fdfd9871','夕陽','鄭谷','唐','唐诗','tang','','[]','夕陽秋更好，斂斂蕙蘭中。',48,'全唐诗/poet.tang.37000.json','["夕陽秋更好，斂斂蕙蘭中。", "極浦明殘雨，長天急遠鴻。", "僧窗留半榻，漁舸透疎篷。", "莫恨清光盡，寒蟾即照空。"]'),
('7c15ef36-3a47-4d75-853d-dbdd53fcc25b','搖落','鄭谷','唐','唐诗','tang','','[]','夜來搖落悲，桑棗半空枝。',48,'全唐诗/poet.tang.37000.json','["夜來搖落悲，桑棗半空枝。", "故國無消息，流年有亂離。", "霜秦聞雁早，煙渭認帆遲。", "日暮寒鼙急，邊軍在雍岐。"]'),
('7c435ade-6a08-4d6e-9b1b-5f3d47225358','西蜀淨衆寺松溪八韻兼寄小筆崔處士','鄭谷','唐','唐诗','tang','','[]','松因溪得名，溪吹荅松聲。',96,'全唐诗/poet.tang.37000.json','["松因溪得名，溪吹荅松聲。", "繚繞能穿寺，幽奇不在城。", "寒煙齋後散，春雨夜中平。", "染岸蒼苔古，翹沙白鳥明。", "澄分僧影瘦，光徹客心清。", "帶梵侵雲響，和鐘擊石鳴。", "澹烹新茗爽，暖泛落花輕。", "此景吟難盡，憑君畫入京。"]'),
('b10c1e3d-fbbc-4f9a-864a-16e76002ae92','遷客','鄭谷','唐','唐诗','tang','','[]','離夜聞橫笛，可堪吹鷓鴣。',48,'全唐诗/poet.tang.37000.json','["離夜聞橫笛，可堪吹鷓鴣。", "雪冤知早晚，雨泣渡江湖。", "秋樹吹黃葉，臘煙垂綠蕪。", "虞飜歸有日，莫便哭窮途。"]'),
('42001782-6af8-43f1-bb05-30413abae062','蔡處士','鄭谷','唐','唐诗','tang','','[]','無著復無求，平生不解愁。',48,'全唐诗/poet.tang.37000.json','["無著復無求，平生不解愁。", "鬻蔬貧潔淨，中酒病風流。", "旨趣陶山相，詩篇沈隱侯。", "小齋江色裏，籬柱繫漁舟。"]'),
('f4b137e4-35f7-4f28-9e97-89d4cb79c778','予嘗有雪景一絕爲人所諷吟段贊善小筆精微忽爲圖畫以詩謝之','鄭谷','唐','唐诗','tang','','[]','贊善賢相後，家藏名畫多。',48,'全唐诗/poet.tang.37000.json','["贊善賢相後，家藏名畫多。", "留心於繪素，得事在煙波。", "屬興同吟詠，成功更琢磨。", "愛予風雪句，幽絕寫漁蓑。"]'),
('029035db-1d9b-47e1-98cb-d814c582100e','京兆府試殘月如新月','鄭谷','唐','唐诗','tang','','[]','榮落何相似，初終却一般。',72,'全唐诗/poet.tang.37000.json','["榮落何相似，初終却一般。", "猶疑和夕照，誰信墮朝寒。", "水木輝華別，詩家比象難。", "佳人應誤拜，棲鳥反求安。", "屈指期輪滿，何心謂影殘。", "庾樓清賞處，吟徹曙鐘看。"]'),
('e26d054c-8c60-463f-8f57-9a6ef196d548','咸通十四年府試木向榮','鄭谷','唐','唐诗','tang','','[]','園林青氣動，衆木散寒聲。',72,'全唐诗/poet.tang.37000.json','["園林青氣動，衆木散寒聲。", "敗葉牆陰在，滋條雪後榮。", "欣欣春令早，藹藹日華輕。", "庾嶺梅先覺，隋堤柳暗驚。", "山川應物候，臯壤起農情。", "秪待花開日，連棲出谷鶯。"]'),
('4a7390a1-9db7-4b50-8fb9-870a02eeaaf8','丞相孟夏祗薦南郊紀獻十韻','鄭谷','唐','唐诗','tang','','[]','節應清和候，郊宮事潔羞。',120,'全唐诗/poet.tang.37000.json','["節應清和候，郊宮事潔羞。", "至誠聞上帝，明德祀圓丘。", "雅用陶匏器，馨非黍稷流。", "就陽陳盛禮，匡國禱鴻休。", "漸曉蘭迎露，微涼麥弄秋。", "壽山橫紫閣，瑞靄抱皇州。", "外肅通班序，中嚴錫慶優。", "奏歌三酒備，表敬百神柔。", "池碧將還鳳，原清再問牛。", "萬方瞻輔翼，共賀贊皇猷。"]'),
('596fc3d9-7ede-4f15-9b92-843081cb8f82','敘事感恩上狄右丞','鄭谷','唐','唐诗','tang','','[]','昔歲曾投贄，關河在左馮。',168,'全唐诗/poet.tang.37000.json','["昔歲曾投贄，關河在左馮。", "庾公垂顧遇，王粲許從容。", "首薦叨殊禮，全家寓近封。", "白樓陪寫望，青眼感遭逢。", "顧念梁間燕，深憐澗底松。", "嵐光蓮嶽逼，酒味菊花濃。", "寇難旋移國，漂離幾聽蛩。", "半生悲逆旅，二紀間門墉。", "蜀雪隨僧蹋，荆煙逐雁衝。", "凋零歸兩鬢，舉止失前蹤。", "得事雖甘晚，陳詩未肯慵。", "邇來趨九仞，又伴賞三峯。", "棲託情何限，吹噓意數重。", "自茲儔侶內，無復歎龍鍾。"]'),
('bb6e25ab-fa24-45d4-aceb-873ef5ce1bc6','詠懷','鄭谷','唐','唐诗','tang','','[]','迂疎雖可欺，心路甚男兒。',120,'全唐诗/poet.tang.37000.json','["迂疎雖可欺，心路甚男兒。", "薄宦渾無味，平生粗有詩。", "澹交終不破，孤達晚相宜。", "直夜花前喚，朝寒雪裏追。", "竹聲輸我聽，茶格共僧知。", "景物還多感，情懷偶不卑。", "溪鶯喧午寢，山蕨止春飢。", "險事銷腸酒，清歡敵手棋。", "香鋤拋藥圃，煙艇憶莎陂。", "自許亨途在，儒綱復振時。"]'),
('30e65aa2-c466-461d-a8aa-b23ab172c0e1','乾符丙申歲奉試春漲曲江池','鄭谷','唐','唐诗','tang','','[]','王澤尚通津，恩波此日新。',72,'全唐诗/poet.tang.37000.json','["王澤尚通津，恩波此日新。", "深疑一夜雨，宛似五湖春。", "泛灩翹振鷺，澄清躍紫鱗。", "翠低孤嶼柳，香失半汀蘋。", "鳳輦尋佳境，龍舟命近臣。", "桂花如入手，願作從遊人。"]'),
('6ee0595b-7702-42a8-86e6-d5457feb6625','華山','鄭谷','唐','唐诗','tang','','[]','峭仞聳巍巍，晴嵐染近畿。',144,'全唐诗/poet.tang.37000.json','["峭仞聳巍巍，晴嵐染近畿。", "孤高不可狀，圖寫盡應非。", "絕頂神仙會，半空鸞鶴歸。", "雲臺分遠靄，樹谷隱斜暉。", "墜石連村響，狂雷發廟威。", "氣中寒渭闊，影外白樓微。", "雲對蓮花落，泉橫露掌飛。", "乳懸危磴滑，樵徹上方稀。", "澹泊生真趣，逍遙息世機。", "野花明澗路，春蘚澀松圍。", "遠洞時聞磬，羣僧晝掩扉。", "他年洗塵骨，香火願相依。"]'),
('872f4732-1448-44f6-9e66-853f19501dfb','入閣','鄭谷','唐','唐诗','tang','','[]','祕殿臨軒日，和鑾返正年。',120,'全唐诗/poet.tang.37000.json','["祕殿臨軒日，和鑾返正年。", "兩班文武盛，百辟羽儀全。", "霜漏清中禁，風旗拂曙天。", "門嚴新勘契，仗入乍承宣。", "玉几當紅旭，金鑪縱碧煙。", "對揚稱法吏，贊引出宮鈿。", "言動揮毫疾，雍容執簿專。", "壽山晴靉靆，顥氣暖連延。", "禮有鴛鸞集，恩無雨露偏。", "小臣叨備位，歌詠泰階前。"]'),
('0ccb5e28-07e5-4b46-9673-a9624c8abd7d','故少師從翁隱巖別墅亂後榛蕪感舊愴懷遂有追紀','鄭谷','唐','唐诗','tang','','[]','風騷爲主人，凡俗仰清塵。',240,'全唐诗/poet.tang.37000.json','["風騷爲主人，凡俗仰清塵。", "密行稱閨閫，明誠動搢紳。", "周旋居顯重，內外掌絲綸。", "妙主蓬壺籍，忠爲社稷臣。", "大儀牆仞峻，東轄紀綱新。", "聞善常開口，推公豈爲身。", "立朝鳴珮重，歸宅典衣貧。", "半醉看花晚，中餐煮菜春。", "晴臺隨鹿上，幽墅結僧鄰。", "理論知清越，生徒得李頻。", "藥香沾筆硯，竹色染衣巾。", "寄鶴眠雲叟，騎驢入室賓。", "近將姚監比，僻與段卿親。", "葉積池邊路，茶遲雪後薪。", "所難留著述，誰不秉陶鈞。", "喪亂時多變，追思事已陳。", "浮華重發作，雅正甚湮淪。", "宗從今何在，依棲素有因。", "七松無影響，雙淚益悲辛。", "猶喜于門秀，年來屈復伸。"]'),
('d69efa5c-b12b-49b8-8c2e-e894c6174482','送吏部曹郎中免官南歸','鄭谷','唐','唐诗','tang','','[]','高名向已求，古韻古無儔。',240,'全唐诗/poet.tang.37000.json','["高名向已求，古韻古無儔。", "風月拋蘭省，江山復桂州。", "賢人知止足，中歲便歸休。", "雲鶴深相待，公卿不易留。", "滿朝張祖席，半路上仙舟。", "篋重藏吳畫，茶新換越甌。", "郡迎紅燭宴，寺宿翠嵐樓。", "觸目成幽興，全家是勝遊。", "篷聲漁叟雨，葦色鷺鷥秋。", "久別郊園改，將歸里巷修。", "桑麻勝祿食，節序免鄉愁。", "陽朔花迎櫂，崇賢葉滿溝。", "席春歡促膝，簷日暖梳頭。", "道暢應爲蝶，時來必問牛。", "終須康庶品，未爽漱寒流。", "議在歸羣望，情難戀自由。", "小生誠淺拙，早歲便依投。", "夏課每垂獎，雪天常見憂。", "遠招陪宿直，首薦向公侯。", "攀送偏揮灑，龍鍾志未酬。"]'),
('2f0fd54c-8222-449b-a52b-0b1c2df9d7cf','迴鑾','鄭谷','唐','唐诗','tang','','["\u9ec4\u5c71"]','妖星沈雨露，和氣滿京關。',96,'全唐诗/poet.tang.37000.json','["妖星沈雨露，和氣滿京關。", "上將忠勳立，明君法駕還。", "順風調雅樂，夾道序羣班。", "香泛傳宣裏，塵清指顧間。", "樓臺新紫氣，雲物舊黃山。", "曉渭行朝肅，秋郊曠望閑。", "廟靈安國步，日角動天顏。", "浩浩昇平曲，流歌徹百蠻。"]'),
('ccdd14b6-eaf7-4474-aa8e-71ad4b68776f','峽中','鄭谷','唐','唐诗','tang','','[]','萬重煙靄裏，隱隱見夔州。',48,'全唐诗/poet.tang.37000.json','["萬重煙靄裏，隱隱見夔州。", "夜靜明月峽，春寒堆雪樓。", "獨吟誰會解，多病自淹留。", "往事如今日，聊同子美愁。"]'),
('1b59d47a-330e-49f5-a010-715480442350','蜀中寓止夏日自貽','鄭谷','唐','唐诗','tang','','[]','展轉攲孤枕，風幃信寂寥。',48,'全唐诗/poet.tang.37000.json','["展轉攲孤枕，風幃信寂寥。", "漲江垂螮蝀，驟雨鬧芭蕉。", "道阻歸期晚，年加記性銷。", "故人衰颯盡，相望在行朝。"]'),
('76f3fc48-4f68-4508-8df5-18bc0446820f','試筆偶書','鄭谷','唐','唐诗','tang','','[]','沙鳥與山麋，由來性不羈。',96,'全唐诗/poet.tang.37000.json','["沙鳥與山麋，由來性不羈。", "可憑唯在道，難解莫過詩。", "任笑孤吟僻，終嫌巧宦卑。", "秉慵恩地恕，冷澹好僧知。", "華省慙公器，滄江負釣師。", "露花春直夜，煙鼓早朝時。", "世路多艱梗，家風免墜遺。", "殷勤一蓑雨，秪得夢中披。"]'),
('0c392f97-7bd3-4852-bf19-dff9a57959e1','奔避','鄭谷','唐','唐诗','tang','','[]','奔避投人遠，漂離易感恩。',48,'全唐诗/poet.tang.37000.json','["奔避投人遠，漂離易感恩。", "愁髯霜颯颯，病眼淚昏昏。", "孤館秋聲樹，寒江落照村。", "更聞歸路絕，新寨截荆門。"]'),
('fb593305-d63e-4a25-8837-a9c5602c51c7','弔水部賈員外嵩','鄭谷','唐','唐诗','tang','','[]','八韻與五字，俱爲時所先。',24,'全唐诗/poet.tang.37000.json','["八韻與五字，俱爲時所先。", "幽魂應自慰，李白墓相連。"]'),
('43451543-6873-4b74-8ae6-443d6650bacb','貧女吟','鄭谷','唐','唐诗','tang','','[]','塵壓鴛鴦廢錦機，滿頭空插麗春枝。',32,'全唐诗/poet.tang.37000.json','["塵壓鴛鴦廢錦機，滿頭空插麗春枝。", "東鄰舞妓多金翠，笑翦燈花學畫眉。"]'),
('b73ec545-cb4d-43a9-b424-80c4346161b9','席上貽歌者','鄭谷','唐','唐诗','tang','','[]','花月樓臺近九衢，清歌一曲倒金壺。',32,'全唐诗/poet.tang.37000.json','["花月樓臺近九衢，清歌一曲倒金壺。", "座中亦有江南客，莫向春風唱鷓鴣。"]'),
('7f3badcd-8fe5-4b33-9579-8fbf0d8bd832','菊','鄭谷','唐','唐诗','tang','','["\u548f\u7269", "\u83ca\u82b1", "\u6292\u6000", "\u548f\u7269\u8bd7"]','王孫莫把比荆蒿，九日枝枝近鬢毛。',32,'全唐诗/poet.tang.37000.json','["王孫莫把比荆蒿，九日枝枝近鬢毛。", "露溼秋香滿池岸，由來不羨瓦松高。"]'),
('80f30bc0-5dff-4590-be24-2d05f01e2efa','下峽','鄭谷','唐','唐诗','tang','','[]','憶子啼猨繞樹哀，雨隨孤櫂過陽臺。',32,'全唐诗/poet.tang.37000.json','["憶子啼猨繞樹哀，雨隨孤櫂過陽臺。", "波頭未白人頭白，瞥見春風灩澦堆。"]'),
('654b40e4-60ad-40b9-93d9-0029f1d5c3d8','文昌寓直','鄭谷','唐','唐诗','tang','','[]','何遜空堦夜雨平，朝來交直雨新晴。',32,'全唐诗/poet.tang.37000.json','["何遜空堦夜雨平，朝來交直雨新晴。", "落花亂上花塼上，不忍和苔蹋紫英。"]'),
('88d442dd-3225-447a-831f-10a42c3d64e8','街西晚歸','鄭谷','唐','唐诗','tang','','[]','御溝春水繞閑坊，信馬歸來傍短牆。',32,'全唐诗/poet.tang.37000.json','["御溝春水繞閑坊，信馬歸來傍短牆。", "幽榭名園臨紫陌，晚風時帶牡丹香。"]'),
('b7bac783-8f0c-4fa5-a73f-d5121fc7069e','十日菊','鄭谷','唐','唐诗','tang','','[]','節去蜂愁蝶不知，曉庭還繞折殘枝。',32,'全唐诗/poet.tang.37000.json','["節去蜂愁蝶不知，曉庭還繞折殘枝。", "自緣今日人心別，未必秋香一夜衰。"]'),
('83232d74-f6ea-430d-b560-e0a8449d1fe7','鷺鷥','鄭谷','唐','唐诗','tang','','["\u5199\u9e1f", "\u548f\u7269", "\u548f\u7269\u8bd7", "\u9e1f"]','閑立春塘煙澹澹，靜眠寒葦雨颼颼。',32,'全唐诗/poet.tang.37000.json','["閑立春塘煙澹澹，靜眠寒葦雨颼颼。", "漁翁歸後汀沙晚，飛下灘頭更自由。"]'),
('a4818958-00ac-44d6-878a-14532d2326cd','柳','鄭谷','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61", "\u5199\u666f"]','半煙半雨江橋畔，暎杏映桃山路中。',32,'全唐诗/poet.tang.37000.json','["半煙半雨江橋畔，暎杏映桃山路中。", "會得離人無限意，千絲萬絮惹春風。"]'),
('ed8d15f4-2f71-4af4-82e9-a3a6113f2d6e','下第退居二首 一','鄭谷','唐','唐诗','tang','','[]','年來還未上丹梯，且著漁蓑謝故溪。',32,'全唐诗/poet.tang.37000.json','["年來還未上丹梯，且著漁蓑謝故溪。", "落盡梨花春又了，破籬殘雨晚鶯啼。"]'),
('cfd5e440-ae9b-4f25-8798-0db66d2ba9db','下第退居二首 二','鄭谷','唐','唐诗','tang','','[]','未嘗青杏出長安，豪士應疑怕牡丹。',32,'全唐诗/poet.tang.37000.json','["未嘗青杏出長安，豪士應疑怕牡丹。", "秪有退耕耕不得，茫然村落水吹殘。"]'),
('70337729-d66c-4603-a0f9-22f4cbe23cd3','江宿聞蘆管','鄭谷','唐','唐诗','tang','','[]','塞曲淒清楚水濱，聲聲吹出落梅春。',32,'全唐诗/poet.tang.37000.json','["塞曲淒清楚水濱，聲聲吹出落梅春。", "須知風月千檣下，亦有葫蘆河畔人。"]'),
('e5fb4a81-0ceb-473e-a230-d5513ed508d0','閑題','鄭谷','唐','唐诗','tang','','[]','舉世何人肯自知，須逢精鑑定妍媸。',32,'全唐诗/poet.tang.37000.json','["舉世何人肯自知，須逢精鑑定妍媸。", "若教嫫母臨明鏡，也道不勞紅粉施。"]'),
('2bc26393-fdcf-4663-b5a7-57a514734715','曲江春草','鄭谷','唐','唐诗','tang','','[]','花落江堤蔟暖煙，雨餘草色遠相連。',32,'全唐诗/poet.tang.37000.json','["花落江堤蔟暖煙，雨餘草色遠相連。", "香輪莫輾青青破，留與愁人一醉眠。"]'),
('aba7b7c1-6c1a-423a-ba7b-9b715724f4ce','雪中偶題','鄭谷','唐','唐诗','tang','','["\u5199\u96ea", "\u5199\u4eba", "\u96ea"]','亂飄僧舍茶煙溼，密灑歌樓酒力微。',32,'全唐诗/poet.tang.37000.json','["亂飄僧舍茶煙溼，密灑歌樓酒力微。", "江上晚來堪畫處，漁人披得一蓑歸。"]'),
('906dc08c-4a95-4db4-b759-10ec0ded5ef2','題慈恩寺默公院','鄭谷','唐','唐诗','tang','','[]','雖近曲江居古寺，舊山終憶九華峯。',32,'全唐诗/poet.tang.37000.json','["雖近曲江居古寺，舊山終憶九華峯。", "春來老病厭迎送，翦却牡丹栽野松。"]'),
('fbb8e3b3-f040-4a79-931f-882f7a17e06e','江上阻風','鄭谷','唐','唐诗','tang','','[]','水天春暗暮寒濃，船閉篷窗細雨中。',32,'全唐诗/poet.tang.37000.json','["水天春暗暮寒濃，船閉篷窗細雨中。", "閑道漁家酒初熟，夜來翻喜打頭風。"]'),
('1f2de7e3-e2c9-404f-91e1-8cc2cc96ccd1','淮上與友人別','鄭谷','唐','唐诗','tang','','["\u79bb\u522b", "\u67f3\u6811"]','揚子江頭楊柳春，楊花愁殺渡江人。',32,'全唐诗/poet.tang.37000.json','["揚子江頭楊柳春，楊花愁殺渡江人。", "數聲風笛離亭晚，君向瀟湘我向秦。"]'),
('2fe2eb19-2420-474b-9140-39ca371e2542','忍公小軒二首 一','鄭谷','唐','唐诗','tang','','[]','松溪水色綠於松，每到松溪到暮鐘。',32,'全唐诗/poet.tang.37000.json','["松溪水色綠於松，每到松溪到暮鐘。", "閑得心源秪如此，問禪何必向雙峯。"]'),
('f9d160c2-7419-454f-b3c5-de3edc200ab1','忍公小軒二首 二','鄭谷','唐','唐诗','tang','','[]','舊遊前事半埃塵，多向林中結淨因。',32,'全唐诗/poet.tang.37000.json','["舊遊前事半埃塵，多向林中結淨因。", "一念一爐香火裏，後身唯願似師身。"]'),
('d33ec077-5373-4bc0-a83e-70c76bc8cd6b','淮上漁者','鄭谷','唐','唐诗','tang','','["\u5782\u9493", "\u5199\u4eba", "\u751f\u6d3b", "\u5199\u4eba\u8bd7"]','白頭波上白頭翁，家逐船移浦浦風。',32,'全唐诗/poet.tang.37000.json','["白頭波上白頭翁，家逐船移浦浦風。", "一尺鱸魚新釣得，兒孫吹火荻花中。"]'),
('178daca9-21e7-4a30-83bc-3f331f43af7e','興州江館','鄭谷','唐','唐诗','tang','','[]','向蜀還秦計未成，寒蛩一夜繞牀鳴。',32,'全唐诗/poet.tang.37000.json','["向蜀還秦計未成，寒蛩一夜繞牀鳴。", "愁眠不穩孤燈盡，坐聽嘉陵江水聲。"]'),
('8be99aff-72d8-45a2-a6bd-deccd1d5e4bf','題無本上人小齋','鄭谷','唐','唐诗','tang','','[]','寒寺唯應我訪師，人稀境靜雪銷遲。',32,'全唐诗/poet.tang.37000.json','["寒寺唯應我訪師，人稀境靜雪銷遲。", "竹西落照侵窗好，堪惜歸時落照時。"]'),
('c6e702e7-8152-4e00-b61f-b3208ecfe3d9','七祖院小山','鄭谷','唐','唐诗','tang','','[]','小巧功成雨蘚斑，軒車日日扣松關。',32,'全唐诗/poet.tang.37000.json','["小巧功成雨蘚斑，軒車日日扣松關。", "峨嵋咫尺無人去，却向僧窗看假山。"]'),
('dbed17cc-1187-499c-8ebe-885e5352e708','定水寺行香','鄭谷','唐','唐诗','tang','','[]','聽經看畫繞虛廊，風拂金鑪待賜香。',32,'全唐诗/poet.tang.37000.json','["聽經看畫繞虛廊，風拂金鑪待賜香。", "丞相未來春雪密，暫偷閑臥老僧牀。"]'),
('618dc75f-4bc9-4f52-b1aa-ef8efdea4d8c','浯溪','鄭谷','唐','唐诗','tang','','[]','湛湛清江疊疊山，白雲白鳥在其間。',32,'全唐诗/poet.tang.37000.json','["湛湛清江疊疊山，白雲白鳥在其間。", "漁翁醉睡又醒睡，誰道皇天最惜閑。"]'),
('46a7691d-245f-4041-ac5d-90e93e70ec08','悶題','鄭谷','唐','唐诗','tang','','[]','莫厭九衢塵土間，秋晴滿眼是南山。',32,'全唐诗/poet.tang.37000.json','["莫厭九衢塵土間，秋晴滿眼是南山。", "僧家未必全無事，道著訪僧心且閑。"]'),
('6722aeca-5845-49a6-9d57-3c463edf71cf','重訪黃神谷策禪者','鄭谷','唐','唐诗','tang','','[]','初塵芸閣辭禪閣，却訪支郎是老郎。',32,'全唐诗/poet.tang.37000.json','["初塵芸閣辭禪閣，却訪支郎是老郎。", "我趣轉卑師趣靜，數峯秋雪一鑪香。"]'),
('a14f0606-1082-429c-9740-88ef29b9a4eb','別修覺寺無本上人','鄭谷','唐','唐诗','tang','','[]','松上閑雲石上苔，自嫌歸去夕陽催。',32,'全唐诗/poet.tang.37000.json','["松上閑雲石上苔，自嫌歸去夕陽催。", "山門握手無他語，秪約今冬看雪來。"]'),
('f3f5608f-bbb5-4e8d-b5d4-6d1854073449','贈日東鑒禪師','鄭谷','唐','唐诗','tang','','[]','故國無心渡海潮，老禪方丈倚中條。',32,'全唐诗/poet.tang.37000.json','["故國無心渡海潮，老禪方丈倚中條。", "夜深雨絕松堂靜，一點山螢照寂寥。"]'),
('3963c22c-9593-403c-a916-43c48fb3a28c','傳經院壁畫松','鄭谷','唐','唐诗','tang','','[]','危根瘦盡聳孤峯，珍重江僧好筆蹤。',32,'全唐诗/poet.tang.37000.json','["危根瘦盡聳孤峯，珍重江僧好筆蹤。", "得向遊人多處畫，却勝澗底作真松。"]'),
('30e21513-3d67-47cb-ac04-437f0eef98b7','高蟾先輩以詩筆相示抒成寄酬','鄭谷','唐','唐诗','tang','','[]','張生故國三千里，知者唯應杜紫微。',32,'全唐诗/poet.tang.37000.json','["張生故國三千里，知者唯應杜紫微。", "君有君恩秋後葉，可能更羨謝玄暉。"]'),
('680cc1ce-564a-4277-8995-8179a194bd68','爲人題','鄭谷','唐','唐诗','tang','','[]','淚溼孤鸞曉鏡昏，近來方解惜青春。',32,'全唐诗/poet.tang.37000.json','["淚溼孤鸞曉鏡昏，近來方解惜青春。", "杏花楊柳年年好，不忍迴看舊寫真。"]'),
('9231dc68-8a85-4b71-b4cd-446b4348c5df','越鳥','鄭谷','唐','唐诗','tang','','[]','背霜南雁不到處，倚櫂北人初聽時。',32,'全唐诗/poet.tang.37000.json','["背霜南雁不到處，倚櫂北人初聽時。", "梅雨滿江春草歇，一聲聲在荔枝枝。"]'),
('2a59242e-34dc-4bcf-a9af-eb6587c834c5','黃鶯','鄭谷','唐','唐诗','tang','','[]','春雲薄薄日輝輝，宮樹煙深隔水飛。',32,'全唐诗/poet.tang.37000.json','["春雲薄薄日輝輝，宮樹煙深隔水飛。", "應爲能歌繫仙籍，麻姑乞與女真衣。"]'),
('b2e6d179-bdbf-4954-ad84-f036c6983adb','失鷺鷥','鄭谷','唐','唐诗','tang','','[]','野格由來倦小池，驚飛却下碧江涯。',32,'全唐诗/poet.tang.37000.json','["野格由來倦小池，驚飛却下碧江涯。", "月昏風急何處宿，秋岸蕭蕭黃葦枝。"]'),
('e5c1af3d-96a8-4ebd-946c-ee5059f3e4b2','苔錢','鄭谷','唐','唐诗','tang','','[]','春紅秋紫繞池臺，箇箇圓如濟世財。',32,'全唐诗/poet.tang.37000.json','["春紅秋紫繞池臺，箇箇圓如濟世財。", "雨後無端滿窮巷，買花不得買愁來。"]'),
('ba17fece-e517-4da1-8ff2-f42bf2bacb18','蓮葉','鄭谷','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u8377\u53f6", "\u548f\u7269"]','移舟水濺差差綠，倚檻風搖柄柄香。',32,'全唐诗/poet.tang.37000.json','["移舟水濺差差綠，倚檻風搖柄柄香。", "多謝浣溪人不折，雨中留得蓋鴛鴦。"]'),
('a19b3ff0-acdd-4269-8be8-66dc3179e8a9','蜀中賞海棠','鄭谷','唐','唐诗','tang','','[]','濃澹芳春滿蜀鄉，半隨風雨斷鶯腸。',32,'全唐诗/poet.tang.37000.json','["濃澹芳春滿蜀鄉，半隨風雨斷鶯腸。", "浣花溪上堪惆悵，子美無心爲發揚。"]'),
('a7e32336-f9e0-4bea-8fc6-f9ff2e856a1c','投所知','鄭谷','唐','唐诗','tang','','[]','砌下芝蘭新滿徑，門前桃李舊垂陰。',32,'全唐诗/poet.tang.37000.json','["砌下芝蘭新滿徑，門前桃李舊垂陰。", "却應迴念江邊草，放出春煙一寸心。"]'),
('10eb92e3-e58f-48c5-8714-76e36a68264e','早入諫院二首 一','鄭谷','唐','唐诗','tang','','[]','玉階春冷未催班，暫拂塵衣就笏眠。',32,'全唐诗/poet.tang.37000.json','["玉階春冷未催班，暫拂塵衣就笏眠。", "孤立小心還自笑，夢魂潛繞御鑪煙。"]'),
('61b42c40-525e-4e4e-8948-67c6c71004d7','早入諫院二首 二','鄭谷','唐','唐诗','tang','','[]','紫雲重疊抱春城，廊下人稀唱漏聲。',32,'全唐诗/poet.tang.37000.json','["紫雲重疊抱春城，廊下人稀唱漏聲。", "偷得微吟斜倚柱，滿衣花露聽宮鶯。"]'),
('a59e6d11-1802-4b45-9683-9a1285a4a006','忝官諫垣明日轉對','鄭谷','唐','唐诗','tang','','[]','吾君英睿相君賢，其那寰區未晏然。',32,'全唐诗/poet.tang.37000.json','["吾君英睿相君賢，其那寰區未晏然。", "明日翠華春殿下，不知何語可聞天。"]'),
('89508bad-34bd-4808-b008-325bc6500bf7','再經南陽','鄭谷','唐','唐诗','tang','','[]','平蕪漠漠失樓臺，昔日遊人亂後來。',32,'全唐诗/poet.tang.37000.json','["平蕪漠漠失樓臺，昔日遊人亂後來。", "寥落牆匡春欲暮，燒殘宮樹有花開。"]'),
('f6d3eb9e-0e90-4d0a-8403-a61037d9df12','贈下第舉公','鄭谷','唐','唐诗','tang','','[]','見君失意我惆悵，記得當年落第情。',32,'全唐诗/poet.tang.37000.json','["見君失意我惆悵，記得當年落第情。", "出去無憀歸又悶，花南慢打講鐘聲。"]'),
('1bb3c6cc-f23e-4cfe-8fd6-eebb20dcfbdd','春陰','鄭谷','唐','唐诗','tang','','[]','推琴當酒度春陰，不解謀生秪解吟。',32,'全唐诗/poet.tang.37000.json','["推琴當酒度春陰，不解謀生秪解吟。", "舞蝶歌鶯莫相試，老郎心是老僧心。"]'),
('960a2d2e-08fe-4838-8dbe-26f949c7ada2','送張逸人','鄭谷','唐','唐诗','tang','','[]','人間疎散更無人，浪兀孤舟酒兀身。',32,'全唐诗/poet.tang.37000.json','["人間疎散更無人，浪兀孤舟酒兀身。", "蘆筍鱸魚拋不得，五陵珍重五湖春。"]'),
('997f0b53-31ef-4385-9c98-67f1b9188096','初還京師寓止府署偶題屋壁','鄭谷','唐','唐诗','tang','','[]','秋光不見舊亭臺，四顧荒涼瓦礫堆。',32,'全唐诗/poet.tang.37000.json','["秋光不見舊亭臺，四顧荒涼瓦礫堆。", "火力不能銷地力，亂前黃菊眼前開。"]'),
('dda4211f-aac5-4da6-9704-9ab6340f92ee','擢第後入蜀經羅村路見海棠盛開偶有題詠','鄭谷','唐','唐诗','tang','','[]','上國休誇紅杏𦫢，深溪自照綠苔磯。',64,'全唐诗/poet.tang.37000.json','["上國休誇紅杏𦫢，深溪自照綠苔磯。", "一枝低帶流鶯睡，數片狂和舞蝶飛。", "堪恨路長移不得，可無人與畫將歸。", "手中已有新春桂，多謝煙香更入衣。"]'),
('56c9ac1f-494c-4e82-b850-b386b2b5867a','次韻和禮部盧侍郎江上秋夕寓懷','鄭谷','唐','唐诗','tang','','[]','盧郎到處覺風生，蜀郡留連亞相情。',64,'全唐诗/poet.tang.37000.json','["盧郎到處覺風生，蜀郡留連亞相情。", "亂後江山悲庾信，夜來煙月屬袁宏。", "夢歸蘭省寒星動，吟向莎洲宿鷺驚。", "未脫白衣頭半白，叨陪屬和倍爲榮。"]'),
('9fb2999d-7cbb-4de7-a718-9b66379f14a0','宜春再訪芳公言公幽齋寫懷敘事因賦長言','鄭谷','唐','唐诗','tang','','[]','入門長恐先師在，香印紗燈似昔年。',64,'全唐诗/poet.tang.37000.json','["入門長恐先師在，香印紗燈似昔年。", "澗路縈迴齋處遠，松堂虛豁講聲圓。", "頃爲弟子曾同社，今忝星郎更契緣。", "顧渚一甌春有味，中林話舊亦潸然。"]'),
('b6db9053-985d-4c42-9495-503d4c02a0a7','讀李白集','鄭谷','唐','唐诗','tang','','[]','何事文星與酒星，一時鍾在李先生。',32,'全唐诗/poet.tang.37000.json','["何事文星與酒星，一時鍾在李先生。", "高吟大醉三千首，留著人間伴月明。"]'),
('2a5687d6-9094-4476-9f8e-ba5efb353d17','卷末偶題三首 一','鄭谷','唐','唐诗','tang','','[]','一卷疎蕪一百篇，名成未敢暫忘筌。',32,'全唐诗/poet.tang.37000.json','["一卷疎蕪一百篇，名成未敢暫忘筌。", "何如海日生殘夜，一句能令萬古傳。"]'),
('71380661-618b-42f9-881a-8c1225a52ffa','卷末偶題三首 二','鄭谷','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','七歲侍行湖外去，岳陽樓上敢題詩。',32,'全唐诗/poet.tang.37000.json','["七歲侍行湖外去，岳陽樓上敢題詩。", "如今寒晚無功業，何以勝任國士知。"]'),
('6f6ee8f2-ee30-435d-8ba1-3732b3f59a6c','卷末偶題三首 三','鄭谷','唐','唐诗','tang','','[]','一第由來是出身，垂名俱爲國風陳。',32,'全唐诗/poet.tang.37000.json','["一第由來是出身，垂名俱爲國風陳。", "此生若不知騷雅，孤宦如何作近臣。"]'),
('3cb4e2d0-4f57-48a0-9fca-27d276df44b8','讀前集二首 一','鄭谷','唐','唐诗','tang','','[]','殷璠裁鑒英靈集，頗覺同才得旨深。',32,'全唐诗/poet.tang.37000.json','["殷璠裁鑒英靈集，頗覺同才得旨深。", "何事後來高仲武，品題間氣未公心。"]'),
('dc972335-a8b6-4116-8eb7-2ffbfca6686c','讀前集二首 二','鄭谷','唐','唐诗','tang','','[]','風騷如線不勝悲，國步多艱即此時。',32,'全唐诗/poet.tang.37000.json','["風騷如線不勝悲，國步多艱即此時。", "愛日滿堦看古集，秪應陶集是吾師。"]'),
('f5f928d8-6043-4bf1-b75c-6a32ba98462c','渚宮亂後作','鄭谷','唐','唐诗','tang','','[]','鄉人來話亂離情，淚滴殘陽問紫荆。',64,'全唐诗/poet.tang.37000.json','["鄉人來話亂離情，淚滴殘陽問紫荆。", "白社已應無故老，清江依舊繞空城。", "高秋軍旅齊山樹，昔日漁家是野營。", "牢落故居灰燼後，黃花紫蔓上牆生。"]'),
('07f46c29-328d-4b1a-9460-1df01a53e2c2','鷓鴣','鄭谷','唐','唐诗','tang','','["\u601d\u4e61", "\u5199\u9e1f", "\u9e1f"]','暖戲煙蕪錦翼齊，品流應得近山雞。',64,'全唐诗/poet.tang.37000.json','["暖戲煙蕪錦翼齊，品流應得近山雞。", "雨昏青草湖邊過，花落黃陵廟裏啼。", "遊子乍聞征袖溼，佳人纔唱翠眉低。", "相呼相應湘江闊，苦竹叢深春日西。"]'),
('123f7d37-7157-47b9-baec-64361e5463ae','燕','鄭谷','唐','唐诗','tang','','[]','年去年來來去忙，春寒煙暝渡瀟湘。',64,'全唐诗/poet.tang.37000.json','["年去年來來去忙，春寒煙暝渡瀟湘。", "低飛綠岸和梅雨，亂入紅樓揀杏梁。", "閑几硯中窺水淺，落花徑裏得泥香。", "千言萬語無人會，又逐流鶯過短牆。"]'),
('ab113383-0a36-4e52-8247-e451d4529fdb','侯家鷓鴣','鄭谷','唐','唐诗','tang','','[]','江天梅雨溼江蘺，到處煙香是此時。',64,'全唐诗/poet.tang.37000.json','["江天梅雨溼江蘺，到處煙香是此時。", "苦竹嶺無歸去日，海棠花落舊棲枝。", "春宵思極蘭燈暗，曉月啼多錦幕垂。", "唯有佳人憶南國，殷勤爲爾唱愁詞。"]'),
('f42e02b4-b83d-4ef8-9fd6-6de2233e3e32','雁','鄭谷','唐','唐诗','tang','','[]','八月悲風九月霜，蓼花紅澹葦條黃。',64,'全唐诗/poet.tang.37000.json','["八月悲風九月霜，蓼花紅澹葦條黃。", "石頭城下波搖影，星子灣西雲間行。", "驚散漁家吹短笛，失羣征戍鎖殘陽。", "故鄉聞爾亦惆悵，何況扁舟非故鄉。"]'),
('4f47f668-da67-4794-97a7-acc4ef897a34','水','鄭谷','唐','唐诗','tang','','[]','竹院松廊分數派，不空清泚亦逶迤。',64,'全唐诗/poet.tang.37000.json','["竹院松廊分數派，不空清泚亦逶迤。", "落花相逐去何處，幽鷺獨來無限時。", "洗鉢老僧臨岸久，釣魚閑客捲綸遲。", "晚晴一片連莎綠，悔與滄浪有舊期。"]'),
('cddf83d8-c0f1-4836-8a02-dff4586528c2','海棠','鄭谷','唐','唐诗','tang','','[]','春風用意勻顏色，銷得攜觴與賦詩。',64,'全唐诗/poet.tang.37000.json','["春風用意勻顏色，銷得攜觴與賦詩。", "穠麗最宜新著雨，嬌饒全在欲開時。", "莫愁粉黛臨窗嬾，梁廣丹青點筆遲。", "朝醉暮吟看不足，羨他蝴蝶宿深枝。"]'),
('7a5278c3-4ed9-4b53-a816-143b0f84e1ce','竹','鄭谷','唐','唐诗','tang','','[]','宜煙宜雨又宜風，拂水藏村復間松。',64,'全唐诗/poet.tang.37000.json','["宜煙宜雨又宜風，拂水藏村復間松。", "移得蕭騷從遠寺，洗來疎淨見前峯。", "侵堦蘚拆春芽迸，繞徑莎微夏蔭濃。", "無賴杏花多意緒，數枝穿翠好相容。"]'),
('1d4a2546-2823-49c6-94e2-345a96eee0ce','荔枝樹','鄭谷','唐','唐诗','tang','','[]','二京曾見畫圖中，數本芳菲色不同。',64,'全唐诗/poet.tang.37000.json','["二京曾見畫圖中，數本芳菲色不同。", "孤櫂今來巴徼外，一枝煙雨思無窮。", "夜郎城近含香瘴，杜宇巢低起暝風。", "腸斷渝瀘霜霰薄，不教葉似灞陵紅。"]'),
('87d992e1-a7ac-451b-be3b-0cfb5be6ad21','錦二首 一','鄭谷','唐','唐诗','tang','','[]','布素豪家定不看，若無文彩入時難。',64,'全唐诗/poet.tang.37000.json','["布素豪家定不看，若無文彩入時難。", "紅迷天子帆邊日，紫奪星郎帳外蘭。", "春水濯來雲雁活，夜機挑處雨燈寒。", "舞衣轉轉求新樣，不問流離桑柘殘。"]'),
('f9c31378-aeef-4759-8c53-e8a6bb5d7490','錦二首 二','鄭谷','唐','唐诗','tang','','[]','文君手裏曙霞生，美號仍聞借蜀城。',64,'全唐诗/poet.tang.37000.json','["文君手裏曙霞生，美號仍聞借蜀城。", "奪得始知袍更貴，著歸方覺晝偏榮。", "宮花顏色開時麗，池雁毛衣浴後明。", "禮部郎官人所重，省中別占好窠名。"]'),
('52f78060-c251-4dcd-a434-1c0d0e31565f','蠟燭','鄭谷','唐','唐诗','tang','','[]','仙漏遲遲出建章，宮簾不動透清光。',64,'全唐诗/poet.tang.37000.json','["仙漏遲遲出建章，宮簾不動透清光。", "金闈露白新裁詔，畫閤春紅正試妝。", "淚滴杯盤何所恨，燼飄蘭麝暗和香。", "多情更有分明處，照得歌塵下燕梁。"]'),
('439e2810-3d95-4b55-8888-d1db2708d928','燈','鄭谷','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','雨向莎堦滴未休，冷光孤恨雨悠悠。',64,'全唐诗/poet.tang.37000.json','["雨向莎堦滴未休，冷光孤恨雨悠悠。", "船中聞雁洞庭宿，牀下有蛩長信秋。", "背照翠簾新灑別，不挑紅燼正含愁。", "蕭騷寒竹南窗靜，一局閑棋爲爾留。"]'),
('c675418e-2cf8-4fbd-8420-0964cff66cd5','宗人作尉唐昌官署幽勝而又博學精富得以言談將欲他之留書屋壁','鄭谷','唐','唐诗','tang','','[]','公堂瀟灑有林泉，秪隔苔牆是渚田。',64,'全唐诗/poet.tang.37000.json','["公堂瀟灑有林泉，秪隔苔牆是渚田。", "宗黨相親離亂世，春秋閑論戰爭年。", "遠江驚鷺來池口，絕頂歸雲過竹邊。", "風雨夜長同一宿，舊遊多共憶樊川。"]'),
('6db2ef27-f424-470f-b568-8620f21d0669','爲戶部李郎中與令季端公寓止渠州江寺偶作寄獻','鄭谷','唐','唐诗','tang','','[]','退居瀟灑寄禪關，高挂朝簪淨室間。',64,'全唐诗/poet.tang.37000.json','["退居瀟灑寄禪關，高挂朝簪淨室間。", "孤島雖留雙鶴歇，五雲爭放二龍閑。", "輕舟共泛花邊水，野屐同登竹外山。", "仙署金閨虛位久，夜清應夢近天顏。"]'),
('f4b03490-6f89-42ca-bb6c-ca8262dbc07f','重陽日訪元秀上人','鄭谷','唐','唐诗','tang','','[]','紅葉黃花秋景寬，醉吟朝夕在樊川。',64,'全唐诗/poet.tang.37000.json','["紅葉黃花秋景寬，醉吟朝夕在樊川。", "却嫌今日登山俗，且共高僧對榻眠。", "別畫長懷吳寺壁，宜茶偏賞霅溪泉。", "歸來童稚爭相笑，何事無人與酒船。"]'),
('1de88885-523f-4834-b590-1c17593b8127','闕下春日','鄭谷','唐','唐诗','tang','','[]','建章宮殿紫雲飄，春漏遲遲下絳霄。',64,'全唐诗/poet.tang.37000.json','["建章宮殿紫雲飄，春漏遲遲下絳霄。", "綺陌暖風嘶去馬，粉廊初日照趨朝。", "花經宿雨香難拾，鶯在豪家語更嬌。", "秦楚年年有離別，揚鞭揮袖灞陵橋。"]'),
('5ab94e50-b52c-456f-9ee9-7fce234c4813','贈劉神童','鄭谷','唐','唐诗','tang','','[]','習讀在前生，僧談足可明。',48,'全唐诗/poet.tang.37000.json','["習讀在前生，僧談足可明。", "還家雖解喜，登第未知榮。", "時果曾霑賜，春闈不挂情。", "燈前猶惡睡，寤語讀書聲。"]'),
('63d7e71b-77fc-40a0-b9e5-426da2d9649e','遠遊','鄭谷','唐','唐诗','tang','','[]','江湖猶足事，食宿戍鼙喧。',72,'全唐诗/poet.tang.37000.json','["江湖猶足事，食宿戍鼙喧。", "久客秋風起，孤舟夜浪翻。", "鄉音離楚水，廟貌入湘源。", "岸闊鳧鷖小，林垂橘柚繁。", "津官來有意，漁者笑無言。", "早晚酬僧約，中條有藥園。"]'),
('af1dd067-780d-4a7c-bfce-fbd8f96362fe','光化戊午年舉公見示省試春草碧色詩偶賦是題','鄭谷','唐','唐诗','tang','','[]','萇弘血染新，含露滿江濱。',72,'全唐诗/poet.tang.37000.json','["萇弘血染新，含露滿江濱。", "想得尋花徑，應迷拾翠人。", "窗紗迎擁砌，簪玉妬成茵。", "天借新晴色，雲饒落日春。", "嵐光垂處合，眉黛看時嚬。", "願與仙桃比，無令惹路塵。"]'),
('7aa521e8-e014-483d-bd5c-167b3ce9c9d4','江際','鄭谷','唐','唐诗','tang','','[]','杳杳漁舟破暝煙，疎疎蘆葦舊江天。',64,'全唐诗/poet.tang.37000.json','["杳杳漁舟破暝煙，疎疎蘆葦舊江天。", "那堪流落逢搖落，可得潸然是偶然。", "萬頃白波迷宿鷺，一林黃葉送殘蟬。", "兵車未息年華促，早晚閑吟向滻川。"]'),
('6e3867bd-fb40-4b66-8840-0ba69bf27c17','將之瀘郡旅次遂州遇裴晤員外謫居於此話舊淒涼因寄二首 一','鄭谷','唐','唐诗','tang','','[]','誰解登高問上玄，謫仙何事謫詩仙。',64,'全唐诗/poet.tang.37000.json','["誰解登高問上玄，謫仙何事謫詩仙。", "雲遮列宿離華省，樹蔭澄江入野船。", "黃鳥晚啼愁瘴雨，青梅早落中蠻煙。", "不知幾首南行曲，留與巴兒萬古傳。"]'),
('edeba321-b6dc-4573-b3d9-6e5d1ac95d0c','將之瀘郡旅次遂州遇裴晤員外謫居於此話舊淒涼因寄二首 二','鄭谷','唐','唐诗','tang','','[]','昔年共照松溪影，松折溪荒僧已無。',64,'全唐诗/poet.tang.37000.json','["昔年共照松溪影，松折溪荒僧已無。", "今日重思錦城事，雪銷花謝夢何殊。", "亂離未定身俱老，騷雅全休道甚孤。", "我拜師門更南去，荔枝春熟向渝瀘。"]'),
('e94f9669-79f3-4c18-bb79-1fa528b8828a','次韻和秀上人長安寺居言懷寄渚宮禪者','鄭谷','唐','唐诗','tang','','[]','舊齋松老別多年，香社人稀喪亂間。',64,'全唐诗/poet.tang.37000.json','["舊齋松老別多年，香社人稀喪亂間。", "出寺秪知趨內殿，閉門長似在深山。", "臥聽秦樹秋鐘斷，吟想荆江夕鳥還。", "唯恐興來飛錫去，老郎無路更追攀。"]'),
('efed73c3-0be3-4bcf-8f9e-8ad44b32a9c1','蜀中春日','鄭谷','唐','唐诗','tang','','[]','海棠風外獨霑巾，襟袖無端惹蜀塵。',64,'全唐诗/poet.tang.37000.json','["海棠風外獨霑巾，襟袖無端惹蜀塵。", "和暖又逢挑菜日，寂寥未是探花人。", "不嫌蟻酒衝愁肺，却憶漁蓑覆病身。", "何事晚來微雨後，錦江春學曲江春。"]'),
('5d41964b-3112-43d1-b55e-f7f353be959a','遊蜀','鄭谷','唐','唐诗','tang','','[]','所向明知是暗投，兩行清淚語前流。',64,'全唐诗/poet.tang.37000.json','["所向明知是暗投，兩行清淚語前流。", "雲橫新塞遮秦甸，花落空山入閬州。", "不忿黃鸝驚曉夢，唯應杜宇信春愁。", "梅黃麥綠無歸處，可得漂漂愛浪遊。"]'),
('92d4263e-d23c-4a98-83d5-895297c6df61','峽中嘗茶','鄭谷','唐','唐诗','tang','','[]','蔟蔟新英摘露光，小江園裏火煎嘗。',64,'全唐诗/poet.tang.37000.json','["蔟蔟新英摘露光，小江園裏火煎嘗。", "吳僧漫說鴉山好，蜀叟休誇鳥觜香。", "合座半甌輕泛綠，開緘數片淺含黃。", "鹿門病客不歸去，酒渴更知春味長。"]'),
('264760ef-3058-4f27-968d-abdada173df4','輦下冬暮詠懷','鄭谷','唐','唐诗','tang','','[]','永巷閑吟一徑蒿，輕肥大笑事風騷。',64,'全唐诗/poet.tang.37000.json','["永巷閑吟一徑蒿，輕肥大笑事風騷。", "煙含紫禁花期近，雪滿長安酒價高。", "失路漸驚前計錯，逢僧更念此生勞。", "十年春淚催衰颯，羞向清流照鬢毛。"]'),
('fc7aa481-e827-4831-8f4d-f4cd6b11fe83','石城','鄭谷','唐','唐诗','tang','','[]','石城昔爲莫愁鄉，莫愁魂散石城荒。',64,'全唐诗/poet.tang.37000.json','["石城昔爲莫愁鄉，莫愁魂散石城荒。", "江人依舊棹舴艋，江岸還飛雙鴛鴦。", "帆去帆來風浩渺，花開花落春悲涼。", "煙濃草遠望不盡，千古漢陽閑夕陽。"]'),
('f9ddbbbc-1826-446c-8477-c1031ff5e631','蜀中三首 一','鄭谷','唐','唐诗','tang','','[]','馬頭春向鹿頭關。',64,'全唐诗/poet.tang.37000.json','["馬頭春向鹿頭關。", "遠樹平蕪一望閑，雪下文君沾酒市。", "雲藏李白讀書山，江樓客恨黃梅後。", "村落人歌紫芋間，堤月橋燈好時景。", "漢庭無事不征蠻。"]'),
('af33b432-6122-443b-8700-8d9ca48214f0','蜀中三首 二','鄭谷','唐','唐诗','tang','','[]','夜無多雨曉生塵，草色嵐光日日新。',64,'全唐诗/poet.tang.37000.json','["夜無多雨曉生塵，草色嵐光日日新。", "蒙頂茶畦千點露，浣花牋紙一溪春。", "揚雄宅在唯喬木，杜甫臺荒絕舊鄰。", "却共海棠花有約，數年留滯不歸人。"]'),
('eb3c1c90-88d1-439b-9d8c-4ead0605da9c','蜀中三首 三','鄭谷','唐','唐诗','tang','','[]','渚遠江清碧簟紋，小桃花繞薛濤墳。',66,'全唐诗/poet.tang.37000.json','["渚遠江清碧簟紋，小桃花繞薛濤墳。", "朱橋直指金門路，粉堞高連玉壘雲。", "窗下[斵]琴翹鳳足，波中濯錦散鷗羣。", "子規夜夜啼巴樹，不並吳鄉楚國聞。"]'),
('84ea3b1f-21e8-495c-8d80-bd9cc7d93e27','少華甘露寺','鄭谷','唐','唐诗','tang','','[]','石門蘿徑與天鄰，雨檜風篁遠近聞。',64,'全唐诗/poet.tang.37000.json','["石門蘿徑與天鄰，雨檜風篁遠近聞。", "飲澗鹿喧雙派水，上樓僧蹋一梯雲。", "孤煙薄暮關城沒，遠色初晴渭曲分。", "長欲然香來此宿，北林猨鶴舊同羣。"]'),
('30ff5290-2c49-4c04-a577-787ceae67aa5','慈恩寺偶題','鄭谷','唐','唐诗','tang','','[]','往事悠悠添浩歎，勞生擾擾竟何能。',64,'全唐诗/poet.tang.37000.json','["往事悠悠添浩歎，勞生擾擾竟何能。", "故山歲晚不歸去，高塔晴來獨自登。", "林下聽經秋苑鹿，江邊掃葉夕陽僧。", "吟餘却起雙峰念，曾看菴西瀑布冰。"]'),
('d863837d-3b16-497f-82ec-b7361e7151f7','石門山泉','鄭谷','唐','唐诗','tang','','[]','一脈清泠何所之，縈莎漱蘚入僧池。',64,'全唐诗/poet.tang.37000.json','["一脈清泠何所之，縈莎漱蘚入僧池。", "雲邊野客窮來處，石上寒猨見落時。", "聚沫繞崖殘雪在，迸流穿樹墮花隨。", "煙春雨晚閑吟去，不復遠尋皇子陂。"]'),
('e7e9496b-e2da-4a0f-a36f-5c0009c2ad62','渭陽樓閑望','鄭谷','唐','唐诗','tang','','[]','千重二華見皇州，望盡凝嵐即此樓。',64,'全唐诗/poet.tang.37000.json','["千重二華見皇州，望盡凝嵐即此樓。", "細雨不藏秦樹色，夕陽空照渭河流。", "後車寧見前車覆，今日難忘昨日憂。", "擾擾塵中猶未已，可能疏傅獨能休。"]'),
('b36e8bbe-26ac-47c1-8c0b-6632fd504a76','送田光','鄭谷','唐','唐诗','tang','','[]','九陌低迷誰問我，五湖流浪可悲君。',64,'全唐诗/poet.tang.37000.json','["九陌低迷誰問我，五湖流浪可悲君。", "著書笑破蘇司業，賦詠思齊鄭廣文。", "理棹好攜三百首，阻風須飲幾千分。", "耒陽江口春山綠，慟哭應尋杜甫墳。"]'),
('9d10d11d-47d1-49f4-ad23-2233cbaddefc','送進士吳延保及第後南遊','鄭谷','唐','唐诗','tang','','[]','得意却思尋舊跡，新銜未切向蘭臺。',64,'全唐诗/poet.tang.37000.json','["得意却思尋舊跡，新銜未切向蘭臺。", "吟看秋草出關去，逢見故人隨計來。", "勝地昔年詩板在，清歌幾處郡筵開。", "江湖易有淹留興，莫待春風落庾梅。"]'),
('c0803f90-4c6f-4346-a48a-392ed2af79c6','送進士王駕下第歸蒲中','鄭谷','唐','唐诗','tang','','[]','失意離愁春不知，到家時是落花時。',64,'全唐诗/poet.tang.37000.json','["失意離愁春不知，到家時是落花時。", "孤單取事休言命，早晚逢人苦愛詩。", "度塞風沙歸路遠，傍河桑柘舊居移。", "應嗟我又巴江去，遊子悠悠聽子規。"]'),
('09e8f01e-e241-4137-9036-903552c1e4fb','作尉鄠郊送進士潘爲下第南歸','鄭谷','唐','唐诗','tang','','[]','歸去宜春春水深，麥秋梅雨過湘陰。',64,'全唐诗/poet.tang.37000.json','["歸去宜春春水深，麥秋梅雨過湘陰。", "鄉園幾度經狂寇，桑柘誰家有舊林。", "結綬位卑甘晚達，登龍心在且高吟。", "灞陵橋上楊花裏，酒滿芳樽淚滿襟。"]'),
('131ec489-2ed0-4bab-a069-f515e3e5d997','送進士韋序赴舉','鄭谷','唐','唐诗','tang','','[]','丹霞照上三清路，瑞錦裁成五色毫。',64,'全唐诗/poet.tang.37000.json','["丹霞照上三清路，瑞錦裁成五色毫。", "波浪不能隨世態，鸞凰應得入吾曹。", "秋山晚水吟情遠，雪竹風松醉格高。", "預想明年騰躍處，龍津春碧浸仙桃。"]'),
('d5bb1c33-e068-4bce-b8fd-c24fcd9a3f35','寄獻狄右丞','鄭谷','唐','唐诗','tang','','[]','逐勝偷閑向杜陵，愛僧不愛紫衣僧。',64,'全唐诗/poet.tang.37000.json','["逐勝偷閑向杜陵，愛僧不愛紫衣僧。", "身爲醉客思吟客，官自中丞拜右丞。", "殘月露垂朝闕蓋，落花風動宿齋燈。", "孤單小諫漁舟在，心戀清潭去未能。"]'),
('628006de-0888-47d0-b153-354c9c49d58d','轉正郎後寄獻集賢相公','鄭谷','唐','唐诗','tang','','[]','予名初在德門前，屈指年來三十年。',64,'全唐诗/poet.tang.37000.json','["予名初在德門前，屈指年來三十年。", "自賀孤危終際會，別將流涕感階緣。", "止陪鴛鴦居清秩，濫應星辰浼上玄。", "平昔苦心何所恨，受恩多是舊詩篇。"]'),
('08b45ab2-c4aa-43d4-bc9a-a022baef95bc','所知從事近藩偶有懷寄','鄭谷','唐','唐诗','tang','','[]','官舍種莎僧對榻，生涯如在舊山貧。',64,'全唐诗/poet.tang.37000.json','["官舍種莎僧對榻，生涯如在舊山貧。", "酒醒草檄聞殘漏，花落移廚送晚春。", "水墨畫松清睡眼，雲霞仙氅挂吟身。", "霜臺伏首思歸切，莫把漁竿逐逸人。"]'),
('cf58beb9-f98e-4cd0-a2fa-40817cac3d58','獻大京兆薛常侍能','鄭谷','唐','唐诗','tang','','[]','耻將官業競前途，自愛篇章古不如。',64,'全唐诗/poet.tang.37000.json','["耻將官業競前途，自愛篇章古不如。", "一炷香新開道院，數坊人聚避朝車。", "縱遊藉草花垂酒，閑臥臨窗燕拂書。", "唯有明公賞新句，秋風不敢憶鱸魚。"]'),
('40d6bdc5-5089-4ce8-8d17-c977eb5cf093','寄贈孫路處士','鄭谷','唐','唐诗','tang','','[]','平生詩譽更誰過，歸老東吳命若何。',64,'全唐诗/poet.tang.37000.json','["平生詩譽更誰過，歸老東吳命若何。", "知己凋零垂白髮，故園寥落近滄波。", "酒醒蘚砌花陰轉，病起漁舟鷺跡多。", "深入富春人不見，閑門空掩半庭莎。"]'),
('cc324730-dd47-499f-882d-9b62ea1b3f86','獻制誥楊舍人','鄭谷','唐','唐诗','tang','','[]','爲郡東吳秪飲冰，瑣闈頻降鳳書徵。',64,'全唐诗/poet.tang.37000.json','["爲郡東吳秪飲冰，瑣闈頻降鳳書徵。", "隨行已有朱衣吏，伴直多招紫閣僧。", "窗下調琴鳴遠水，簾前睡鶴背秋燈。", "葦陂竹塢情無限，閑話毘陵問杜陵。"]'),
('2eed5d45-fb2e-4d65-95d8-0139ddd1c565','次韻酬張補闕因寒食見寄之什','鄭谷','唐','唐诗','tang','','[]','柳近清明翠縷長，多情右衮不相忘。',64,'全唐诗/poet.tang.37000.json','["柳近清明翠縷長，多情右衮不相忘。", "開緘雖覩新篇麗，破鼻須聞冷酒香。", "時態嬾隨人上下，花心甘被蝶分張。", "朝稀且莫輕春賞，勝事由來在帝鄉。"]'),
('c48039e2-5566-4502-935a-b8e38c25ea0c','贈宗人前公安宰君','鄭谷','唐','唐诗','tang','','[]','喧卑從宦出喧卑，別畫能琴又解棊。',64,'全唐诗/poet.tang.37000.json','["喧卑從宦出喧卑，別畫能琴又解棊。", "海上春耕因亂廢，年來冬薦得官遲。", "風中夜犬驚槐巷，月下寒驢嚙槿籬。", "孤散恨無推唱路，耿懷吟得贈君詩。"]'),
('9b6bb491-5023-49f6-99fa-8e8a78fd1076','寄贈楊夔處士','鄭谷','唐','唐诗','tang','','[]','結茅秪約釣魚臺，濺水鸕鷀去又迴。',64,'全唐诗/poet.tang.37000.json','["結茅秪約釣魚臺，濺水鸕鷀去又迴。", "春臥甕邊聽酒熟，露吟庭際待花開。", "三江勝景遨遊徧，百氏羣書講貫來。", "國步未安風雅薄，可能高尚掞天才。"]'),
('681c4483-8436-49d1-a24d-ec1a75926d13','寄同年禮部趙郎中','鄭谷','唐','唐诗','tang','','[]','仙步徐徐整羽衣，小儀澄澹轉中儀。',64,'全唐诗/poet.tang.37000.json','["仙步徐徐整羽衣，小儀澄澹轉中儀。", "樺飄紅燼趨朝路，蘭縱清香宿省時。", "彩筆煙霞供不足，綸闈鸞鳳訝來遲。", "自憐孤宦誰相念，禱祝空吟一首詩。"]'),
('7294fe27-0cd0-4ce0-b949-409801d2a6de','春暮詠懷寄集賢韋起居衮','鄭谷','唐','唐诗','tang','','[]','寂寂風簾信自垂，楊花筍籜正離披。',64,'全唐诗/poet.tang.37000.json','["寂寂風簾信自垂，楊花筍籜正離披。", "長安一夜殘春雨，右省三年老拾遺。", "坐看羣賢爭得路，退量孤分且吟詩。", "五湖煙網非無意，未去難忘國士知。"]'),
('27ea5340-00b6-4ecf-b16b-6854d65f4c3c','多情','鄭谷','唐','唐诗','tang','','[]','賦分多情却自嗟，蕭衰未必爲年華。',64,'全唐诗/poet.tang.37000.json','["賦分多情却自嗟，蕭衰未必爲年華。", "睡輕可忍風敲竹，飲散那堪月在花。", "薄宦因循拋峴首，故人流落向天涯。", "鶯春鴈夜長如此，賴是幽居近酒家。"]'),
('8e5665d5-a59e-4c56-a548-3899149341c2','感懷投時相','鄭谷','唐','唐诗','tang','','[]','非才偶忝直文昌，兩鬢年深一鏡霜。',48,'全唐诗/poet.tang.37000.json','["非才偶忝直文昌，兩鬢年深一鏡霜。", "待漏敢辭稱小吏，立班猶未出中行。", "孤吟馬跡拋槐陌，遠夢漁竿擲葦鄉。"]'),
('ffad1c02-1268-4dd2-828a-113e1556d056','自貽','鄭谷','唐','唐诗','tang','','[]','飲筵博席與心違，野眺春吟更是誰。',64,'全唐诗/poet.tang.37000.json','["飲筵博席與心違，野眺春吟更是誰。", "琴有澗風聲轉澹，詩無僧字格還卑。", "恨拋水國荷蓑雨，貧過長安櫻筍時。", "頭角俊髦應指笑，權門蹤跡獨差池。"]'),
('3ade1117-285b-46e4-b1e5-54c50af3e4c3','自遣','鄭谷','唐','唐诗','tang','','[]','強健宦途何足謂，入微章句更難論。',64,'全唐诗/poet.tang.37000.json','["強健宦途何足謂，入微章句更難論。", "誰知野性真天性，不扣權門扣道門。", "窺硯晚鶯臨砌樹，迸堦春筍隔籬根。", "朝迴何處消長日，紫閣峰南有舊村。"]'),
('ca8d6f3d-e27c-40f1-a02d-9f659c2a9fdb','中年','鄭谷','唐','唐诗','tang','','["\u6625\u5929", "\u8ffd\u5fc6", "\u6101\u7eea"]','漠漠秦雲澹澹天，新年景象入中年。',64,'全唐诗/poet.tang.37000.json','["漠漠秦雲澹澹天，新年景象入中年。", "情多最恨花無語，愁破方知酒有權。", "苔色滿牆尋故第，雨聲一夜憶春田。", "衰遲自喜添詩學，更把前題改數聯。"]'),
('e4c5c926-d193-4e9b-8147-87648f65c39b','自適','鄭谷','唐','唐诗','tang','','[]','紫陌奔馳不暫停，送迎終日在郊坰。',64,'全唐诗/poet.tang.37000.json','["紫陌奔馳不暫停，送迎終日在郊坰。", "年來鬢畔未垂白，雨後江頭且蹋青。", "浮蟻滿盃難暫捨，貫珠一曲莫辭聽。", "春風秪有九十日，可合花前半日醒。"]'),
('0b7022b8-88b5-4803-9230-8b77755f383c','結綬鄠郊縻攝府署偶有自詠','鄭谷','唐','唐诗','tang','','[]','鶯離寒谷士逢春，釋褐來年暫種芸。',64,'全唐诗/poet.tang.37000.json','["鶯離寒谷士逢春，釋褐來年暫種芸。", "自笑老爲梅少府，可堪貧攝鮑參軍。", "酒醒往事多興念，吟苦鄰居必厭聞。", "推却簿書搔短髮，落花飛絮正紛紛。"]'),
('4d929b40-3fd2-4b48-adf8-51cbbade0ee2','漂泊','鄭谷','唐','唐诗','tang','','[]','槿墜蓬疎池館清，日光風緒澹無情。',48,'全唐诗/poet.tang.37000.json','["槿墜蓬疎池館清，日光風緒澹無情。", "鱸魚斫鱠輸張翰，橘樹呼奴羨李衡。", "十口漂零猶寄食，兩川消息未休兵。"]'),
('bde78274-74f8-4b40-954c-c51ccb0064d7','弔故禮部韋員外序','鄭谷','唐','唐诗','tang','','[]','臘雪初晴共舉盃，便期攜手上春臺。',64,'全唐诗/poet.tang.37000.json','["臘雪初晴共舉盃，便期攜手上春臺。", "高情唯怕酒不滿，長逝可悲花正開。", "曉奠鶯啼殘漏在，風幃燕覓舊巢來。", "杜陵芳草年年綠，醉魄吟魂無復迴。"]'),
('01b08ffe-23ce-4afb-bb96-34cb59e81b29','渼陂','鄭谷','唐','唐诗','tang','','[]','昔事東流共不迴，春深獨向渼陂來。',64,'全唐诗/poet.tang.37000.json','["昔事東流共不迴，春深獨向渼陂來。", "亂前別業依稀在，雨裏繁花寂寞開。", "却展漁絲無野艇，舊題詩句沒蒼苔。", "潸然四顧難消遣，秪有佯狂泥酒盃。"]'),
('673619df-a40a-4122-8c4a-013695fe64ac','代秋扇詞','鄭谷','唐','唐诗','tang','','[]','露入庭蕪恨已深，熱時天下是知音。',64,'全唐诗/poet.tang.37000.json','["露入庭蕪恨已深，熱時天下是知音。", "汗流浹背曾施力，氣爽中宵便負心。", "一片山溪從蠹損，數行文字任塵侵。", "綠槐陰合清和後，不會何顏又見尋。"]'),
('717ee290-1817-4910-a66a-edd46a2a4e21','宣義里舍冬暮自貽','鄭谷','唐','唐诗','tang','','[]','幽居不稱在長安，溝淺浮春岸雪殘。',64,'全唐诗/poet.tang.37000.json','["幽居不稱在長安，溝淺浮春岸雪殘。", "板屋漸移方帶野，水車新入夜添寒。", "名如有分終須立，道若離心豈易寬。", "滿眼塵埃馳騖去，獨尋煙竹翦漁竿。"]'),
('a51eaddf-5c71-41de-bc7c-52946c90db29','省中偶作','鄭谷','唐','唐诗','tang','','[]','三轉郎曹自勉旃，莎階吟步想前賢。',64,'全唐诗/poet.tang.37000.json','["三轉郎曹自勉旃，莎階吟步想前賢。", "未如何遜無佳句，若比馮唐是壯年。", "捧制名題黃紙尾，約僧心在白雪邊。", "乳毛松雪春來好，直夜清閑且學禪。"]'),
('094ed953-b328-40c7-83e3-b61c6dd7ce33','同志顧雲下第出京偶有寄勉','鄭谷','唐','唐诗','tang','','[]','鳳策聯華是國華，春來偶未上仙槎。',64,'全唐诗/poet.tang.37000.json','["鳳策聯華是國華，春來偶未上仙槎。", "鄉連南渡思菰米，淚滴東風避杏花。", "吟聒暮鶯歸廟院，睡消遲日寄僧家。", "一般情緒應相信，門靜莎深樹影斜。"]'),
('6bacfaeb-9c19-4bcd-bbe1-25d24aa6bcd2','敷溪高士','鄭谷','唐','唐诗','tang','','[]','敷溪南岸掩柴荆，挂却朝衣愛淨名。',64,'全唐诗/poet.tang.37000.json','["敷溪南岸掩柴荆，挂却朝衣愛淨名。", "閑得林園栽樹法，喜聞兒姪讀書聲。", "眠窗日暖添幽夢，步野風清散酒酲。", "謫去徵還何擾擾，片雲相伴看衰榮。"]'),
('1d69d600-8915-4873-a905-4cabecc9288a','九日偶懷寄左省張起居','鄭谷','唐','唐诗','tang','','[]','令節爭歡我獨閑，荒臺盡日向晴山。',64,'全唐诗/poet.tang.37000.json','["令節爭歡我獨閑，荒臺盡日向晴山。", "渾無酒泛金英菊，漫道官趨玉筍班。", "深愧青莎迎野步，不堪紅葉照衰顏。", "羨君官重多吟興，醉帶南陂落照還。"]'),
('3255a714-388e-4f98-bb9b-b4c66b846e83','春夕伴同年禮部趙員外省直','鄭谷','唐','唐诗','tang','','[]','錦帳名郎重錦科，清宵寓直縱吟哦。',64,'全唐诗/poet.tang.37000.json','["錦帳名郎重錦科，清宵寓直縱吟哦。", "冰含玉鏡春寒在，粉傅仙闈月色多。", "視草即應歸屬望，握蘭知道暫經過。", "流鶯百囀和殘漏，猶把芳樽藉露莎。"]'),
('7644b65d-804f-40e5-a536-1f8dfff0dec4','倦客','鄭谷','唐','唐诗','tang','','[]','十年五年岐路中，千里萬里西復東。',64,'全唐诗/poet.tang.37000.json','["十年五年岐路中，千里萬里西復東。", "匹馬愁衝晚村雪，孤舟悶阻春江風。", "達士由來知道在，昔賢何必哭途窮。", "閑烹蘆筍炊菰米，會向源鄉作醉翁。"]'),
('2b208766-121b-4d0c-bb48-0daac768898d','溫處士能畫鷺鶿以四韻換之','鄭谷','唐','唐诗','tang','','[]','昔年吟醉繞江蘺，愛把漁竿伴鷺鶿。',64,'全唐诗/poet.tang.37000.json','["昔年吟醉繞江蘺，愛把漁竿伴鷺鶿。", "聞說小毫能縱逸，敢憑輕素寫幽奇。", "涓涓浪濺殘菱蔓，戛戛風搜折葦枝。", "得向曉窗閑挂翫，雪蓑煙艇恨無遺。"]'),
('ca0353be-8b32-4bd4-a25e-6eb1cf8e35f1','駕部鄭郎中三十八丈尹貳東周榮加金紫谷以末派之外恩舊事深因賀送','鄭谷','唐','唐诗','tang','','[]','香浮玉陛曉辭天，袍拂蒲茸稱少年。',64,'全唐诗/poet.tang.37000.json','["香浮玉陛曉辭天，袍拂蒲茸稱少年。", "郎署轉曹雖久次，京河亞尹是優賢。", "縱遊雲水無公事，貴買琴書有俸錢。", "今日龍門看松雪，探春明日向平泉。"]'),
('f46944d0-b26d-469e-bc37-a5d9cb9502fa','欹枕','鄭谷','唐','唐诗','tang','','[]','攲枕高眠日午春，酒酣睡足最閑身。',32,'全唐诗/poet.tang.37000.json','["攲枕高眠日午春，酒酣睡足最閑身。", "明朝會得窮通理，未必輸他馬上人。"]'),
('48d6d6a3-6e1a-40f0-9d4d-81a13979592d','野步','鄭谷','唐','唐诗','tang','','[]','翠嵐迎步興何長，笑領漁翁入醉鄉。',32,'全唐诗/poet.tang.37000.json','["翠嵐迎步興何長，笑領漁翁入醉鄉。", "日暮渚田微雨後，鷺鶿閑暇稻花香。"]'),
('809561f1-eecd-4001-9b88-152b1760a005','偶書','鄭谷','唐','唐诗','tang','','[]','承時偷喜負明神，務實那能得庇身。',32,'全唐诗/poet.tang.37000.json','["承時偷喜負明神，務實那能得庇身。", "不會蒼蒼主何事，忍飢多是力耕人。"]'),
('7df17548-30fe-4b41-9051-f352c6ac4bac','靜吟','鄭谷','唐','唐诗','tang','','[]','騷雅荒涼我未安，月和餘雪夜吟寒。',32,'全唐诗/poet.tang.37000.json','["騷雅荒涼我未安，月和餘雪夜吟寒。", "相門相客應相笑，得句勝於得好官。"]'),
('1d3454a4-50ac-4670-a0bd-bd91b1eef250','和知己秋日傷懷','鄭谷','唐','唐诗','tang','','[]','流水歌聲共不迴，去年天氣舊亭臺。',32,'全唐诗/poet.tang.37000.json','["流水歌聲共不迴，去年天氣舊亭臺。", "梁塵寂寞燕歸去，黃蜀葵花一朵開。"]'),
('67b77890-1d04-41ae-9d54-39df1e65135c','谷比歲受同年丈人故川守李侍郎教諭衰晏龍鍾益用感歎遂以章句自貽','鄭谷','唐','唐诗','tang','','[]','多感京河李丈人，童蒙受教便書紳。',64,'全唐诗/poet.tang.37000.json','["多感京河李丈人，童蒙受教便書紳。", "文章至竟無功業，名宦由來致苦辛。", "皎日還應知守道，平生自信解甘貧。", "孤單所得皆逾分，歸種敷溪一畝春。"]'),
('f6c793f7-b0cc-4524-b353-7378ff91642a','郊墅','鄭谷','唐','唐诗','tang','','[]','韋曲樊川雨半晴，竹莊花院徧題名。',64,'全唐诗/poet.tang.37000.json','["韋曲樊川雨半晴，竹莊花院徧題名。", "畫成煙景垂楊色，滴破春愁壓酒聲。", "滿野紅塵誰得路，連天紫閣獨關情。", "渼陂水色澄於鏡，何必滄浪始濯纓。"]'),
('db741ec9-e7c7-4317-9394-f3c435e1b6c3','舟行','鄭谷','唐','唐诗','tang','','[]','九派迢迢九月殘，舟人相語且相寬。',64,'全唐诗/poet.tang.37000.json','["九派迢迢九月殘，舟人相語且相寬。", "村逢好處嫌風便，酒到醒來覺夜寒。", "蓼渚白波喧夏口，柿園紅葉憶長安。", "季鷹可是思鱸鱠，引退知時自古難。"]'),
('778eeb97-8550-4eb5-9c72-27b02af404af','奔問三峰寓止近墅','鄭谷','唐','唐诗','tang','','[]','半年奔走頗驚魂，來謁行宮淚眼昏。',64,'全唐诗/poet.tang.37000.json','["半年奔走頗驚魂，來謁行宮淚眼昏。", "鴛鷺入朝同待漏，牛羊送日獨歸村。", "灞陵散失詩千首，太華淒涼酒一樽。", "兵革未休無異術，不知何以受君恩。"]'),
('7ac9cf3b-9a52-4672-aa7e-90e0e06ba2e0','朝直','鄭谷','唐','唐诗','tang','','[]','朝直叨居省閣間，由來疎退校安閑。',64,'全唐诗/poet.tang.37000.json','["朝直叨居省閣間，由來疎退校安閑。", "落花夜靜宮中漏，微雨春寒廊下班。", "自扣玄門齊寵辱，從他榮路用機關。", "孤峰未得深歸去，名畫偏求水墨山。"]'),
('6bfe41d3-cd24-4777-8bd1-0de8ddc58062','巴江','鄭谷','唐','唐诗','tang','','[]','亂來奔走巴江濱，愁客多於江徼人。',64,'全唐诗/poet.tang.37000.json','["亂來奔走巴江濱，愁客多於江徼人。", "朝醉暮醉雪開霽，一枝兩枝梅探春。", "詔書罪己方哀痛，鄉縣徵兵尚苦辛。", "鬢禿又驚逢獻歲，眼前渾不見交親。"]'),
('0e5b8798-7216-4f25-bec1-ce7c61120135','故許昌薛尚書能嘗爲都官郎中後數歲故建州李員外頻自憲府內彈拜都官員外八座外郎皆一時騷雅宗師則都官之曹振盛於此予早年請益實受深知今忝此官復是正秩豈唯俯慰孤宦何以仰繼前賢榮惕在衷遂賦自賀','鄭谷','唐','唐诗','tang','','[]','都官雖未是名郎，踐歷曾聞薛許昌。',64,'全唐诗/poet.tang.37000.json','["都官雖未是名郎，踐歷曾聞薛許昌。", "復有李公陪雅躅，豈宜鄭子忝餘光。", "榮爲後進趨蘭署，喜拂前題在粉牆。", "他日節旄如可繼，不嫌曹冷在中行。"]'),
('31b7f556-c3c4-4891-a0b7-58f4d4aa8148','訪題表兄王藻渭上別業','鄭谷','唐','唐诗','tang','','[]','桑林搖落渭川西，蓼水瀰瀰接稻泥。',64,'全唐诗/poet.tang.37000.json','["桑林搖落渭川西，蓼水瀰瀰接稻泥。", "幽檻靜來魚唱遠，暝天寒極鴈行低。", "濁醪最稱看山醉，冷句偏宜選竹題。", "中表人稀離亂後，花時莫惜重相攜。"]'),
('505d2009-c562-48bf-a6a0-45ff2b42201f','題汝州從事廳','鄭谷','唐','唐诗','tang','','[]','詩人公署如山舍，秪向堦前便採薇。',64,'全唐诗/poet.tang.37000.json','["詩人公署如山舍，秪向堦前便採薇。", "驚燕拂簾閑睡覺，落花沾硯會餐歸。", "壁看舊記官多達，牓挂明文吏莫違。", "自說小池栽葦後，雨涼頻見鷺鶿飛。"]'),
('06311a0c-4b1c-45ae-b0f4-c2484fb125b5','谷初忝諫垣今憲長薛公方在西閣知獎隆異以四韻代述榮感','鄭谷','唐','唐诗','tang','','[]','舊詩常得在高吟，不奈公心愛苦心。',64,'全唐诗/poet.tang.37000.json','["舊詩常得在高吟，不奈公心愛苦心。", "道自瑣闈言下振，恩從仙殿對迴深。", "流年漸覺霜欺鬢，至藥能教土化金。", "自拂青萍知有地，齋誠旦夕望爲霖。"]'),
('a744970a-8ffd-43b3-bac3-c71eb1ccdc68','兵部盧郎中光濟借示詩集以四韻謝之','鄭谷','唐','唐诗','tang','','[]','七子風騷尋失主，五君歌誦久無聲。',64,'全唐诗/poet.tang.37000.json','["七子風騷尋失主，五君歌誦久無聲。", "調和雅樂歸時正，澄濾頹波到底清。", "才大始知寰宇窄，吟高何止鬼神驚。", "葉公好尚渾疎闊，忽見真龍幾喪明。"]'),
('0260857c-c155-42f6-9ecd-0f2d434dfc48','賀左省新除韋拾遺','鄭谷','唐','唐诗','tang','','[]','初昇諫署是真仙，浪透桃花恰五年。',64,'全唐诗/poet.tang.37000.json','["初昇諫署是真仙，浪透桃花恰五年。", "垂白郎官居座末，著緋人吏立階前。", "百寮班列趨丹陛，兩掖風清上碧天。", "從此追飛何處去，金鑾殿與玉堂連。"]'),
('f4a02fe2-d08b-4cb1-b270-06469c614b68','右省張補闕茂樞同在諫垣連居光德新春賦詠聊以寄懷','鄭谷','唐','唐诗','tang','','[]','小梅零落雪欺殘，浩蕩窮愁豈易寬。',64,'全唐诗/poet.tang.37000.json','["小梅零落雪欺殘，浩蕩窮愁豈易寬。", "唯有郎吟償晚景，且無濃醉厭春寒。", "高齋每喜追攀近，麗句先憂屬和難。", "十五年前諳苦節，知心不獨爲同官。"]'),
('875b55e9-4c3c-418f-ae70-aeca936b66c8','右省補闕張茂樞同在諫垣鄰居光德迭和篇什未嘗間時忽見貽謂谷將來履歷必在文昌當與何水部宋考功爲儔谷雖賦於風雅實用兢惶因抒酬寄','鄭谷','唐','唐诗','tang','','[]','何宋清名動粉闈，不才今日偶陳詩。',64,'全唐诗/poet.tang.37000.json','["何宋清名動粉闈，不才今日偶陳詩。", "考功豈敢聞題品，水部猶須繫挈維。", "積雪巷深酬唱夜，落花牆隔笑言時。", "紫垣名士推揚切，爲話心孤倍感知。"]'),
('1c7a83fc-7c03-47ec-a121-516a517e1c87','寄職方李員外','鄭谷','唐','唐诗','tang','','[]','曾袖篇章謁長卿，今來附鳳事何榮。',64,'全唐诗/poet.tang.37000.json','["曾袖篇章謁長卿，今來附鳳事何榮。", "星臨南省陪仙步，春滿東朝接珮聲。", "談笑不拘先後禮，歲寒仍契子孫情。", "龍墀仗下天街暖，共看圭峰並馬行。"]'),
('eb561d29-21f6-439c-b96b-b038f6032db7','寄題詩僧秀公','鄭谷','唐','唐诗','tang','','[]','靈一心傳清塞心，可公吟後楚公吟。',64,'全唐诗/poet.tang.37000.json','["靈一心傳清塞心，可公吟後楚公吟。", "近來雅道相親少，唯仰吾師所得深。", "好句未停無暇日，舊山歸老有東林。", "冷曹孤宦甘寥落，多謝攜筇數訪尋。"]'),
('bd39f148-47df-4092-932b-9b80fd55e18c','東蜀春晚','鄭谷','唐','唐诗','tang','','[]','如此浮生更別離，可堪長慟送春歸。',32,'全唐诗/poet.tang.37000.json','["如此浮生更別離，可堪長慟送春歸。", "潼江水上楊花雪，剛逐孤舟繚繞飛。"]'),
('49c24634-f9d1-4738-93b1-04c1f5778196','永日有懷','鄭谷','唐','唐诗','tang','','[]','能消永日是摴蒱，坑塹由來似宦途。',32,'全唐诗/poet.tang.37000.json','["能消永日是摴蒱，坑塹由來似宦途。", "兩擲未終楗橛內，座中何惜爲呼盧。"]'),
('5e111b37-e887-40bf-b195-ebd224afbfaa','槐花','鄭谷','唐','唐诗','tang','','[]','毿毿金蕊撲晴空，舉子魂驚落照中。',32,'全唐诗/poet.tang.37000.json','["毿毿金蕊撲晴空，舉子魂驚落照中。", "今日老郎猶有恨，昔年相虐十秋風。"]'),
('51b676bc-b146-4861-98eb-9cbc506de5d1','小桃','鄭谷','唐','唐诗','tang','','[]','和煙和雨遮敷水，映竹映村連灞橋。',32,'全唐诗/poet.tang.37000.json','["和煙和雨遮敷水，映竹映村連灞橋。", "撩亂春風耐寒令，到頭贏得杏花嬌。"]'),
('ac882845-f9b6-4266-8c7d-178a64e66f1f','長江縣經賈島墓','鄭谷','唐','唐诗','tang','','["\u957f\u6c5f"]','水繞荒墳縣路斜，耕人訝我久咨嗟。',32,'全唐诗/poet.tang.37000.json','["水繞荒墳縣路斜，耕人訝我久咨嗟。", "重來兼恐無尋處，落日風吹鼓子花。"]'),
('503d1ba1-3f17-4b3f-be42-d18b4431cbfc','嘉陵','鄭谷','唐','唐诗','tang','','[]','細雨溼萋萋，人稀江日西。',24,'全唐诗/poet.tang.37000.json','["細雨溼萋萋，人稀江日西。", "春愁腸已斷，不在子規啼。"]'),
('17586e90-99a9-4e55-9c15-f64a831cc87a','嘉陵','鄭谷','唐','唐诗','tang','','[]','細雨濕淒淒，人稀江日西。',24,'全唐诗/poet.tang.37000.json','["細雨濕淒淒，人稀江日西。", "春膓已愁斷，不待子規啼。"]'),
('fe65e78e-b989-4b45-a5ca-16c9208207f6','中秋','鄭谷','唐','唐诗','tang','','["\u6292\u60c5", "\u4e2d\u79cb", "\u5199\u666f"]','清香聞曉蓮，水國雨餘天。',48,'全唐诗/poet.tang.37000.json','["清香聞曉蓮，水國雨餘天。", "天氣正得所，客心剛悄然。", "亂兵何日息，故老幾人全。", "此際難消遣，從來未學禪。"]'),
('55137af3-1bc8-4f99-a392-23c320c80bbc','朝謁','鄭谷','唐','唐诗','tang','','[]','捧日整朝簪，千官一片心。',48,'全唐诗/poet.tang.37000.json','["捧日整朝簪，千官一片心。", "班趨黃道急，殿接紫宸深。", "威鳳迴香扆，新鶯囀上林。", "小松含瑞露，春翠易成陰。"]'),
('fad07e14-4073-4c1f-8fb3-9367e82c2017','錦浦','鄭谷','唐','唐诗','tang','','[]','流落夜淒淒，春寒錦浦西。',48,'全唐诗/poet.tang.37000.json','["流落夜淒淒，春寒錦浦西。", "不甘花逐水，可惜雪成泥。", "病眼嫌燈近，離腸賴酒迷。", "憑君囑鵯鵊，莫向五更啼。"]'),
('aaa0a081-1919-43b6-b8cd-178374477bf8','峨嵋山','鄭谷','唐','唐诗','tang','','["\u5ce8\u7709\u5c71"]','萬仞白雲端，經春雪未殘。',48,'全唐诗/poet.tang.37000.json','["萬仞白雲端，經春雪未殘。", "夏消江峽滿，晴照蜀樓寒。", "造境知僧熟，歸林認鶴難。", "會須朝闕去，秪有畫圖看。"]'),
('b2040218-eba4-4bd4-87bf-3f366fdb29a2','蜀江有弔','鄭谷','唐','唐诗','tang','','[]','孟子有良策，惜哉今已而。',48,'全唐诗/poet.tang.37000.json','["孟子有良策，惜哉今已而。", "徒將心體國，不識道消時。", "折檻未爲切，沈湘何足悲。", "蒼蒼無問處，煙雨徧江蘺。"]'),
('e112f756-5ffa-4e6e-ae76-f4fa8ebe863c','書村叟壁','鄭谷','唐','唐诗','tang','','[]','草肥朝牧牛，桑綠晚鳴鳩。',48,'全唐诗/poet.tang.37000.json','["草肥朝牧牛，桑綠晚鳴鳩。", "列岫簷前見，清泉碓下流。", "春蔬和雨割，社酒向花篘。", "引我南陂去，籬邊有小舟。"]'),
('b0b7c197-b3d2-4c1b-a02c-d891b1597bcc','題進士王駕郊居','鄭谷','唐','唐诗','tang','','[]','前山微有雨，永巷淨無塵。',48,'全唐诗/poet.tang.37000.json','["前山微有雨，永巷淨無塵。", "牛臥籬陰晚，鳩鳴村意春。", "時浮應寡合，道在不嫌貧。", "後徑臨陂水，菰蒲是切鄰。"]'),
('f8ac58d6-0251-4f6b-9ca9-67bed33dfc46','題莊嚴寺休公院','鄭谷','唐','唐诗','tang','','[]','秋深庭色好，紅葉間青松。',48,'全唐诗/poet.tang.37000.json','["秋深庭色好，紅葉間青松。", "病客殊無著，吾師甚見容。", "疎鐘和細溜，高塔等遙峰。", "未省求名侶，頻於此地逢。"]'),
('5349d0c0-6584-4c57-a7d2-1d3f2863cdfa','題興善寺','鄭谷','唐','唐诗','tang','','[]','寺在帝城陰，清虛勝二林。',48,'全唐诗/poet.tang.37000.json','["寺在帝城陰，清虛勝二林。", "蘚侵隋畫暗，茶助越甌深。", "巢鶴和鐘唳，詩僧倚錫吟。", "煙莎後池水，前跡杳難尋。"]'),
('cd9df830-cc32-4eeb-b0c5-3462d7ca011c','宿澄泉蘭若','鄭谷','唐','唐诗','tang','','[]','山半古招提，空林雪月迷。',48,'全唐诗/poet.tang.37000.json','["山半古招提，空林雪月迷。", "亂流分石上，斜漢在松西。", "雲集寒菴宿，猨先曉磬啼。", "此心如了了，即此是曹溪。"]'),
('2bd06730-a44c-440e-9a17-93af58548d9a','送舉子下第東歸','鄭谷','唐','唐诗','tang','','[]','夫子道何孤，青雲未得途。',48,'全唐诗/poet.tang.37000.json','["夫子道何孤，青雲未得途。", "詩書難捨魯，山水暫遊吳。", "野綠梅陰重，江春浪勢麤。", "秣陵兵役後，舊業半成蕪。"]'),
('e9d191b4-d134-4a8f-81f2-687f2a63b6a7','寄察院李侍御文炬','鄭谷','唐','唐诗','tang','','[]','古柏間疎篁，清陰在印牀。',48,'全唐诗/poet.tang.37000.json','["古柏間疎篁，清陰在印牀。", "宿郊虔點饌，秋寺靜監香。", "參集行多揖，風儀見即莊。", "佇聞橫擘去，帷集諫書囊。"]'),
('b663455e-25c3-400b-8a21-ca6bee9eddb7','偶懷寄臺院孫端公棨','鄭谷','唐','唐诗','tang','','[]','才拙道仍孤，無何捨釣徒。',48,'全唐诗/poet.tang.37000.json','["才拙道仍孤，無何捨釣徒。", "班雖沾玉筍，香不近金爐。", "雨露瞻雙闕，煙波隔五湖。", "唯君應見念，曾共伏青蒲。"]'),
('e0385c28-710b-4bdb-93d4-dcde5d609186','次韻和秀上人遊南五臺','鄭谷','唐','唐诗','tang','','[]','中峰曾到處，題記沒蒼苔。',48,'全唐诗/poet.tang.37000.json','["中峰曾到處，題記沒蒼苔。", "振錫傳深谷，翻經想舊臺。", "蒼松臨砌偃，驚鹿驀溪來。", "內殿評詩切，身迴心未迴。"]'),
('4a895719-7d0a-4aff-8c8b-1b1614402b17','乖慵','鄭谷','唐','唐诗','tang','','[]','乖慵居竹裏，涼冷臥池東。',72,'全唐诗/poet.tang.37000.json','["乖慵居竹裏，涼冷臥池東。", "一霎芰荷雨，幾迴簾幕風。", "遠僧來扣寂，小吏笑書空。", "衰鬢霜供白，愁顏酒借紅。", "扇輕搖鷺羽，屏古畫漁翁。", "自得無端趣，琴棊舫子中。"]'),
('80c5944f-1c88-47cc-b3c2-b49e7937e182','南宮寓直','鄭谷','唐','唐诗','tang','','[]','寓直事非輕，宦孤憂且榮。',96,'全唐诗/poet.tang.37000.json','["寓直事非輕，宦孤憂且榮。", "制承黃紙重，詞見紫垣清。", "曉霽庭松色，風和禁漏聲。", "僧攜新茗伴，吏掃落花迎。", "鎖印詩心動，垂簾睡思生。", "粉廊曾試處，石柱昔賢名。", "來誤宮窗燕，啼疑苑樹鶯。", "殘陽應更好，歸促恨嚴城。"]'),
('ca814cd2-078a-435b-8ecb-3f0b7c8a1457','恩門小諫雨中乞菊栽','鄭谷','唐','唐诗','tang','','[]','握蘭將滿歲，栽菊伴吟詩。',72,'全唐诗/poet.tang.37000.json','["握蘭將滿歲，栽菊伴吟詩。", "老去慵趨世，朝迴獨繞籬。", "遞香風細細，澆綠水瀰瀰。", "秪共山僧賞，何當國士移。", "孤根深有託，微雨正相宜。", "更待金英發，憑君插一枝。"]'),
('8cf90bf5-b8c0-4951-88ea-f7d70d7c59ff','荆渚八月十五夜值雨寄同年李嶼','鄭谷','唐','唐诗','tang','','[]','共待輝光夜，翻成黯澹秋。',72,'全唐诗/poet.tang.37000.json','["共待輝光夜，翻成黯澹秋。", "正宜清路望，潛起滴堦愁。", "棹倚袁宏渚，簾垂庾亮樓。", "桂無香實落，蘭有露花休。", "玉漏添蕭索，金尊阻獻酬。", "明年佳景在，相約向神州。"]'),
('e6317eb7-2efa-4c57-8f2e-4fd35796acb3','寄左省張起居','鄭谷','唐','唐诗','tang','','[]','含香復記言，清秩稱當年。',120,'全唐诗/poet.tang.37000.json','["含香復記言，清秩稱當年。", "點筆非常筆，朝天最近天。", "家聲三相後，公事一人前。", "詩句江郎伏，書蹤甯氏傳。", "風標欺鷺鶴，才力湧沙泉。", "居僻貧無慮，名高退更堅。", "漁舟思靜泛，僧榻寄閑眠。", "消息當彌入，絲綸的粲然。", "依棲常接跡，屬和舊盈編。", "開口人皆信，淒涼是謝氈。"]'),
('4c8d65a0-6a55-47ba-9edd-7cfb3d1b0f39','前寄左省張起居一百言尋蒙唱酬見譽過實却用舊韻重荅','鄭谷','唐','唐诗','tang','','[]','減瘦經多難，憂傷集晚年。',120,'全唐诗/poet.tang.37000.json','["減瘦經多難，憂傷集晚年。", "吟高風過樹，坐久夜涼天。", "旅退慙隨衆，孤飛怯向前。", "釣朋蓑叟在，藥術衲僧傳。", "鬢禿趨榮路，腸焦鄙盜泉。", "品徒誠有隔，推唱意何堅。", "寒地殊知感，秋燈耿不眠。", "從來甘默爾，自此倍怡然。", "蘭爲官須握，蒲因學更編。", "預愁搖落後，子美笑無氈。"]'),
('2d80a795-beea-4881-b268-de73dc423218','讀故許昌薛尚書詩集','鄭谷','唐','唐诗','tang','','["\u9ec4\u6cb3"]','篇篇高且真，真爲國風陳。',120,'全唐诗/poet.tang.37000.json','["篇篇高且真，真爲國風陳。", "澹薄雖師古，縱橫得意新。", "翦裁成幾篋，唱和是誰人。", "華岳題無敵，黃河句絕倫。", "吟殘荔枝雨，詠徹海棠春。", "李白欺前輩，陶潛仰後塵。", "難忘嵩室下，不負蜀江濱。", "屬思看山眼，冥搜倚樹身。", "楷模勞夢想，諷誦爽精神。", "落筆空追愴，曾蒙借斧斤。"]'),
('ece91815-1c5b-40c2-96b8-b7e264448e4e','送水部張郎中彥回宰洛陽','鄭谷','唐','唐诗','tang','','[]','何遜蘭休握，陶潛柳正垂。',48,'全唐诗/poet.tang.37000.json','["何遜蘭休握，陶潛柳正垂。", "官清真塞詔，事簡好吟詩。", "春漏懷丹闕，涼船泛碧伊。", "已虛西閣位，朝夕鳳書追。"]'),
('c5c3c0a2-a3c8-4512-9ee6-be78df9d48aa','贈咸陽王主簿','鄭谷','唐','唐诗','tang','','[]','可愛咸陽王主簿，窮經盡到昔賢心。',64,'全唐诗/poet.tang.37000.json','["可愛咸陽王主簿，窮經盡到昔賢心。", "登科未足酬多學，執卷猶聞惜寸陰。", "自與山妻舂斗粟，祗憑鄰叟典孤琴。", "我來賒酒相留宿，聽我披衣看雪吟。"]'),
('cfbcffe9-27fe-4233-a4cb-90c3d9544530','松','鄭谷','唐','唐诗','tang','','[]','下視垂楊拂路塵，雙峰石上覆苔文。',64,'全唐诗/poet.tang.37000.json','["下視垂楊拂路塵，雙峰石上覆苔文。", "濃霜滿逕無紅葉，晚日高枝有白雲。", "春砌花飄僧旋掃，寒溪子落鶴先聞。", "那堪寂寞悲風起，千樹深藏李白墳。"]'),
('7e16272d-d13b-41b8-bcbb-1cf54c6445c0','梅','鄭谷','唐','唐诗','tang','','[]','江國正寒春信穩，嶺頭枝上雪飄飄。',64,'全唐诗/poet.tang.37000.json','["江國正寒春信穩，嶺頭枝上雪飄飄。", "何言落處堪惆悵，直是開時也寂寥。", "素豔照尊桃莫比，孤香黏袖李須饒。", "離人南去腸應斷，片片隨鞭過楚橋。"]'),
('14335120-5191-430e-a341-1eb260d84874','鶴','鄭谷','唐','唐诗','tang','','[]','一自王喬放自由，俗人行處嬾回頭。',64,'全唐诗/poet.tang.37000.json','["一自王喬放自由，俗人行處嬾回頭。", "睡輕旋覺松花墮，舞罷閑聽澗水流。", "羽翼光明欺積雪，風神灑落占高秋。", "應嫌白鷺無仙骨，長伴漁翁宿葦洲。"]'),
('fe9f83c4-3e37-4c57-b65b-ad74f309f963','重陽夜旅懷','鄭谷','唐','唐诗','tang','','[]','強插黃花三兩枝，還圖一醉浸愁眉。',32,'全唐诗/poet.tang.37000.json','["強插黃花三兩枝，還圖一醉浸愁眉。", "半牀斜月醉醒後，惆悵多於未醉時。"]'),
('9cb3d360-e42a-49b4-b85d-f7e9624cdda7','壬戌西幸後','鄭谷','唐','唐诗','tang','','[]','武德門前顥氣新，雪融鴛瓦土膏春。',32,'全唐诗/poet.tang.37000.json','["武德門前顥氣新，雪融鴛瓦土膏春。", "夜來夢到宣麻處，草沒龍墀不見人。"]'),
('43d12331-1533-42d3-8c50-433e54aa54f5','多虞','鄭谷','唐','唐诗','tang','','[]','多虞難住人稀處，近耗渾無戰罷碁。',32,'全唐诗/poet.tang.37000.json','["多虞難住人稀處，近耗渾無戰罷碁。", "向闕歸山俱未得，且沽春酒且吟詩。"]'),
('b75fa89f-86b0-42ac-b765-a7b83f1cf895','短褐','鄭谷','唐','唐诗','tang','','[]','閑披短褐杖山藤，頭不是僧心是僧。',32,'全唐诗/poet.tang.37000.json','["閑披短褐杖山藤，頭不是僧心是僧。", "坐睡覺來清夜半，芭蕉影動道場燈。"]'),
('016c91df-4b23-41e7-81bd-81e7dbf70da0','曲江紅杏','鄭谷','唐','唐诗','tang','','[]','遮莫江頭柳色遮，日濃鶯睡一枝斜。',32,'全唐诗/poet.tang.37000.json','["遮莫江頭柳色遮，日濃鶯睡一枝斜。", "女郎折得殷勤看，道是春風及第花。"]'),
('541dc566-b159-4a4f-bc87-408027ea2f5c','折得梅','鄭谷','唐','唐诗','tang','','[]','寒步江村折得梅，孤香不肯待春催。',32,'全唐诗/poet.tang.37000.json','["寒步江村折得梅，孤香不肯待春催。", "滿枝盡是愁人淚，莫殢朝來露溼來。"]'),
('b8c9456f-4357-4a76-b5cc-7841dcb0ebc7','牡丹','鄭谷','唐','唐诗','tang','','[]','畫堂簾卷張清宴，含香帶霧情無限。',32,'全唐诗/poet.tang.37000.json','["畫堂簾卷張清宴，含香帶霧情無限。", "春風愛惜未放開，柘枝鼓振紅英綻。"]'),
('fe40775f-6060-4e63-bac4-c6db46197066','寂寞','鄭谷','唐','唐诗','tang','','[]','江郡人稀便是村，踏青天氣欲黃昏。',32,'全唐诗/poet.tang.37000.json','["江郡人稀便是村，踏青天氣欲黃昏。", "春愁不破還成醉，衣上淚痕和酒痕。"]'),
('a078e612-cdf9-4c1f-ba7b-71f1ab8b342b','亂後灞上','鄭谷','唐','唐诗','tang','','[]','柳絲牽水杏房紅，煙岸人稀草色中。',32,'全唐诗/poet.tang.37000.json','["柳絲牽水杏房紅，煙岸人稀草色中。", "日暮一行高鳥處，依稀合是望春宮。"]'),
('3b2c1b62-b426-4de1-9b18-8e741ebc0ed0','長門怨二首 一','鄭谷','唐','唐诗','tang','','[]','閑把羅衣泣鳳皇，先朝曾教舞霓裳。',32,'全唐诗/poet.tang.37000.json','["閑把羅衣泣鳳皇，先朝曾教舞霓裳。", "春來却羨庭花落，得逐晴風出禁牆。"]'),
('9624023a-f595-426b-aff8-349adc530d34','長門怨二首 二','鄭谷','唐','唐诗','tang','','[]','流水君恩共不回，杏花爭忍掃成堆。',32,'全唐诗/poet.tang.37000.json','["流水君恩共不回，杏花爭忍掃成堆。", "殘春未必多煙雨，淚滴閑堦長綠苔。"]'),
('64abde06-fe63-4b9b-bc16-d097c8f2455f','郊野戲題','鄭谷','唐','唐诗','tang','','[]','竹巷溪橋天氣涼，荷開稻熟村酒香。',32,'全唐诗/poet.tang.37000.json','["竹巷溪橋天氣涼，荷開稻熟村酒香。", "唯憂野叟相迴避，莫道儂家是漢郎。"]'),
('801d77ad-17c3-4d0d-9a22-54fabfe25366','宗人惠四藥','鄭谷','唐','唐诗','tang','','[]','宗人忽惠西山藥，四味清新香助茶。',32,'全唐诗/poet.tang.37000.json','["宗人忽惠西山藥，四味清新香助茶。", "爽得心神便騎鶴，何須燒得白朱砂。"]'),
('bd40b3cb-acc1-487b-8cca-2f813ac2aa85','題張衡廟','鄭谷','唐','唐诗','tang','','[]','遠俗只憑淫祀切，多年平子固悠悠。',32,'全唐诗/poet.tang.37000.json','["遠俗只憑淫祀切，多年平子固悠悠。", "江煙日午無簫鼓，直到如今詠四愁。"]'),
('81c3b7a4-1f41-4f2f-9a7d-717a16d58a71','山鳥','鄭谷','唐','唐诗','tang','','[]','驚飛失勢粉牆高，好箇聲音好羽毛。',32,'全唐诗/poet.tang.37000.json','["驚飛失勢粉牆高，好箇聲音好羽毛。", "小婢不須催柘彈，且從枝上喫櫻桃。"]'),
('8af1c349-24d3-44e9-a75d-9ab67d5833b8','黯然','鄭谷','唐','唐诗','tang','','[]','搢紳奔避復淪亡，消息春來到水鄉。',32,'全唐诗/poet.tang.37000.json','["搢紳奔避復淪亡，消息春來到水鄉。", "屈指故人能幾許，月明花好更悲涼。"]'),
('35462bad-977e-411e-917a-890cb32b285e','借薛尚書集','鄭谷','唐','唐诗','tang','','[]','江天冬暖似花時，上國音塵杳未知。',32,'全唐诗/poet.tang.37000.json','["江天冬暖似花時，上國音塵杳未知。", "正被蟲聲喧老耳，今君又借薛能詩。"]'),
('2f7ede4b-21fd-4503-b739-22529390b6c5','小北廰閑題','鄭谷','唐','唐诗','tang','','[]','冷曹孤宦本相宜，山在牆南落照時。',32,'全唐诗/poet.tang.37000.json','["冷曹孤宦本相宜，山在牆南落照時。", "洗竹澆莎足公事，一來贏寫一聯詩。"]'),
('8659fcdb-5c76-4529-a218-2099d20c0889','菊','鄭谷','唐','唐诗','tang','','[]','日日池邊載酒行，黃昏猶自遶黃英。',32,'全唐诗/poet.tang.37000.json','["日日池邊載酒行，黃昏猶自遶黃英。", "重陽過後頻來此，甚覺多情勝薄情。"]'),
('4626e2b1-8836-4df3-a67d-137231006e39','贈楊夔二首 一','鄭谷','唐','唐诗','tang','','[]','散賦宂書高且奇，百篇仍有百篇詩。',32,'全唐诗/poet.tang.37000.json','["散賦宂書高且奇，百篇仍有百篇詩。", "江湖休灑春風淚，十軸香於一桂枝。"]'),
('e1010dda-0424-49da-8d74-bac2dab4dcd6','贈楊夔二首 二','鄭谷','唐','唐诗','tang','','[]','時無韓柳道難窮，也覺天公不至公。',32,'全唐诗/poet.tang.37000.json','["時無韓柳道難窮，也覺天公不至公。", "看取年年金牓上，幾人才氣似揚雄。"]'),
('9298b80e-7bc7-4fed-8eae-c852558a6c13','中秋夜有懷','許彬','唐','唐诗','tang','','[]','趨馳早晚休，一歲又殘秋。',48,'全唐诗/poet.tang.37000.json','["趨馳早晚休，一歲又殘秋。", "若只如今日，何難致白頭。", "滄波歸處遠，旅舍向邊愁。", "賴見前賢說，窮通不自由。"]'),
('c0ca960f-3153-4838-af1e-b1242e1443c8','尋白石山人澗','許彬','唐','唐诗','tang','','[]','路窮川島上，果值古仙家。',48,'全唐诗/poet.tang.37000.json','["路窮川島上，果值古仙家。", "陰洞長鳴磬，石泉寒泛花。", "莓苔深峭壁，煙靄積層崖。", "難見囊中術，人間有歲華。"]'),
('0c5c73fa-2f2a-4cb9-9a69-4640eb4e8bb6','遊頭陀寺上方','許彬','唐','唐诗','tang','','[]','高步陟崔嵬，吟閑路惜迴。',48,'全唐诗/poet.tang.37000.json','["高步陟崔嵬，吟閑路惜迴。", "寺從何代有，僧是梵宮來。", "暮靄連沙積，餘霞逼檻開。", "更期招靜者，長嘯上方臺。"]'),
('a194fa86-5a90-4f00-a0e3-26137a24ae7b','歸山夜發湖中','許彬','唐','唐诗','tang','','[]','廣澤去無邊，夜程風信偏。',48,'全唐诗/poet.tang.37000.json','["廣澤去無邊，夜程風信偏。", "疎星遙抵浪，遠燒似迎船。", "響嶽猿相次，翻空雁接連。", "北歸家業就，深處更踰年。"]'),
('39ad35a2-f000-4211-a0bf-25997d09b6ee','同友人會裴明府縣樓','許彬','唐','唐诗','tang','','[]','開閣雨吹塵，陶家揖上賓。',48,'全唐诗/poet.tang.37000.json','["開閣雨吹塵，陶家揖上賓。", "湖山萬疊翠，汀樹一行春。", "景逼歸簷燕，歌喧已醉身。", "登臨興未足，喜有數年因。"]'),
('181300bf-da35-4eb7-a74e-b5ba6eb09038','荆山夜泊與親友遇','許彬','唐','唐诗','tang','','[]','山海兩分歧，停舟偶此期。',48,'全唐诗/poet.tang.37000.json','["山海兩分歧，停舟偶此期。", "別來何限意，相見卻無詞。", "坐永神疑夢，愁多鬢欲絲。", "趨名易遲晚，此去莫經時。"]'),
('e3a6c904-645c-49d1-aa43-9d881f00ddc2','北遊夜懷','許彬','唐','唐诗','tang','','[]','苦心終是否，捨此復無營。',48,'全唐诗/poet.tang.37000.json','["苦心終是否，捨此復無營。", "已致歸成晚，非緣去有程。", "館空吟向月，霜曙坐聞更。", "住久誰相問，馳羸又獨行。"]'),
('114dd663-8166-40ba-a687-3aa0952fca67','重經漢南','許彬','唐','唐诗','tang','','[]','分散多如此，人情豈自由。',48,'全唐诗/poet.tang.37000.json','["分散多如此，人情豈自由。", "重來看月夕，不似去年秋。", "息慮雖孤寢，論空未識愁。", "須同醉鄉者，萬事付江流。"]'),
('beecc85d-bf46-4567-bbfe-7745f1f0442d','湘江','許彬','唐','唐诗','tang','','[]','孤舟方此去，嘉景稱於聞。',48,'全唐诗/poet.tang.37000.json','["孤舟方此去，嘉景稱於聞。", "煙盡九峰雪，雨生諸派雲。", "沙寒鴻鵠聚，底極龜魚分。", "異日誰爲侶，逍遙耕釣羣。"]'),
('f790d31e-22c7-4bce-b8c2-84f07a937924','黔中書事','許彬','唐','唐诗','tang','','[]','巴蜀水南偏，山窮塞壘寬。',48,'全唐诗/poet.tang.37000.json','["巴蜀水南偏，山窮塞壘寬。", "歲時將近臘，草樹未知寒。", "獨狖啼朝雨，羣牛向暮灘。", "更聞蠻俗近，烽火不艱難。"]'),
('d5ea444d-0c09-4cc3-bd76-295115cd814f','經李翰林廬山屏風疊所居','許彬','唐','唐诗','tang','','["\u5e90\u5c71"]','放逐非多罪，江湖偶不廻。',48,'全唐诗/poet.tang.37000.json','["放逐非多罪，江湖偶不廻。", "深居應有謂，濟代豈無才。", "疊巘晴舒障，寒川暗動雷。", "誰能續高興，醉死一千杯。"]'),
('5bda7434-051c-41c3-a046-2833d66a8972','酬簡寂熊尊師以趙員外廬山草堂見借','許彬','唐','唐诗','tang','','["\u5e90\u5c71"]','豈易投居止，廬山得此峰。',48,'全唐诗/poet.tang.37000.json','["豈易投居止，廬山得此峰。", "主人曾已許，仙客偶相逢。", "顧己恩難答，窮經業未慵。", "還能勵僮僕，稍更補杉松。"]'),
('85e71e2a-d07e-4e5a-aeac-086914de180f','寄懷孫處士','許彬','唐','唐诗','tang','','[]','生平酌與吟，誰是見君心。',48,'全唐诗/poet.tang.37000.json','["生平酌與吟，誰是見君心。", "上國一歸去，滄波閑至今。", "鐘繁秋寺遠，岸闊晚濤深。", "疎放長如此，何人更得尋。"]'),
('96d21ddb-a1da-473c-ac94-00546aa9bf0e','漢南懷友人','許彬','唐','唐诗','tang','','[]','此身西復東，何計此相逢。',48,'全唐诗/poet.tang.37000.json','["此身西復東，何計此相逢。", "夢盡吳越水，恨深湘漢鐘。", "積雲開去路，曙雪疊前峰。", "誰即知非舊，憐君忽見容。"]'),
('fce73c81-7a08-43a1-9c6b-26425ff8bc73','送人下第歸江州','許彬','唐','唐诗','tang','','[]','名高不俟召，操賦獻君門。',48,'全唐诗/poet.tang.37000.json','["名高不俟召，操賦獻君門。", "偶屈應緣數，他人盡爲冤。", "新春城外路，舊隱水邊村。", "歸去無勞久，知音待更論。"]'),
('288c1772-ce41-4ffa-8b81-58be8042b9a1','送蘇處士歸西山','許彬','唐','唐诗','tang','','[]','南游何所爲，一篋又空歸。',48,'全唐诗/poet.tang.37000.json','["南游何所爲，一篋又空歸。", "守道安清世，無心換白衣。", "深溪猿共暮，絕頂客來稀。", "早晚還相見，論詩更及微。"]'),
('1291ca8f-6964-4cf5-a911-295e4f0791cc','送李處士歸山','許彬','唐','唐诗','tang','','[]','舊山來復去，不與世人論。',48,'全唐诗/poet.tang.37000.json','["舊山來復去，不與世人論。", "得道書留篋，忘機酒滿尊。", "溪軒松偃坐，石室水臨門。", "應有頻相訪，相看坐到昏。"]'),
('25886d8e-163c-45c1-8c3f-032f36cb36c9','送新羅客歸','許彬','唐','唐诗','tang','','[]','君家滄海外，一別見何因。',48,'全唐诗/poet.tang.37000.json','["君家滄海外，一別見何因。", "風土難知教，程途自致貧。", "浸天波色晚，橫吹鳥行春。", "明發千檣下，應爲更遠人。"]'),
('bff08281-f9c1-4c35-af53-faa1d085076f','府試萊城晴日望三山','許彬','唐','唐诗','tang','','[]','不易識蓬瀛，憑高望有程。',72,'全唐诗/poet.tang.37000.json','["不易識蓬瀛，憑高望有程。", "盤根出巨浸，遠色到孤城。", "隱隱排雲峻，層層就日明。", "淨收殘靄盡，浮動嫩嵐輕。", "縱目徒多暇，馳心累發誠。", "從容更何往，此路徹三清。"]'),
('444ef586-4750-4ce8-9a2a-b56c65bae04d','題故李賓客廬山草堂','許彬','唐','唐诗','tang','','["\u5e90\u5c71"]','難窮林下趣，坐使致君恩。',72,'全唐诗/poet.tang.37000.json','["難窮林下趣，坐使致君恩。", "術業行當代，封章動諫垣。", "已明邪佞迹，幾雪薜蘿冤。", "報主深知此，憂民詎可論。", "名將山共古，跡與道俱存。", "爲謝重來者，何人更及門。"]'),
('193e0151-be6a-4975-a7fa-a4bfc513bd84','秋夕送友人歸吳','崔塗','唐','唐诗','tang','','[]','離心醉豈懽，把酒彊相寬。',48,'全唐诗/poet.tang.37000.json','["離心醉豈懽，把酒彊相寬。", "世路須求達，還家亦未安。", "旅程愁算遠，江月坐吟殘。", "莫羨扁舟興，功成去不難。"]'),
('3e15e5e9-e94f-4881-9429-089ac51b58a5','長安逢江南僧','崔塗','唐','唐诗','tang','','[]','孤雲無定蹤，忽到又相逢。',48,'全唐诗/poet.tang.37000.json','["孤雲無定蹤，忽到又相逢。", "說盡天涯事，聽殘上國鐘。", "問人尋寺僻，乞食過街慵。", "憶到曾棲處，開門對數峰。"]'),
('8d7fc04a-f1db-42df-9da0-33e8db1c798c','晚次修路僧','崔塗','唐','唐诗','tang','','[]','平盡不平處，尚嫌功未深。',48,'全唐诗/poet.tang.37000.json','["平盡不平處，尚嫌功未深。", "應難將世路，便得稱師心。", "高鳥下殘照，白煙生遠林。", "更聞清磬發，聊喜緩塵襟。"]'),
('a0097f48-d494-4cc4-9c6f-b40719043b14','湖外送友人遊邊','崔塗','唐','唐诗','tang','','[]','我泛瀟湘浦，君行指塞雲。',48,'全唐诗/poet.tang.37000.json','["我泛瀟湘浦，君行指塞雲。", "兩鄉天外隔，一徑渡頭分。", "雨暗江花老，笳愁隴月曛。", "不堪來去鴈，迢遞思離羣。"]'),
('f238165d-617e-499f-abac-797b26b03e4c','讀段太尉碑','崔塗','唐','唐诗','tang','','[]','憤激計潛成，臨危豈顧生。',48,'全唐诗/poet.tang.37000.json','["憤激計潛成，臨危豈顧生。", "秪空持一笏，便欲碎長鯨。", "國已酬徽烈，家猶聳義聲。", "不知青史上，誰可計功名。"]'),
('79c2ecbb-4e08-4bfe-978e-ed90eaa11275','夕次洛陽道中','崔塗','唐','唐诗','tang','','[]','秋風吹故城，城下獨吟行。',48,'全唐诗/poet.tang.37000.json','["秋風吹故城，城下獨吟行。", "高樹鳥已息，古原人尚耕。", "流年川暗度，往事月空明。", "不復歎岐路，馬前塵夜生。"]'),
('ae49898a-82d5-457e-83cb-3a5555f8036b','讀方干詩因懷別業','崔塗','唐','唐诗','tang','','[]','把君詩一吟，萬里見君心。',48,'全唐诗/poet.tang.37000.json','["把君詩一吟，萬里見君心。", "華髮新知少，滄洲舊隱深。", "潮衝虛閣上，山入暮窗沈。", "憶宿高齋夜，庭枝識海禽。"]'),
('42fc0ab0-3f65-4651-9fc8-55e0546350a6','題嵩陽隱者','崔塗','唐','唐诗','tang','','[]','四十年高夢，生涯指一丘。',48,'全唐诗/poet.tang.37000.json','["四十年高夢，生涯指一丘。", "無人同久住，有鶴對冥修。", "草雜芝田出，泉和石髓流。", "更嫌庭樹老，疑是世間秋。"]'),
('ca0b4b5a-3d40-49f6-98ef-b19a32dd0fc1','友人問卜見招','崔塗','唐','唐诗','tang','','[]','何必問蓍龜，行藏自可期。',48,'全唐诗/poet.tang.37000.json','["何必問蓍龜，行藏自可期。", "但逢公道日，即是命通時。", "樂善知無厭，操心幸不欺。", "豈能花下淚，長似去年垂。"]'),
('83f6327e-f4ff-4113-8733-968532b2c994','江行晚望','崔塗','唐','唐诗','tang','','[]','木落曙江晴，寒郊極望平。',48,'全唐诗/poet.tang.37000.json','["木落曙江晴，寒郊極望平。", "孤舟三楚去，萬里獨吟行。", "鳥占橫查立，人當故里耕。", "十年來復去，不覺二毛生。"]'),
('2be1bfc4-d05a-4dd6-b41b-e596fb8d0912','巫山廟','崔塗','唐','唐诗','tang','','[]','雙黛儼如嚬，應傷故國春。',36,'全唐诗/poet.tang.37000.json','["雙黛儼如嚬，應傷故國春。", "江山非舊主，雲雨是前身。", "夢覺傳詞客，靈猶福楚人。"]'),
('3ce22705-20bd-4ae7-84de-a8d7dea5406c','秋夕與友人話別','崔塗','唐','唐诗','tang','','[]','懷君非一夕，此夕倍堪悲。',48,'全唐诗/poet.tang.37000.json','["懷君非一夕，此夕倍堪悲。", "華髮猶漂泊，滄洲又別離。", "冷禽棲不定，衰葉墮無時。", "況值干戈隔，相逢未可期。"]'),
('3da01ed4-0663-4719-8104-dc0fe29a54cc','與友人同懷江南別業','崔塗','唐','唐诗','tang','','[]','因君話故國，此夕倍依依。',48,'全唐诗/poet.tang.37000.json','["因君話故國，此夕倍依依。", "舊業臨秋水，何人在釣磯。", "浮名如縱得，滄海亦終歸。", "却是風塵裏，如何便息機。"]'),
('80cf692c-8cf8-4c1e-8792-e225f78e21ed','苦吟','崔塗','唐','唐诗','tang','','[]','朝吟復暮吟，只此望知音。',48,'全唐诗/poet.tang.37000.json','["朝吟復暮吟，只此望知音。", "舉世輕孤立，何人念苦心。", "他鄉無舊識，落日羨歸禽。", "況住寒江上，漁家似故林。"]'),
('31bd6f86-5b79-4db5-8193-f5c5d9a00500','春日郊居酬友人見貽','崔塗','唐','唐诗','tang','','[]','荒齋原上掩，不出動經旬。',48,'全唐诗/poet.tang.37000.json','["荒齋原上掩，不出動經旬。", "忽覺草木變，始知天地春。", "方期五字達，未厭一簞貧。", "麗句勞相勉，余非樂釣綸。"]'),
('145c084e-4428-458d-88ea-45e4a9802521','問卜','崔塗','唐','唐诗','tang','','[]','承家望一名，幾欲問君平。',48,'全唐诗/poet.tang.37000.json','["承家望一名，幾欲問君平。", "自小非無志，何年即有成。", "豈能長失路，爭忍學歸耕。", "不擬逢昭代，悠悠過此生。"]'),
('78da2e02-38d6-41d5-97f5-0f1d0baa3d64','蜀城春','崔塗','唐','唐诗','tang','','[]','天涯憔悴身，一望一霑巾。',48,'全唐诗/poet.tang.37000.json','["天涯憔悴身，一望一霑巾。", "在處有芳草，滿城無故人。", "懷才皆得路，失計自傷春。", "清鏡不能照，鬢毛愁更新。"]'),
('7b6a16bc-67e1-41ed-a1d6-7f60da051ac6','送道士于千齡游南岳','崔塗','唐','唐诗','tang','','[]','物外與誰期，人間又別離。',48,'全唐诗/poet.tang.37000.json','["物外與誰期，人間又別離。", "四方多事日，高岳獨游時。", "猨狖瀟湘樹，煙波屈宋祠。", "無因陪此去，空惜鬢將衰。"]'),
('3cf09977-fdd7-4887-9a53-5a2062731b58','入蜀赴舉秋夜與先生話別','崔塗','唐','唐诗','tang','','[]','欲愴峨嵋別，中宵寢不能。',48,'全唐诗/poet.tang.37000.json','["欲愴峨嵋別，中宵寢不能。", "聽殘池上雨，吟盡枕前燈。", "失計方期隱，修心未到僧。", "雲門一萬里，應笑又擔簦。"]'),
('31532d72-a2b9-4637-b029-ff108bb59228','春晚懷進士韋澹','崔塗','唐','唐诗','tang','','[]','故里花應盡，江樓夢尚殘。',48,'全唐诗/poet.tang.37000.json','["故里花應盡，江樓夢尚殘。", "半生吟欲過，一命達何難。", "特立珪無玷，相思草有蘭。", "二年春悵望，不似在長安。"]'),
('b85418a6-17d9-4b3b-b7f8-0cb1f907cadc','言懷','崔塗','唐','唐诗','tang','','[]','干時雖苦節，趨世且無機。',48,'全唐诗/poet.tang.37000.json','["干時雖苦節，趨世且無機。", "及覺知音少，翻疑所業非。", "青雲如不到，白首亦難歸。", "所以滄江上，年年別釣磯。"]'),
('0945906d-3734-4661-a9fb-f9e923217761','秋夜興上人別','崔塗','唐','唐诗','tang','','[]','常時豈不別，此別異常情。',48,'全唐诗/poet.tang.37000.json','["常時豈不別，此別異常情。", "南國初聞鴈，中原未息兵。", "暗蛩侵語歇，疎磬入吟清。", "曾聽無生說，辭師話此行。"]'),
('2dea0929-dffd-40cf-9361-1f0e00bf8212','感花','崔塗','唐','唐诗','tang','','[]','繡軛香韉夜不歸，少年爭惜最紅枝。',32,'全唐诗/poet.tang.37000.json','["繡軛香韉夜不歸，少年爭惜最紅枝。", "東風一陣黃昏雨，又到繁華夢覺時。"]'),
('33b0c3a7-e2c2-4427-aa53-e7e29e0d0b4b','秋宿天彭僧舍','崔塗','唐','唐诗','tang','','[]','身世兩相惜，秋雲每獨興。',48,'全唐诗/poet.tang.37000.json','["身世兩相惜，秋雲每獨興。", "難將塵界事，話向雪山僧。", "力善知誰許，歸耕又未能。", "此懷平不得，挑盡草堂燈。"]'),
('b03d28c4-7dd4-4f68-afa3-decc4bebb1ab','秋夜僧舍聞猨','崔塗','唐','唐诗','tang','','[]','哀猨聽未休，禪景夜方幽。',48,'全唐诗/poet.tang.37000.json','["哀猨聽未休，禪景夜方幽。", "暫得同僧靜，那能免客愁。", "影搖雲外樹，聲褭月中秋。", "曾向巴江宿，當時淚亦流。"]'),
('b408736b-d72f-4619-9fd4-f6b03755b432','過昭君故宅','崔塗','唐','唐诗','tang','','[]','以色靜胡塵，名還異衆嬪。',48,'全唐诗/poet.tang.37000.json','["以色靜胡塵，名還異衆嬪。", "免勞征戰力，無愧綺羅身。", "骨竟埋青塚，魂應怨畫人。", "不堪逢舊宅，寥落對江濱。"]'),
('e31dcea2-2d4a-47d5-83c0-18bc1a1819a3','過洛陽故城','崔塗','唐','唐诗','tang','','[]','三十世皇都，蕭條是霸圖。',48,'全唐诗/poet.tang.37000.json','["三十世皇都，蕭條是霸圖。", "片墻看破盡，遺跡漸應無。", "野徑通荒苑，高槐映遠衢。", "獨吟人不問，清冷自嗚嗚。"]'),
('df49da5f-bd2d-4b39-9221-0faecbba8b46','秋夕與友人同會','崔塗','唐','唐诗','tang','','[]','章句積微功，星霜二十空。',48,'全唐诗/poet.tang.37000.json','["章句積微功，星霜二十空。", "僻應如我少，吟喜得君同。", "月上僧歸後，詩成客夢中。", "更聞棲鶴警，清露滴青松。"]'),
('7ab68f44-fe46-4317-ad9f-5c8d3db9e900','春日登吳門','崔塗','唐','唐诗','tang','','[]','故國望不見，愁襟難暫開。',48,'全唐诗/poet.tang.37000.json','["故國望不見，愁襟難暫開。", "春潮映楊柳，細雨入樓臺。", "靜少人同到，晴逢鴈正來。", "長安遠於日，搔首獨徘徊。"]'),
('767a855e-d581-424e-a016-d99328580238','湘中秋懷遷客','崔塗','唐','唐诗','tang','','[]','蘭杜曉香薄，汀洲夕露繁。',48,'全唐诗/poet.tang.37000.json','["蘭杜曉香薄，汀洲夕露繁。", "併聞燕塞鴈，獨立楚人村。", "霧散孤城上，灘迴曙枕喧。", "不堪逢賈傅，還欲弔湘沅。"]'),
('35a30de2-c57e-4a79-a4c5-a51ada6709a9','南山旅舍與故人別','崔塗','唐','唐诗','tang','','[]','一日又將暮，一年看即殘。',48,'全唐诗/poet.tang.37000.json','["一日又將暮，一年看即殘。", "病知新事少，老別舊交難。", "山盡路猶險，雨餘春却寒。", "那堪試迴首，烽火是長安。"]'),
('29ec64a5-3de4-4137-b9a6-eaee895afc4a','東林愿禪師院','崔塗','唐','唐诗','tang','','[]','與世漸無緣，身心獨了然。',48,'全唐诗/poet.tang.37000.json','["與世漸無緣，身心獨了然。", "講銷林下日，臘長定中年。", "磬絕朝齋後，香焚古寺前。", "非因送小朗，不到虎谿邊。"]'),
('45aca44a-f366-4f97-b2ac-1a8581a57d39','孤鴈 一','崔塗','唐','唐诗','tang','','[]','湘浦離應晚，邊城去已孤。',36,'全唐诗/poet.tang.37000.json','["湘浦離應晚，邊城去已孤。", "如何萬里計，只在一枝蘆。", "迥起波搖楚，寒棲月映蒲。"]'),
('c836e52f-2346-4a3e-84bb-97514b17faf6','孤鴈 二','崔塗','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5b64\u72ec", "\u7f81\u65c5", "\u4e94\u8a00\u5f8b\u8bd7", "\u5199\u9e1f", "\u7ec4\u8bd7"]','幾行歸去盡，片影獨何之。',48,'全唐诗/poet.tang.37000.json','["幾行歸去盡，片影獨何之。", "暮雨相呼失，寒塘獨下遲。", "渚雲低暗度，關月冷遙隨。", "未必逢矰繳，孤飛自可疑。"]'),
('3a24cec6-4f9f-47a5-b17e-b702f4a11ef0','寄青城山颢禪師','崔塗','唐','唐诗','tang','','[]','懷師不可攀，師往杳冥間。',48,'全唐诗/poet.tang.37000.json','["懷師不可攀，師往杳冥間。", "林下誰聞法，塵中只見山。", "終年人不到，盡日鳥空還。", "曾聽無生說，應憐獨未還。"]'),
('af0eb744-9295-4b03-818b-06139b92af84','秋夕與王處士話別','崔塗','唐','唐诗','tang','','[]','微燈照寂寥，此夕正迢迢。',48,'全唐诗/poet.tang.37000.json','["微燈照寂寥，此夕正迢迢。", "丹桂得已晚，故山歸尚遙。", "蟲聲移暗壁，月色動寒條。", "此去如真隱，期君試一瓢。"]'),
('0681ee53-6856-453b-afb3-b2ed911f6745','秋日犍爲道中','崔塗','唐','唐诗','tang','','[]','久客厭岐路，出門吟且悲。',48,'全唐诗/poet.tang.37000.json','["久客厭岐路，出門吟且悲。", "平生未到處，落日獨行時。", "芳草不長綠，故人無重期。", "那堪更南渡，鄉國已天涯。"]'),
('f77cb8bc-263c-4042-9615-480715b043bd','送僧歸江東','崔塗','唐','唐诗','tang','','[]','坐徹秦城夏，行登越客船。',48,'全唐诗/poet.tang.37000.json','["坐徹秦城夏，行登越客船。", "去留那有著，語默不離禪。", "葉擁臨關路，霞明近海天。", "更尋同社侶，應得虎溪邊。"]'),
('46d6fdcf-4db3-4604-b278-d1dc60bf5ce7','喜友人及第','崔塗','唐','唐诗','tang','','[]','孤吟望至公，已老半生中。',48,'全唐诗/poet.tang.37000.json','["孤吟望至公，已老半生中。", "不有同人達，兼疑此道窮。", "只應才自薄，豈是命難通。", "尚激摶溟勢，期君借北風。"]'),
('11f62453-4078-4079-9ee7-da3ef4f4f4e7','上巳日永崇里言懷','崔塗','唐','唐诗','tang','','[]','未敢分明賞物華，十年如見夢中花。',32,'全唐诗/poet.tang.37000.json','["未敢分明賞物華，十年如見夢中花。", "遊人過盡衡門掩，獨自凭欄到日斜。"]'),
('8eb8619f-07ea-49ad-9056-11036bbec986','送僧歸天竺','崔塗','唐','唐诗','tang','','[]','忽憶曾棲處，千峰近沃州。',48,'全唐诗/poet.tang.37000.json','["忽憶曾棲處，千峰近沃州。", "別來秦樹老，歸去海門秋。", "汲帶寒汀月，禪隣賈客舟。", "遙思清興愜，不厭石林幽。"]'),
('470cf59b-dd76-4114-92b7-ff49731d254b','牛渚夜泊','崔塗','唐','唐诗','tang','','[]','煙老石磯平，袁郎夜泛情。',48,'全唐诗/poet.tang.37000.json','["煙老石磯平，袁郎夜泛情。", "數吟人不遇，千古月空明。", "人事年年別，春潮日日生。", "無因逢謝尚，風物自淒清。"]'),
('bcfa77d3-26e9-4c9c-b765-02d69f7361c2','送友人歸江南','崔塗','唐','唐诗','tang','','[]','渚田芳草徧，共憶故山春。',48,'全唐诗/poet.tang.37000.json','["渚田芳草徧，共憶故山春。", "獨往滄洲暮，相看白髮新。", "定過林下寺，應見社中人。", "只恐東歸後，難將鷗鳥親。"]'),
('8c6a2c65-035c-43b3-b608-760c5895f454','過陶徵君隱居','崔塗','唐','唐诗','tang','','[]','陶令昔居此，弄琴遺世榮。',48,'全唐诗/poet.tang.37000.json','["陶令昔居此，弄琴遺世榮。", "田園三畝綠，軒冕一銖輕。", "衰柳自無主，白雲猶可耕。", "不隨陵谷變，應只有高名。"]'),
('5a30c61d-6603-4070-8ad9-04adefcb36bf','江上旅泊','崔塗','唐','唐诗','tang','','[]','汀洲一夜泊，久客半連檣。',48,'全唐诗/poet.tang.37000.json','["汀洲一夜泊，久客半連檣。", "盡說逢秋色，多同憶故鄉。", "孤岡生晚燒，獨樹隱回塘。", "欲問東歸路，遙知隔渺茫。"]'),
('5da97811-c1b4-4496-b6a5-76170faef6a5','灞上','崔塗','唐','唐诗','tang','','[]','長安名利路，役役古田今。',48,'全唐诗/poet.tang.37000.json','["長安名利路，役役古田今。", "征騎少閑日，綠楊無舊陰。", "水侵秦甸闊，草接漢陵深。", "紫閣曾過處，依稀白鳥沈。"]'),
('c9f6cf04-a977-4107-a788-5bafdd7ae14c','寄舅','崔塗','唐','唐诗','tang','','[]','中朝軒冕內，久絕甯家親。',48,'全唐诗/poet.tang.37000.json','["中朝軒冕內，久絕甯家親。", "白社同孤立，青雲獨併伸。", "致君期折檻，舉職在埋輪。", "須信堯庭草，猶能指佞人。"]'),
('efd6b1e5-17e3-49cf-86e7-eb1a769ce36d','贈休糧僧','崔塗','唐','唐诗','tang','','[]','聞鐘獨不齋，何事更關懷。',48,'全唐诗/poet.tang.37000.json','["聞鐘獨不齋，何事更關懷。", "靜少人過院，閑從草上堦。", "生臺無鳥下，石路有雲埋。", "爲憶禪中舊，時猶夢百崖。"]'),
('4babb757-d44d-42a7-b88a-5f98393d7e24','題絕島山寺','崔塗','唐','唐诗','tang','','[]','絕島跨危欄，登臨到此難。',48,'全唐诗/poet.tang.37000.json','["絕島跨危欄，登臨到此難。", "夕陽高鳥過，疎雨一鐘殘。", "駭浪搖空闊，靈山厭渺漫。", "那堪更回首，鄉樹隔雲端。"]'),
('7520d77e-233f-4367-9f09-a89aaa4af120','讀侯道華真人傳','崔塗','唐','唐诗','tang','','[]','漢皇輕萬乘，方士說三丹。',48,'全唐诗/poet.tang.37000.json','["漢皇輕萬乘，方士說三丹。", "不得修心要，翻知出世難。", "茂陵春竟綠，金掌曙空寒。", "何似先生去，翩翩逐彩鸞。"]'),
('41dcc72d-ee84-4019-b9d1-2dfcb374ae93','殘花','崔塗','唐','唐诗','tang','','[]','遲遲傍曉陰，昨夜色猶深。',48,'全唐诗/poet.tang.37000.json','["遲遲傍曉陰，昨夜色猶深。", "畢竟終須落，堪悲古與今。", "明年何處見，盡日此時心。", "蜂蝶無情極，殘香更不尋。"]'),
('9b2ac2ea-673b-4d01-8b0e-e6e182bf4f1b','題興善寺隋松院與人期不至','崔塗','唐','唐诗','tang','','[]','青青伊澗松，移植在蓮宮。',48,'全唐诗/poet.tang.37000.json','["青青伊澗松，移植在蓮宮。", "蘚色前朝雨，秋聲半夜風。", "長閑應未得，暫賞亦難同。", "不及禪棲者，相看老此中。"]'),
('5e828f50-094c-432c-a727-872eb3143101','樵者','崔塗','唐','唐诗','tang','','[]','行山行採薇，閑翦蕙爲衣。',48,'全唐诗/poet.tang.37000.json','["行山行採薇，閑翦蕙爲衣。", "避世嫌山淺，逢人說姓稀。", "有時還獨醉，何處掩衡扉？", "莫看棋終局，溪風晚待歸。"]'),
('a33164e3-64ca-43f3-a829-0675cb105595','南澗耕叟','崔塗','唐','唐诗','tang','','[]','年年南澗濱，力盡志猶存。',48,'全唐诗/poet.tang.37000.json','["年年南澗濱，力盡志猶存。", "雨雪朝耕苦，桑麻歲計貧。", "戰添丁壯役，老憶太平春。", "見說經荒後，田園半屬人。"]'),
('e7163d43-99ac-4fee-80c3-f597f1dcc6b7','春日閑居憶江南舊業','崔塗','唐','唐诗','tang','','[]','杜門朝復夕，豈是解謀身。',48,'全唐诗/poet.tang.37000.json','["杜門朝復夕，豈是解謀身。", "夢不離泉石，林唯稱隱淪。", "漸諳浮世事，轉憶故山春。", "南國水風暖，又應生白蘋。"]'),
('e101eab1-9e6c-46c8-a3d9-27531f821293','屈原廟','崔塗','唐','唐诗','tang','','[]','讒勝禍難防，沈冤信可傷。',48,'全唐诗/poet.tang.37000.json','["讒勝禍難防，沈冤信可傷。", "本圖安楚國，不是怨懷王。", "廟古碑無字，洲晴蕙有香。", "獨醒人尚笑，誰與奠椒漿。"]'),
('10023796-9225-452d-8f14-65a3b0ccf9ad','宿廬山絕頂山舍','崔塗','唐','唐诗','tang','','["\u5e90\u5c71"]','一磴出林端，千峰次第看。',48,'全唐诗/poet.tang.37000.json','["一磴出林端，千峰次第看。", "長閑如未遂，暫到亦應難。", "谷樹雲埋老，僧窗瀑影寒。", "自嫌心不達，向此夢長安。"]'),
('d4eb8b07-e96e-478a-b9b4-f9402669bab7','王逸人隱居','崔塗','唐','唐诗','tang','','[]','一徑入千岑，幽人許重尋。',48,'全唐诗/poet.tang.37000.json','["一徑入千岑，幽人許重尋。", "不逢秦世亂，未覺武陵深。", "石轉生寒色，雲歸帶夕陰。", "却愁危坐久，看盡暝棲禽。"]'),
('ba010328-07c5-4e6c-83ff-2f5bafdafd3d','申州道中','崔塗','唐','唐诗','tang','','[]','風緊日淒淒，鄉心向此迷。',48,'全唐诗/poet.tang.37000.json','["風緊日淒淒，鄉心向此迷。", "水分平楚闊，山接故關低。", "客路緣烽火，人家厭鼓鼙。", "那堪獨馳馬，江樹穆陵西。"]'),
('a6b82932-a1c5-4791-a8f1-0743f1c1d61b','江上懷翠微寺空上人','崔塗','唐','唐诗','tang','','[]','旅泛本無定，相逢那可期。',48,'全唐诗/poet.tang.37000.json','["旅泛本無定，相逢那可期。", "空懷白閣夜，未荅碧雲詩。", "暮雨潮生早，春寒鴈到遲。", "所思今不見，鄉國正天涯。"]'),
('dd7bdd89-da7b-496b-b8c0-8a4119702a5d','秋宿鶴林寺','崔塗','唐','唐诗','tang','','[]','步步入林中，山窮意未窮。',48,'全唐诗/poet.tang.37000.json','["步步入林中，山窮意未窮。", "偏逢僧話久，轉與鶴棲同。", "燭焰風銷盡，蘭條露濕空。", "又須從此別，江上正秋鴻。"]'),
('682909dd-b9df-4666-b88a-1824fd167ffc','遠望','崔塗','唐','唐诗','tang','','[]','長爲鄉思侵，望極即霑襟。',48,'全唐诗/poet.tang.37000.json','["長爲鄉思侵，望極即霑襟。", "不是前山色，能傷愁客心。", "平蕪連海盡，獨樹隱雲深。", "況復斜陽外，分明有去禽。"]'),
('d693b670-78ab-4b3f-b851-0875e9229739','秋晚書懷','崔塗','唐','唐诗','tang','','[]','看看秋色晚，又是出門時。',48,'全唐诗/poet.tang.37000.json','["看看秋色晚，又是出門時。", "白髮生非早，青雲去自遲。", "夢唯懷上國，跡不到他岐。", "以此堅吾道，還無媿已知。"]'),
('90b9759a-9ba7-4b41-b457-de1b5245cd03','途中秋晚送友人歸江南','崔塗','唐','唐诗','tang','','[]','又指煙波算路岐，此生多是厭羇離。',64,'全唐诗/poet.tang.37000.json','["又指煙波算路岐，此生多是厭羇離。", "正逢搖落仍須別，不待登臨已合悲。", "里巷半空兵過後，水雲初冷鴈來時。", "扁舟未得如君去，空向滄江夢所思。"]'),
('15cb3d75-36b7-4707-b201-9caae039b327','己亥歲感事','崔塗','唐','唐诗','tang','','[]','正聞青犢起葭萌，又報黃巾犯漢營。',64,'全唐诗/poet.tang.37000.json','["正聞青犢起葭萌，又報黃巾犯漢營。", "豈是將皆無上略，直疑天自棄蒼生。", "瓜沙舊戍猶傳檄，吳楚新春已廢耕。", "見說聖君能仄席，不知誰是請長纓。"]'),
('5e0eb2d0-eb15-4e0d-a02b-bd4a212f0cae','金陵晚眺','崔塗','唐','唐诗','tang','','[]','葦聲騷屑水天秋，吟對金陵古渡頭。',64,'全唐诗/poet.tang.37000.json','["葦聲騷屑水天秋，吟對金陵古渡頭。", "千古是非輸蝶夢，一輪風雨屬漁舟。", "若無仙分應須老，幸有歸山即合休。", "何必登臨更惆悵，比來身世只如浮。"]'),
('05358d91-44b7-4a9d-afd2-9614680fa5d8','過長江賈島主簿舊廳','崔塗','唐','唐诗','tang','','["\u957f\u6c5f"]','雕琢文章字字精，我經此處倍傷情。',64,'全唐诗/poet.tang.37000.json','["雕琢文章字字精，我經此處倍傷情。", "身從謫宦方霑祿，才被槌埋更有聲。", "過縣已無曾識吏，到廳空見舊題名。", "長江一曲年年水，應爲先生萬古清。"]'),
('70bf0a2b-3276-46c6-aa9c-68e0962c0c9b','途中感懷寄青城李明府','崔塗','唐','唐诗','tang','','[]','鱗鬣催殘志未休，壯心飜是此身讐。',64,'全唐诗/poet.tang.37000.json','["鱗鬣催殘志未休，壯心飜是此身讐。", "併聞寒雨多因夜，不得鄉書又到秋。", "耕釣舊交吟好憶，雪霜危棧去堪愁。", "如何只是三年別，君著朱衣我白頭。"]'),
('121192f9-8b5f-43b7-a720-3ca9ad510a9a','夏日書懷寄道友','崔塗','唐','唐诗','tang','','[]','達即匡邦退即耕，是非何足撓平生。',64,'全唐诗/poet.tang.37000.json','["達即匡邦退即耕，是非何足撓平生。", "終期道向希夷得，未省心因寵辱驚。", "峰轉暫無當戶影，雉飛時有隔林聲。", "十年惟悟吟詩句，待得中原欲鑄兵。"]'),
('e0755669-f89d-4318-a111-450bc347a181','和進士張曙聞鴈見寄','崔塗','唐','唐诗','tang','','[]','斷行哀響遞相催，爭趁高秋作恨媒。',64,'全唐诗/poet.tang.37000.json','["斷行哀響遞相催，爭趁高秋作恨媒。", "雲外關山聞獨去，渡頭風雨見初來。", "也知榆塞寒須別，莫戀蘋汀暖不迴。", "試向富春江畔過，故園猶合有池臺。"]'),
('337330c6-3aa1-4214-934a-44e3b20f5cd4','鸚鵡洲即事','崔塗','唐','唐诗','tang','','[]','悵望春襟鬱未開，重吟鸚鵡益堪哀。',64,'全唐诗/poet.tang.37000.json','["悵望春襟鬱未開，重吟鸚鵡益堪哀。", "曹瞞尚不能容物，黃祖何曾解愛才。", "幽島暖聞燕鴈去，曉江晴覺蜀波來。", "何人正得風濤便，一點輕帆萬里迴。"]'),
('0cd52052-facd-4990-a7d4-0d247c80e20a','讀留侯傳','崔塗','唐','唐诗','tang','','[]','覆楚讐韓勢有餘，男兒遭遇更難如。',64,'全唐诗/poet.tang.37000.json','["覆楚讐韓勢有餘，男兒遭遇更難如。", "偶成漢室千年業，只讀圯橋一卷書。", "翻把壯心輕尺組，却煩商皓正皇儲。", "若能終始匡天子，何必□□□□□。"]'),
('414134d3-a4e7-414b-83fa-a63b719d3671','赤壁懷古','崔塗','唐','唐诗','tang','','[]','漢室河山鼎勢分，勤王誰肯顧元勳。',64,'全唐诗/poet.tang.37000.json','["漢室河山鼎勢分，勤王誰肯顧元勳。", "不知征伐由天子，唯許英雄共使君。", "江上戰餘陵是谷，渡頭春在草連雲。", "分明勝敗無尋處，空聽漁歌到夕曛。"]'),
('ce0da344-799e-4078-8fb3-de84bc7d9d28','東晉 一','崔塗','唐','唐诗','tang','','[]','五陵豪俠笑爲儒，將爲儒生只讀書。',32,'全唐诗/poet.tang.37000.json','["五陵豪俠笑爲儒，將爲儒生只讀書。", "看取不成投筆後，謝安功業復何如。"]'),
('a430b3dd-bfa4-4d20-96d4-365470d53e39','東晉 二','崔塗','唐','唐诗','tang','','[]','秦國金陵王氣全，一龍正道始東遷。',32,'全唐诗/poet.tang.37000.json','["秦國金陵王氣全，一龍正道始東遷。", "興亡竟不關人事，虛倚長淮五百年。"]'),
('1f8c69c3-6ae6-48ff-bf8c-1e18b0f42133','春夕','崔塗','唐','唐诗','tang','','["\u6625\u5929", "\u601d\u4e61", "\u5199\u666f"]','水流花謝兩無情，送盡東風過楚城。',64,'全唐诗/poet.tang.37000.json','["水流花謝兩無情，送盡東風過楚城。", "胡蝶夢中家萬里，子規枝上月三更。", "故園書動經年絕，華髮春唯滿鏡生。", "自是不歸歸便得，五湖煙景有誰爭。"]'),
('fcb25fca-d489-4c56-926e-09e0f2ea9bbe','澗松','崔塗','唐','唐诗','tang','','[]','寸寸凌霜長勁條，路人猶笑未干霄。',32,'全唐诗/poet.tang.37000.json','["寸寸凌霜長勁條，路人猶笑未干霄。", "南園桃李雖堪羨，爭奈春殘又寂寥。"]'),
('16a70700-4400-4f4f-9796-0e031d9749da','湘中弦 一','崔塗','唐','唐诗','tang','','[]','蒼山遙遙江潾潾，路傍老盡沒閑人。',32,'全唐诗/poet.tang.37000.json','["蒼山遙遙江潾潾，路傍老盡沒閑人。", "王孫不見草空綠，惆悵渡頭春復春。"]'),
('2e6e4f97-889c-4ac3-aea8-b7641fefba1b','湘中弦 二','崔塗','唐','唐诗','tang','','[]','煙愁雨細雲冥冥，杜蘭香老三湘清。',32,'全唐诗/poet.tang.37000.json','["煙愁雨細雲冥冥，杜蘭香老三湘清。", "故山望斷不知處，鶗鴂隔花時一聲。"]'),
('16758d7d-ecdc-41b7-a2bc-13bf010bdf9e','續紀漢武','崔塗','唐','唐诗','tang','','[]','分明三鳥下儲胥，一覺鈞天夢不如。',32,'全唐诗/poet.tang.37000.json','["分明三鳥下儲胥，一覺鈞天夢不如。", "爭那白頭方士到，茂陵紅葉已蕭疎。"]'),
('1f733392-8a94-4c3d-8b77-ad595c4a6aa1','隴上逢江南故人','崔塗','唐','唐诗','tang','','[]','三聲戍角邊城暮，萬里鄉心塞草春。',32,'全唐诗/poet.tang.37000.json','["三聲戍角邊城暮，萬里鄉心塞草春。", "莫學少年輕遠別，隴關西少向東人。"]'),
('f9be2ffa-7287-42e1-923a-01afbd062933','夷陵夜泊','崔塗','唐','唐诗','tang','','[]','家依楚塞窮秋別，身逐孤舟萬里行。',32,'全唐诗/poet.tang.37000.json','["家依楚塞窮秋別，身逐孤舟萬里行。", "一曲巴歌半江月，便應消得二毛生。"]'),
('a8da7d9c-3b0d-4943-ab4a-09b38a1cc769','櫓聲','崔塗','唐','唐诗','tang','','[]','煙外橈聲遠，天涯幽夢迴。',24,'全唐诗/poet.tang.37000.json','["煙外橈聲遠，天涯幽夢迴。", "爭知江上客，不是故鄉來。"]'),
('0dfcc935-097a-4706-b15d-eb91f97d44d9','海棠圖','崔塗','唐','唐诗','tang','','[]','海棠花底三年客，不見海棠花盛開。',32,'全唐诗/poet.tang.37000.json','["海棠花底三年客，不見海棠花盛開。", "却向江南看圖畫，始慙虛到蜀城來。"]'),
('99a9ee17-c5e9-4444-906e-5bd4073db083','雲','崔塗','唐','唐诗','tang','','[]','得路直爲霖濟物，不然閑共鶴忘機。',32,'全唐诗/poet.tang.37000.json','["得路直爲霖濟物，不然閑共鶴忘機。", "無端却向陽臺畔，長送襄王暮雨歸。"]'),
('bfb4c590-44c7-4f77-9593-edd68a261311','過二妃廟','崔塗','唐','唐诗','tang','','[]','殘陽楚水畔，獨弔舜時人。',24,'全唐诗/poet.tang.37000.json','["殘陽楚水畔，獨弔舜時人。", "不及廟前草，至今江上春。"]'),
('4953f68b-5357-4d74-a2a7-89d1916ac9ea','送友人','崔塗','唐','唐诗','tang','','[]','登高迎送遠，春恨併依依。',24,'全唐诗/poet.tang.37000.json','["登高迎送遠，春恨併依依。", "不得滄洲信，空看白鶴歸。"]'),
('1b79e1a5-af89-4a58-a673-e98cc8980808','聲','崔塗','唐','唐诗','tang','','[]','歡戚猶來恨不平，此中高下本無情。',32,'全唐诗/poet.tang.37000.json','["歡戚猶來恨不平，此中高下本無情。", "韓娥絕唱唐衢哭，盡是人間第一聲。"]'),
('643820d7-50d8-4b43-8474-3db1af060d2a','放鷓鴣','崔塗','唐','唐诗','tang','','[]','秋入池塘風露微，曉開籠檻看初飛。',32,'全唐诗/poet.tang.37000.json','["秋入池塘風露微，曉開籠檻看初飛。", "滿身金翠畫不得，無限煙波何處歸。"]'),
('f00e3b9e-d1b7-41e3-a3fd-f0c95e334f74','泉','崔塗','唐','唐诗','tang','','[]','遠辭巖竇瀉潺潺，靜拂雲根別故山。',32,'全唐诗/poet.tang.37000.json','["遠辭巖竇瀉潺潺，靜拂雲根別故山。", "可惜寒聲留不得，旋添波浪向人間。"]'),
('b691e895-11ba-4c9c-b788-a140c9e08c0c','巫山旅別','崔塗','唐','唐诗','tang','','[]','五千里外三年客，十二峰前一望秋。',32,'全唐诗/poet.tang.37000.json','["五千里外三年客，十二峰前一望秋。", "無限別魂招不得，夕陽西下水東流。"]'),
('6ea18b1d-eab4-4f62-bc66-fff4e7b1d76a','幽蘭','崔塗','唐','唐诗','tang','','[]','幽植衆寧知，芬芳只暗持。',48,'全唐诗/poet.tang.37000.json','["幽植衆寧知，芬芳只暗持。", "自無君子佩，未是國香衰。", "白露霑長草，春風到每遲。", "不如當路草，芬馥欲何爲。"]'),
('b7012b44-6953-4ddf-bee7-79b0fc5c6e3b','讀庾信集','崔塗','唐','唐诗','tang','','[]','四朝十帝盡風流，建業長安兩醉遊。',32,'全唐诗/poet.tang.37000.json','["四朝十帝盡風流，建業長安兩醉遊。", "唯有一篇楊柳曲，江南江北爲君愁。"]'),
('26473a08-45c4-4c1d-aeb0-ef05efd33bdd','過繡嶺宮','崔塗','唐','唐诗','tang','','[]','古殿春殘綠野陰，上皇曾此駐泥金。',64,'全唐诗/poet.tang.37000.json','["古殿春殘綠野陰，上皇曾此駐泥金。", "三城帳屬升平夢，一曲鈴關悵望心。", "苑路暗迷香輦絕，繚垣秋斷草煙深。", "前朝舊物東流在，猶爲年年下翠岑。"]'),
('9d33c118-cde9-49af-b572-c43427a10b48','巴山道中除夜書懷','崔塗','唐','唐诗','tang','','["\u7f81\u65c5", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u5f8b\u8bd7", "\u6625\u8282", "\u601d\u4e61"]','迢遰三巴路，羇危萬里身。',48,'全唐诗/poet.tang.37000.json','["迢遰三巴路，羇危萬里身。", "亂山殘雪夜，孤燭異鄉春。", "漸與骨肉遠，轉於僮僕親。", "那堪正漂泊，明日歲華新。"]'),
('3c4257ee-1330-4d11-9e10-9a86d065eb19','題淨衆寺古松','崔塗','唐','唐诗','tang','','[]','百尺森疎倚梵臺，昔人誰見此初栽。',64,'全唐诗/poet.tang.37000.json','["百尺森疎倚梵臺，昔人誰見此初栽。", "故園未有偏堪戀，浮世如閑即合來。", "天暝豈分蒼翠色，歲寒應識棟梁材。", "清陰可惜不駐得，歸去暮城空首回。"]'),
('ba8d2179-8111-4cfe-9abc-d82137e102a7','折楊柳','崔塗','唐','唐诗','tang','','[]','朝朝車馬如蓬轉，處處江山待客歸。',32,'全唐诗/poet.tang.37000.json','["朝朝車馬如蓬轉，處處江山待客歸。", "若使人間少離別，楊花應合過春飛。"]'),
('e8ddfdf6-b540-4c91-a0c1-53402bd5410b','七夕','崔塗','唐','唐诗','tang','','[]','年年七夕渡瑤軒，誰道秋期有淚痕。',32,'全唐诗/poet.tang.37000.json','["年年七夕渡瑤軒，誰道秋期有淚痕。", "自是人間一週歲，何妨天上只黃昏。"]'),
('e5fc74cd-ebe1-45af-9985-a6b7bc495cb9','泛楚江','崔塗','唐','唐诗','tang','','[]','九重城外家書遠，百里洲前客棹還。',32,'全唐诗/poet.tang.37000.json','["九重城外家書遠，百里洲前客棹還。", "金印碧幢如見問，一生安穩是長閑。"]'),
('b4ad536f-639a-4dc4-bb1c-aae1d7f34165','初過漢江','崔塗','唐','唐诗','tang','','[]','襄陽好向峴亭看，人物蕭條值歲闌。',32,'全唐诗/poet.tang.37000.json','["襄陽好向峴亭看，人物蕭條值歲闌。", "爲報習家多置酒，夜來風雪過江寒。"]'),
('98845b0c-e9b0-4d14-ab8e-bac4354eefce','題授陽鎮路','崔塗','唐','唐诗','tang','','[]','越鳥巢邊溪路斷，秦人耕處洞門開。',32,'全唐诗/poet.tang.37000.json','["越鳥巢邊溪路斷，秦人耕處洞門開。", "小桃花發春風起，千里江山一夢回。"]'),
('53773b6d-17a1-469a-8ae3-4ddcaa5acc31','初識梅花','崔塗','唐','唐诗','tang','','[]','江北不如南地暖，江南好斷北人腸。',32,'全唐诗/poet.tang.37000.json','["江北不如南地暖，江南好斷北人腸。", "燕脂桃頰棃花粉，共作寒梅一面粧。"]'),
('2d423c1c-664a-44cf-811b-d956a6e4b49f','江雨望花','崔塗','唐','唐诗','tang','','[]','細雨滿江春水漲，好風留客野梅香。',32,'全唐诗/poet.tang.37000.json','["細雨滿江春水漲，好風留客野梅香。", "避秦不是無歸意，一度逢花一斷腸。"]'),
('03c0bc51-afe4-4edf-9297-4760bb68907b','雨後月中玉堂閑坐','韓偓','唐','唐诗','tang','','[]','銀臺直北金鑾外，暑雨初晴皓月中。',64,'全唐诗/poet.tang.37000.json','["銀臺直北金鑾外，暑雨初晴皓月中。", "唯對松篁聽刻漏，更無塵土翳虛空。", "綠香熨齒冰盤果，清冷侵肌水殿風。", "夜久忽聞鈴索動，玉堂西畔響丁東。"]'),
('f2e14ca2-a34e-4e44-9d2c-bd584526e3cb','六月十七日召對自辰及申方歸本院','韓偓','唐','唐诗','tang','','[]','清[暑]簾開散異香，恩深咫尺對龍章。',66,'全唐诗/poet.tang.37000.json','["清[暑]簾開散異香，恩深咫尺對龍章。", "花應洞裏尋常發，日向壺中特地長。", "坐久忽疑槎犯斗，歸來兼恐海生桑。", "如今冷笑東方朔，唯用詼諧侍漢皇。"]'),
('a284014c-d8b9-4965-9e22-9c3c8b1d024e','與吳子華侍郎同年玉堂同直懷恩敘懇因成長句四韻兼呈諸同年','韓偓','唐','唐诗','tang','','[]','往年鶯谷接清塵，今日鼇山作侍臣。',64,'全唐诗/poet.tang.37000.json','["往年鶯谷接清塵，今日鼇山作侍臣。", "二紀計偕勞筆研，一朝宣入掌絲綸。", "聲名烜赫文章士，金紫雍容富貴身。", "絳帳恩深無路報，語餘相顧却酸辛。"]'),
('c63102bb-ba42-4b33-be65-d49aac33a104','和吳子華侍郎令狐昭化舍人歎白菊衰謝之絕次山本韻','韓偓','唐','唐诗','tang','','[]','正憐香雪披千片，忽訝殘霞覆一叢。',32,'全唐诗/poet.tang.37000.json','["正憐香雪披千片，忽訝殘霞覆一叢。", "還似妖姬長年後，酒酣雙臉却微紅。"]'),
('c51b3616-0006-43b0-8db9-5daa895868b0','中秋禁直','韓偓','唐','唐诗','tang','','[]','星斗疎明禁漏殘，紫泥封後獨凭闌。',64,'全唐诗/poet.tang.37000.json','["星斗疎明禁漏殘，紫泥封後獨凭闌。", "露和玉屑金盤冷，月射珠光貝闕寒。", "天襯樓臺籠苑外，風吹歌管下雲端。", "長卿秪爲長門賦，未識君臣際會難。"]'),
('965672f8-8e76-4bfa-9ef6-da341f985909','侍宴','韓偓','唐','唐诗','tang','','[]','蠭黃蝶粉兩依依，狎宴臨春日正遲。',32,'全唐诗/poet.tang.37000.json','["蠭黃蝶粉兩依依，狎宴臨春日正遲。", "密旨不教江令醉，麗華微笑認皇慈。"]'),
('f3651949-bfae-4589-ba3b-33eee7f6e77a','錫宴日作','韓偓','唐','唐诗','tang','','[]','玉銜花馬蹋香街，詔遣追歡綺席開。',95,'全唐诗/poet.tang.37000.json','["玉銜花馬蹋香街，詔遣追歡綺席開。", "中使押從天上去外人知自日邊來。", "臣心淨比漪漣水，聖澤深於瀲灩杯。", "纔有異恩頒稷契，已將優禮及鄒枚。", "清商適向棃園降，妙妓新行峽雨迴。", "不敢通宵離禁直，晚乘殘醉入銀臺。"]'),
('083229cb-4ef5-4c37-8922-d9abc021d5d8','宮柳','韓偓','唐','唐诗','tang','','[]','莫道秋來芳意違，宮娃猶似妒蛾眉。',64,'全唐诗/poet.tang.37000.json','["莫道秋來芳意違，宮娃猶似妒蛾眉。", "幸當玉輦經過處，不怕金風浩蕩時。", "草色長承垂地葉，日華先動映樓枝。", "澗松亦有凌雲分，爭似移根太液池。"]'),
('2735f18c-b45d-4f53-b83d-1e6db5b4036e','苑中','韓偓','唐','唐诗','tang','','[]','上苑離宮處處迷，相風高與露盤齊。',64,'全唐诗/poet.tang.37000.json','["上苑離宮處處迷，相風高與露盤齊。", "金階鑄出狻猊立，玉樹雕成狒𤝞啼。", "外使調鷹初得按，中官過馬不教嘶。", "笙歌錦繡雲霄裏，獨許詞臣醉似泥。"]'),
('6fa1b676-0b4a-424d-b644-dd9f8da8227e','從獵三首 一','韓偓','唐','唐诗','tang','','[]','獵犬諳斜路，宮嬪識認旗。',24,'全唐诗/poet.tang.37000.json','["獵犬諳斜路，宮嬪識認旗。", "馬前雙兔起，宣爾羽林兒。"]'),
('325d59bb-d131-4c7d-9ede-2fea977a75b9','從獵三首 二','韓偓','唐','唐诗','tang','','[]','小鐙狹鞦鞘，鞍輕妓細腰。',24,'全唐诗/poet.tang.37000.json','["小鐙狹鞦鞘，鞍輕妓細腰。", "有時齊走馬，也學唱交交。"]'),
('35034dbf-6d75-4cbb-8e09-fac41be51f46','從獵三首 三','韓偓','唐','唐诗','tang','','[]','蹀躞巴陵駿，毰毸碧野雞。',24,'全唐诗/poet.tang.37000.json','["蹀躞巴陵駿，毰毸碧野雞。", "忽聞仙樂動，賜酒玉偏提。"]'),
('38795a47-717c-46f2-8c53-00bfec573df1','辛酉歲冬十一月隨駕幸岐下作','韓偓','唐','唐诗','tang','','[]','曳裾談笑殿西頭，忽聽征鐃從冕旒。',64,'全唐诗/poet.tang.37000.json','["曳裾談笑殿西頭，忽聽征鐃從冕旒。", "鳳蓋行時移紫氣，鸞旗駐處認皇州。", "曉題御服頒羣吏，夜發宮嬪詔列侯。", "雨露涵濡三百載，不知誰擬殺身酬。"]'),
('24bbc744-35b5-4c1c-a69d-7befafa8989e','冬至夜作','韓偓','唐','唐诗','tang','','[]','中宵忽見動葭灰，料得南枝有早梅。',64,'全唐诗/poet.tang.37000.json','["中宵忽見動葭灰，料得南枝有早梅。", "四野便應枯草綠，九重先覺凍雲開。", "陰冰莫向河源塞，陽氣今從地底迴。", "不道慘舒無定分，却憂蚊響又成雷。"]'),
('ee885aa9-21bf-403b-ac58-72792c2fe6ba','秋霖夜憶家','韓偓','唐','唐诗','tang','','[]','垂老何時見弟兄，背燈愁泣到天明。',32,'全唐诗/poet.tang.37000.json','["垂老何時見弟兄，背燈愁泣到天明。", "不知短髮能多少，一滴秋霖白一莖。"]'),
('e37c39e8-8658-4652-8b46-a7148b984084','恩賜櫻桃分寄朝士','韓偓','唐','唐诗','tang','','[]','未許鶯偷出漢宮，上林初進半金籠。',64,'全唐诗/poet.tang.37000.json','["未許鶯偷出漢宮，上林初進半金籠。", "蔗漿自透銀杯冷，朱實相輝玉椀紅。", "俱有亂離終日恨，貴將滋味片時同。", "霜威食檗應難近，宜在紗窗繡戶中。"]'),
('edc6d4bc-3a89-4e5a-9925-eaf8cc031f7c','出官經硤石縣','韓偓','唐','唐诗','tang','','[]','謫宦過東畿，所抵州名濮。',72,'全唐诗/poet.tang.37000.json','["謫宦過東畿，所抵州名濮。", "故里欲清明，臨風堪慟哭。", "溪長柳似帷，山暖花如醭。", "逆旅訝簪裾，野老悲陵谷。", "暝鳥影連翩，驚狐尾纛簌。", "尚得佐方州，信是皇恩沐。"]'),
('33927a94-a928-4a22-b321-bafc60c6323e','訪同年虞部李郎中','韓偓','唐','唐诗','tang','','[]','策蹇相尋犯雪泥，廚煙未動日平西。',64,'全唐诗/poet.tang.37000.json','["策蹇相尋犯雪泥，廚煙未動日平西。", "門庭野水䙰褷鷺，鄰里短牆咿喔雞。", "未入慶霄君擇肉，畏逢華轂我吹韲。", "地爐貰酒成狂醉，更覺襟懷得喪齊。"]'),
('8bc9be77-d206-4380-9bc5-689c0a6b0a92','贈漁者','韓偓','唐','唐诗','tang','','[]','箇儂居處近誅茅，枳棘籬兼用荻梢。',64,'全唐诗/poet.tang.37000.json','["箇儂居處近誅茅，枳棘籬兼用荻梢。", "盡日風扉從自掩，無人筒釣是誰拋。", "城方四面牆陰直，江闊中心水脈坳。", "我亦好閑求老伴，莫嫌遷客且論交。"]'),
('1b99d11d-e823-483a-9a6a-d26b7b2981c0','春陰獨酌寄同年虞部李郎中','韓偓','唐','唐诗','tang','','[]','春陰漠漠土脈潤，春寒微微風意和。',64,'全唐诗/poet.tang.37000.json','["春陰漠漠土脈潤，春寒微微風意和。", "閑嗤入甲奔競態，醉唱落調漁樵歌。", "詩道揣量疑可進，宦情刓缺轉無多。", "酒酣狂興依然在，其奈千莖鬢雪何。"]'),
('74ad9399-d822-4988-aca5-6500a848ece9','奉和峽州孫舍人肇荆南重圍中寄諸朝士二篇時李常侍洵嚴諫議龜李起居殷衡李郎中冉皆有繼和余久有是債今至湖南方暇牽課 一','韓偓','唐','唐诗','tang','','[]','敏手何妨誤汰金，敢懷私忿斅羊斟。',64,'全唐诗/poet.tang.37000.json','["敏手何妨誤汰金，敢懷私忿斅羊斟。", "直應宣室還三接，未必豐城便陸沈。", "熾炭一爐真玉性，濃霜千澗老松心。", "私恩尚有捐驅誓，況是君恩萬倍深。"]'),
('bd6fef66-ea3b-42e9-829a-3a51d354c516','奉和峽州孫舍人肇荆南重圍中寄諸朝士二篇時李常侍洵嚴諫議龜李起居殷衡李郎中冉皆有繼和余久有是債今至湖南方暇牽課 二','韓偓','唐','唐诗','tang','','[]','征途安敢更遷延，冒入重圍勢使然。',64,'全唐诗/poet.tang.37000.json','["征途安敢更遷延，冒入重圍勢使然。", "衆果却應存苦李，五缾惟恐竭甘泉。", "多端莫撼三珠樹，密策尋遺七寶鞭。", "黃篾舫中梅雨裏，野人無事日高眠。"]'),
('34b9c6ed-e301-49f8-8645-124cfed3effd','雪中過重湖信筆偶題','韓偓','唐','唐诗','tang','','[]','道方時險擬如何，謫去甘心隱薜蘿。',64,'全唐诗/poet.tang.37000.json','["道方時險擬如何，謫去甘心隱薜蘿。", "青草湖將天暗合，白頭浪與雪相和。", "旗亭臘酎踰年熟，水國春寒向晚多。", "處困不忙仍不怨，醉來唯是欲傞傞。"]'),
('07561bdc-b2f1-4d04-9fb3-4c4079961ba6','寄湖南從事','韓偓','唐','唐诗','tang','','[]','索寞襟懷酒半醒，無人一爲解餘酲。',64,'全唐诗/poet.tang.37000.json','["索寞襟懷酒半醒，無人一爲解餘酲。", "岸頭柳色春將盡，船背雨聲天欲明。", "去國正悲同旅雁，隔江何忍更啼鶯。", "蓮花幕下風流客，試與溫存譴逐情。"]'),
('bbea9ea3-9250-477e-aa04-125c768cafd9','翫水禽','韓偓','唐','唐诗','tang','','[]','兩兩珍禽渺渺溪，翠衿紅掌淨無泥。',64,'全唐诗/poet.tang.37000.json','["兩兩珍禽渺渺溪，翠衿紅掌淨無泥。", "向陽眠處莎成毯，蹋水飛時浪作梯。", "依倚雕梁輕社燕，抑揚金距笑晨雞。", "勸君細認漁翁意，莫遣絚羅誤穩棲。"]'),
('b6a189ba-3400-4dac-8d96-bedbc4700f76','早翫雪梅有懷親屬','韓偓','唐','唐诗','tang','','[]','北陸候纔變，南枝花已開。',48,'全唐诗/poet.tang.37000.json','["北陸候纔變，南枝花已開。", "無人同悵望，把酒獨裴回。", "凍白雪爲伴，寒香風是媒。", "何因逢越使，腸斷謫仙才。"]'),
('1eca84f6-8861-4a14-82a7-5b537353fe9e','欲明','韓偓','唐','唐诗','tang','','[]','欲明籬被風吹倒，過午門因客到開。',64,'全唐诗/poet.tang.37000.json','["欲明籬被風吹倒，過午門因客到開。", "忍苦可能遭鬼笑，息機應免致鷗猜。", "岳僧互乞新詩去，酒保頻徵舊債來。", "唯有狂吟與沈飲，時時猶自觸靈臺。"]'),
('b2dbb64b-5632-406a-849c-0847f43ec6d0','梅花','韓偓','唐','唐诗','tang','','[]','梅花不肯傍春光，自向深冬著豔陽。',64,'全唐诗/poet.tang.37000.json','["梅花不肯傍春光，自向深冬著豔陽。", "龍笛遠吹胡地月，燕釵初試漢宮妝。", "風雖強暴翻添思，雪欲侵凌更助香。", "應笑暫時桃李樹，盜天和氣作年芳。"]'),
('c2ebcb07-c980-4a17-bf0b-b6e64de1ac07','小隱','韓偓','唐','唐诗','tang','','[]','借得茅齋岳麓西，擬將身世老鋤犂。',64,'全唐诗/poet.tang.37000.json','["借得茅齋岳麓西，擬將身世老鋤犂。", "清晨向市煙含郭，寒夜歸村月照溪。", "爐爲窗明僧偶坐，松因雪折鳥驚啼。", "靈椿朝菌由來事，却笑莊生始欲齊。"]'),
('dee61727-039f-4a5f-a899-84aa07de92da','曛黑','韓偓','唐','唐诗','tang','','[]','古木侵天日已沈，露華涼冷潤衣襟。',32,'全唐诗/poet.tang.37000.json','["古木侵天日已沈，露華涼冷潤衣襟。", "江城曛黑人行絕，唯有啼鳥伴夜碪。"]'),
('b1a2d76e-07dc-40d0-a810-b04303fc49cf','曉日','韓偓','唐','唐诗','tang','','[]','天際霞光入水中，水中天際一時紅。',32,'全唐诗/poet.tang.37000.json','["天際霞光入水中，水中天際一時紅。", "直須日觀三更後，首送金烏上碧空。"]'),
('c1f784d0-7857-4031-87fd-84397d0828f4','醉著','韓偓','唐','唐诗','tang','','[]','萬里清江萬里天，一村桑柘一村煙。',32,'全唐诗/poet.tang.37000.json','["萬里清江萬里天，一村桑柘一村煙。", "漁翁醉著無人喚，過午醒來雪滿船。"]'),
('5172c647-ac04-4a4f-a32d-af08b6fef814','柳','韓偓','唐','唐诗','tang','','[]','一籠金線拂彎橋，幾被兒童損細腰。',32,'全唐诗/poet.tang.37000.json','["一籠金線拂彎橋，幾被兒童損細腰。", "無奈靈和標格在，春來依舊褭長條。"]'),
('e300db24-6ef9-4712-b2b9-43d7304cfd70','病中初聞復官二首 一','韓偓','唐','唐诗','tang','','[]','抽毫連夜侍明光，執靮三年從省方。',64,'全唐诗/poet.tang.37000.json','["抽毫連夜侍明光，執靮三年從省方。", "燒玉謾勞曾歷試，鑠金寧爲欠周防。", "也知恩澤招讒口，還痛神祇誤直腸。", "聞道復官飜涕泗，屬車何在水茫茫。"]');
